function legalRouteLabel(route: keyof typeof LEGAL_PAGES) {
  return route === 'acceptable-use' ? 'Acceptable Use' : route === 'contractor-agreement' ? 'Contractor Agreement' : LEGAL_PAGES[route].title.replace(' of Service', '');
}

function storedFieldWorkState(): StoredFieldWorkState | null {
  try {
    return JSON.parse(window.localStorage.getItem(STORAGE_KEYS.fieldWorkState) || 'null') as StoredFieldWorkState | null;
  } catch {
    return null;
  }
}

function storedInspectionViewForJobsView(jobsView: ContractorJobsView): InspectionView {
  const fieldWorkState = storedFieldWorkState();
  if ((jobsView === 'open_jobs' || jobsView === 'closed_jobs') && fieldWorkState?.view === 'detail' && fieldWorkState.inspectionId) {
    return 'detail';
  }
  return jobsView === 'new_jobs' ? 'new' : 'list';
}

function createEstimateLineDraft(overrides: Partial<EstimateLineDraft> = {}): EstimateLineDraft {
  const draft: EstimateLineDraft = {
    id: crypto.randomUUID(),
    line_type: 'labor',
    description: '',
    line_title: '',
    customer_description: '',
    model_spec: '',
    supply_status: '',
    quantity: '1',
    unit: 'each',
    unit_price: '',
    ...overrides,
  };
  if (!draft.line_title.trim() && draft.description.trim()) draft.line_title = draft.description;
  if (!draft.description.trim() && draft.line_title.trim()) draft.description = draft.line_title;
  draft.supply_status = normalizeEstimateLineSupplyStatus(draft.supply_status);
  return draft;
}

function createBlankEstimateDraft(overrides: Partial<EstimateDraft> = {}): EstimateDraft {
  return {
    title: '',
    scope: '',
    notes: '',
    terms: 'Estimate is valid for 30 days unless otherwise noted. Final pricing may change if site conditions or requested scope changes.',
    service_request_id: '',
    inspection_id: '',
    home_id: '',
    local_home_id: '',
    line_items: [createEstimateLineDraft()],
    ...overrides,
  };
}

function createBlankSavedEstimateChargeDraft(overrides: Partial<SavedEstimateChargeDraft> = {}): SavedEstimateChargeDraft {
  return {
    name: '',
    description: '',
    line_type: 'labor',
    charge_type: 'flat',
    amount: '',
    default_quantity: '1',
    unit: '',
    active: true,
    sort_order: '0',
    ...overrides,
  };
}

function savedEstimateChargeDraftFromRecord(charge: ContractorSavedEstimateCharge): SavedEstimateChargeDraft {
  return createBlankSavedEstimateChargeDraft({
    name: charge.name,
    description: charge.description || '',
    line_type: normalizeEstimateLineType(charge.line_type),
    charge_type: charge.charge_type,
    amount: charge.amount_cents === 0 ? '0.00' : centsToDollars(charge.amount_cents),
    default_quantity: String(Number(charge.default_quantity || 1)),
    unit: charge.unit || '',
    active: charge.active,
    sort_order: String(charge.sort_order || 0),
  });
}

function savedEstimateChargeLineDescription(charge: ContractorSavedEstimateCharge) {
  return charge.name;
}

function savedEstimateChargeEditorNote(charge: ContractorSavedEstimateCharge) {
  const description = charge.description?.trim();
  return [
    `Added from saved charge: ${charge.name}.`,
    description ? `Saved charge note: ${description}` : '',
  ].filter(Boolean).join(' ');
}

function estimateLineDraftFromSavedCharge(charge: ContractorSavedEstimateCharge): EstimateLineDraft {
  return createEstimateLineDraft({
    line_type: normalizeEstimateLineType(charge.line_type),
    description: savedEstimateChargeLineDescription(charge),
    line_title: charge.name,
    customer_description: '',
    quantity: String(Number(charge.default_quantity || 1)),
    unit: charge.unit || (charge.charge_type === 'hourly' ? 'hour' : 'each'),
    unit_price: charge.amount_cents === 0 ? '0.00' : centsToDollars(charge.amount_cents),
    editor_source_note: savedEstimateChargeEditorNote(charge),
  });
}

function createBlankInvoiceDraft(subjectName = 'Customer', overrides: Partial<InvoiceDraftForm> = {}): InvoiceDraftForm {
  const dateLabel = new Date().toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
  const defaultLineItems = [
    createEstimateLineDraft({ line_type: 'labor', description: 'Labor for completed work', quantity: '1', unit: 'job' }),
    createEstimateLineDraft({ line_type: 'material', description: 'Materials and supplies', quantity: '1', unit: 'lot' }),
    createEstimateLineDraft({ line_type: 'labor', description: 'Demolition / removal of existing material', quantity: '1', unit: 'job' }),
    createEstimateLineDraft({ line_type: 'fee', description: 'Debris disposal / haul-off', quantity: '1', unit: 'job' }),
  ];
  const draft = {
    invoice_number: '',
    title: `Invoice — ${subjectName || 'Customer'} — ${dateLabel}`,
    scope: 'Completed work performed for the customer.',
    notes: 'Final invoice for completed work. Contractor should confirm all labor, materials, disposal, taxes, and payment terms before sending.',
    terms: 'Payment is due upon receipt unless otherwise agreed in writing.',
    service_request_id: '',
    job_id: '',
    estimate_id: '',
    home_id: '',
    local_home_id: '',
    due_at: '',
    tax: '',
    discount_type: 'amount' as const,
    discount: '',
    discount_reason: '',
    line_items: defaultLineItems,
    ...overrides,
  };
  return {
    ...draft,
    line_items: Array.isArray(draft.line_items) && draft.line_items.length ? draft.line_items : [createEstimateLineDraft()],
  };
}

function estimateDocumentLabel(estimate: Pick<Estimate, 'title' | 'scope' | 'notes'>) {
  const haystack = normalizeText(`${estimate.title || ''} ${estimate.scope || ''} ${estimate.notes || ''}`);
  if (/\b(invoice|completed work|payment due|paid|final invoice|billable work)\b/.test(haystack)) return 'Invoice';
  return 'Estimate';
}

function isInspectionLikeFieldWork(work: Pick<Inspection, 'name' | 'summary'>) {
  const haystack = normalizeText(`${work.name || ''} ${work.summary || ''}`);
  return /\b(inspection|assessment|inspect|report)\b/.test(haystack);
}

const SIMPLE_SERVICE_JOB_TYPES = new Set(['service_visit', 'repair', 'install', 'estimate_visit']);
const CHECKLIST_JOB_TYPES = new Set(['inspection', 'maintenance_visit']);
const SIMPLE_WORK_ITEMS_ROOM = 'Work Items';
const FINDING_KEY_SEPARATOR = '||';

type RoomIdentitySource = Pick<InspectionRoomData, 'room' | 'room_id' | 'display_name' | 'room_type' | 'location_note' | 'reference_photo_storage_path' | 'sort_order' | 'last_edited_by' | 'last_edited_at'>;
type LocalFindingState = { status: FindingStatus; notes: string; action: string; due: string; photos: string[] };
type InspectionLayoutSnapshotRoom = {
  room_key: string;
  room_id: string;
  display_name: string;
  room: string;
  room_type: string;
  location_note: string;
  reference_photo_storage_path: string;
  sort_order: number;
  items: string[];
};

type InspectionLayoutSnapshot = InspectionLayoutSnapshotRoom[];

function createClientRoomId(label?: string) {
  const seed = (label || 'room')
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .slice(0, 32) || 'room';
  try {
    return `local-${seed}-${crypto.randomUUID()}`;
  } catch {
    return `local-${seed}-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
  }
}

function roomDisplayLabel(room?: Partial<RoomIdentitySource> | null) {
  return (room?.display_name || room?.room || '').trim() || 'Unnamed Room';
}

function roomIdentityKey(room?: Partial<RoomIdentitySource> | null) {
  return (room?.room_id || room?.room || roomDisplayLabel(room)).trim() || 'unnamed-room';
}

function roomIdentityFields(room: Partial<RoomIdentitySource>, index?: number): RoomIdentitySource {
  const displayName = roomDisplayLabel(room);
  return {
    room: (room.room || displayName).trim() || 'Unnamed Room',
    room_id: room.room_id || createClientRoomId(displayName),
    display_name: (room.display_name || room.room || displayName).trim() || 'Unnamed Room',
    room_type: room.room_type || '',
    location_note: room.location_note || '',
    reference_photo_storage_path: room.reference_photo_storage_path || '',
    sort_order: typeof room.sort_order === 'number' ? room.sort_order : index,
    last_edited_by: room.last_edited_by || '',
    last_edited_at: room.last_edited_at || '',
  };
}

function normalizeInspectionRoomData(room: InspectionRoomData, index: number): InspectionRoomData {
  return {
    ...roomIdentityFields(room, index),
    findings: Array.isArray(room.findings) ? room.findings : [],
  };
}

function normalizeTemplateRoom(room: InspectionTemplateRoom, index: number): InspectionTemplateRoom {
  return {
    ...roomIdentityFields(room, index),
    items: Array.isArray(room.items) ? room.items : [],
  };
}

function normalizeLayoutText(value?: string | null) {
  return (value || '').trim().replace(/\s+/g, ' ');
}

function layoutRoomIdentityKey(room: Partial<RoomIdentitySource>) {
  return normalizeLayoutText(room.room_id || roomDisplayLabel(room) || room.room || 'Unnamed Room');
}

function inspectionLayoutSnapshotFromTemplateRooms(rooms: InspectionTemplateRoom[]): InspectionLayoutSnapshot {
  return rooms.map((room, index) => {
    const displayName = normalizeLayoutText(room.display_name || room.room || roomDisplayLabel(room) || 'Unnamed Room');
    return {
      room_key: layoutRoomIdentityKey(room),
      room_id: normalizeLayoutText(room.room_id),
      display_name: displayName,
      room: normalizeLayoutText(room.room || displayName || 'Unnamed Room'),
      room_type: normalizeLayoutText(room.room_type),
      location_note: normalizeLayoutText(room.location_note),
      reference_photo_storage_path: normalizeLayoutText(room.reference_photo_storage_path),
      sort_order: typeof room.sort_order === 'number' ? room.sort_order : index,
      items: (Array.isArray(room.items) ? room.items : [])
        .map(item => normalizeLayoutText(item))
        .filter(Boolean),
    };
  });
}

function inspectionLayoutSnapshotFromInspectionRooms(rooms: InspectionRoomData[]): InspectionLayoutSnapshot {
  return inspectionLayoutSnapshotFromTemplateRooms(rooms.map((room, index) => ({
    ...roomIdentityFields(room, index),
    items: (Array.isArray(room.findings) ? room.findings : [])
      .map(finding => finding.title)
      .filter(Boolean),
  })));
}

function inspectionLayoutSnapshotsEqual(left: InspectionLayoutSnapshot | null, right: InspectionLayoutSnapshot | null) {
  if (!left || !right) return left === right;
  return JSON.stringify(left) === JSON.stringify(right);
}

function findingStateKey(room: Partial<RoomIdentitySource>, item: string) {
  return `${roomIdentityKey(room)}${FINDING_KEY_SEPARATOR}${item}`;
}

function splitFindingStateKey(key: string) {
  const [roomPart, ...itemParts] = key.split(FINDING_KEY_SEPARATOR);
  return {
    roomKey: roomPart ?? '',
    item: itemParts.join(FINDING_KEY_SEPARATOR),
  };
}

function findRoomByIdentity<T extends RoomIdentitySource>(rooms: T[], selection?: string | null) {
  if (!selection) return null;
  const normalizedSelection = normalizeText(selection);
  return rooms.find(room =>
    roomIdentityKey(room) === selection
    || normalizeText(roomIdentityKey(room)) === normalizedSelection
    || normalizeText(room.room || '') === normalizedSelection
    || normalizeText(roomDisplayLabel(room)) === normalizedSelection
  ) ?? null;
}

const SMART_NUMBERED_ROOM_BASES = new Set(['bedroom', 'bathroom', 'garage', 'living room', 'dining room', 'office', 'hallway', 'closet']);

function smartRoomBaseLabel(label: string) {
  const normalized = normalizeText(label);
  if (normalized.includes('bedroom') || normalized === 'bed') return 'Bedroom';
  if (normalized.includes('bathroom') || normalized === 'bath') return 'Bathroom';
  if (normalized.includes('garage')) return 'Garage';
  if (normalized.includes('living room')) return 'Living Room';
  if (normalized.includes('dining room')) return 'Dining Room';
  if (normalized.includes('office')) return 'Office';
  if (normalized.includes('hallway') || normalized === 'hall') return 'Hallway';
  if (normalized.includes('closet')) return 'Closet';
  return label.trim();
}

function isSmartNumberedRoomBase(label: string) {
  return SMART_NUMBERED_ROOM_BASES.has(normalizeText(smartRoomBaseLabel(label)));
}

function numberedRoomRank(label: string, baseLabel: string) {
  const normalized = normalizeText(label);
  const base = normalizeText(baseLabel);
  if (base === 'bedroom' && (normalized === 'primary bedroom' || normalized === 'master bedroom')) return 1;
  if (base === 'bathroom' && (normalized === 'primary bathroom' || normalized === 'master bathroom')) return 1;
  if (normalized === base) return 1;
  const escapedBase = base.replace(/[.*+?^${}()|[\]\\]/g, '\\$&').replace(/\s+/g, '\\s+');
  const match = normalized.match(new RegExp(`^${escapedBase}\\s+(\\d+)$`));
  return match ? Number(match[1]) : null;
}

function nextRoomSectionName(baseRoomName: string, existingRooms: Array<Partial<RoomIdentitySource>>) {
  const baseLabel = smartRoomBaseLabel(baseRoomName);
  const existingLabels = existingRooms.map(room => roomDisplayLabel(room)).filter(Boolean);
  const normalizedExisting = new Set(existingLabels.map(label => normalizeText(label)));

  if (!isSmartNumberedRoomBase(baseLabel)) {
    if (!normalizedExisting.has(normalizeText(baseLabel))) return baseLabel;
    let suffix = 2;
    let candidate = `${baseLabel} ${suffix}`;
    while (normalizedExisting.has(normalizeText(candidate))) {
      suffix += 1;
      candidate = `${baseLabel} ${suffix}`;
    }
    return candidate;
  }

  const highestRank = existingLabels.reduce((highest, label) => {
    const rank = numberedRoomRank(label, baseLabel);
    return rank && rank > highest ? rank : highest;
  }, 0);

  let candidate = highestRank > 0 ? `${baseLabel} ${highestRank + 1}` : baseLabel;
  while (normalizedExisting.has(normalizeText(candidate))) {
    const rank = numberedRoomRank(candidate, baseLabel) ?? 1;
    candidate = `${baseLabel} ${rank + 1}`;
  }
  return candidate;
}

function roomIsApprovedScope(roomName: string) {
  return normalizeText(roomName) === 'approved scope' || normalizeText(roomName) === 'approved work';
}

function roomIsSimpleWorkItems(roomName: string) {
  return normalizeText(roomName) === normalizeText(SIMPLE_WORK_ITEMS_ROOM);
}

const SERVICE_TASK_ACTION_STARTERS = [
  'add',
  'adjust',
  'assemble',
  'build',
  'caulk',
  'check',
  'clean',
  'connect',
  'demo',
  'diagnose',
  'dispose',
  'fix',
  'haul',
  'install',
  'inspect',
  'mount',
  'paint',
  'patch',
  'repair',
  'replace',
  'remove',
  'seal',
  'secure',
  'service',
  'test',
  'troubleshoot',
  'verify',
];

function cleanServiceTaskTitle(value: string) {
  const cleaned = value
    .replace(/^\s*[-*\d.)]+/g, '')
    .replace(/\s+/g, ' ')
    .replace(/^[,;:\s]+|[,;:\s.]+$/g, '')
    .trim();
  return cleaned ? cleaned.charAt(0).toUpperCase() + cleaned.slice(1) : '';
}

function splitScopeIntoServiceTaskCandidates(scope: string) {
  const protectedScope = scope
    .replace(/\r\n/g, '\n')
    .replace(/\s*[;]\s*/g, '\n')
    .replace(/\n+/g, '\n');
  const commaPattern = new RegExp(`,\\s+(?=(?:${SERVICE_TASK_ACTION_STARTERS.join('|')})\\b)`, 'gi');
  const andPattern = new RegExp(`\\s+and\\s+(?=(?:${SERVICE_TASK_ACTION_STARTERS.join('|')})\\b)`, 'gi');
  return protectedScope
    .split('\n')
    .flatMap(part => part.split(commaPattern))
    .flatMap(part => part.split(andPattern));
}

function serviceTasksFromScope(scope: string, jobTitle: string) {
  const normalizedJobTitle = normalizeText(jobTitle);
  const seen = new Set<string>();
  const tasks = splitScopeIntoServiceTaskCandidates(scope)
    .map(cleanServiceTaskTitle)
    .filter(candidate => {
      const normalized = normalizeText(candidate);
      if (!normalized || normalized.length < 4) return false;
      if (normalized === normalizedJobTitle) return false;
      if (seen.has(normalized)) return false;
      seen.add(normalized);
      return true;
    });
  if (tasks.length > 1) return tasks;
  const fallback = cleanServiceTaskTitle(scope);
  const normalizedFallback = normalizeText(fallback);
  if (normalizedFallback && normalizedFallback !== normalizedJobTitle && normalizedFallback.length >= 4) {
    return [fallback];
  }
  return [];
}

function jobHasChecklistStructure(job: Pick<Inspection, 'rooms_with_findings'>) {
  const rooms = job.rooms_with_findings ?? [];
  const findingCount = rooms.reduce((count, room) => count + (room.findings?.length ?? 0), 0);
  if (findingCount === 0) return false;
  return !rooms.every(room => roomIsApprovedScope(room.room));
}

function jobTypeFromWorkflowKind(kind: FieldWorkflowKind, mode: JobWorkflowMode = 'checklist'): string {
  if (mode === 'simple') return 'service_visit';
  if (kind === 'maintenance') return 'maintenance_visit';
  if (kind === 'inspection' || kind === 'assessment') return 'inspection';
  return 'service_visit';
}

function isChecklistJob(job: Pick<Inspection, 'job_type' | 'template_id' | 'name' | 'summary' | 'rooms_with_findings'>) {
  const type = (job.job_type || '').trim();
  if (CHECKLIST_JOB_TYPES.has(type)) return true;
  if (SIMPLE_SERVICE_JOB_TYPES.has(type)) return false;
  return Boolean(job.template_id && jobHasChecklistStructure(job)) || (isInspectionLikeFieldWork(job) && jobHasChecklistStructure(job));
}

function isSimpleServiceJob(job: Pick<Inspection, 'job_type' | 'template_id' | 'name' | 'summary' | 'rooms_with_findings'>) {
  return !isChecklistJob(job);
}

function jobTypeLabel(job: Pick<Inspection, 'job_type' | 'template_id' | 'name' | 'summary' | 'rooms_with_findings'>) {
  if (isChecklistJob(job)) {
    return job.job_type === 'maintenance_visit' ? 'Maintenance / checklist job' : 'Inspection / checklist job';
  }
  const labels: Record<string, string> = {
    service_visit: 'Service job',
    repair: 'Repair job',
    install: 'Install job',
    estimate_visit: 'Estimate visit',
  };
  return labels[(job.job_type || 'service_visit').trim()] ?? 'Service job';
}

function jobTypeHelperCopy(job: Pick<Inspection, 'job_type' | 'template_id' | 'name' | 'summary' | 'rooms_with_findings'>) {
  if (isChecklistJob(job)) {
    return job.job_type === 'maintenance_visit'
      ? 'Record completed maintenance tasks and future recommendations.'
      : 'Use checklist items and notes to document conditions.';
  }
  const helpers: Record<string, string> = {
    service_visit: 'Track the issue, diagnosis, work performed, and recommendations.',
    repair: 'Document the problem, repair performed, parts used, and follow-up needs.',
    install: 'Track install notes, photos, and completion details.',
    estimate_visit: 'Capture site notes and scope details for an estimate.',
  };
  return helpers[(job.job_type || 'service_visit').trim()] ?? helpers.service_visit;
}

const OPEN_JOB_STATUSES: JobLifecycleStatus[] = ['draft', 'scheduled', 'in_progress'];
const CLOSED_JOB_STATUSES: JobLifecycleStatus[] = ['completed', 'closed', 'cancelled'];

function inspectionJobStatus(work: Pick<Inspection, 'status' | 'job_status'>): JobLifecycleStatus {
  if (work.job_status) return work.job_status;
  return work.status === 'finalized' ? 'completed' : 'draft';
}

function inspectionIsOpenJob(work: Pick<Inspection, 'status' | 'job_status'>) {
  return OPEN_JOB_STATUSES.includes(inspectionJobStatus(work));
}

function inspectionIsClosedJob(work: Pick<Inspection, 'status' | 'job_status'>) {
  return CLOSED_JOB_STATUSES.includes(inspectionJobStatus(work));
}

function inspectionCanSaveProgress(work: Pick<Inspection, 'status' | 'job_status'>) {
  return work.status === 'draft' && OPEN_JOB_STATUSES.includes(inspectionJobStatus(work));
}

function inspectionJobStatusLabel(work: Pick<Inspection, 'status' | 'job_status'>) {
  const labels: Record<JobLifecycleStatus, string> = {
    draft: 'Draft',
    scheduled: 'Scheduled',
    in_progress: 'In progress',
    completed: 'Completed',
    closed: 'Closed',
    cancelled: 'Cancelled',
  };
  return labels[inspectionJobStatus(work)];
}

function inspectionJobBadgeClass(work: Pick<Inspection, 'status' | 'job_status'>) {
  const status = inspectionJobStatus(work);
  if (status === 'draft' || status === 'scheduled') return 'bg-amber-50 text-amber-700';
  if (status === 'in_progress') return 'bg-blue-50 text-blue-700';
  if (status === 'cancelled') return 'bg-red-50 text-red-700';
  return 'bg-emerald-50 text-emerald-700';
}

function compactText(value: string) {
  return normalizeText(value).replace(/[^a-z0-9\s]/g, ' ').replace(/\s+/g, ' ').trim();
}

function estimateBuilderJobTypeLabel(jobType: EstimateDraftBuilderJobType) {
  return ESTIMATE_DRAFT_BUILDER_JOB_LABELS[jobType];
}

function inferEstimateBuilderTrade(text: string): EstimateDraftBuilderTrade | null {
  const normalized = compactText(text);
  if (!normalized) return null;
  const scores: Record<EstimateDraftBuilderTrade, number> = {
    HVAC: 0,
    Plumbing: 0,
    Electrical: 0,
    Carpentry: 0,
    Other: 0,
  };
  const keywordGroups: Record<EstimateDraftBuilderTrade, string[]> = {
    HVAC: ['hvac', 'furnace', 'ac', 'air conditioner', 'condenser', 'heat pump', 'thermostat', 'duct', 'vent', 'air handler', 'mini split'],
    Plumbing: ['plumbing', 'plumber', 'pipe', 'leak', 'faucet', 'toilet', 'sink', 'drain', 'water heater', 'valve', 'shower', 'garbage disposal'],
    Electrical: ['electrical', 'electric', 'outlet', 'switch', 'breaker', 'panel', 'circuit', 'fixture', 'light', 'wire', 'gfci'],
    Carpentry: ['carpentry', 'carpenter', 'deck', 'framing', 'trim', 'cabinet', 'door', 'window', 'lumber', 'stairs', 'railing'],
    Other: [],
  };
  ESTIMATE_DRAFT_BUILDER_TRADES.forEach(trade => {
    keywordGroups[trade].forEach(keyword => {
      const compactKeyword = compactText(keyword);
      if (normalized.includes(compactKeyword)) scores[trade] += compactKeyword.includes(' ') ? 3 : 2;
    });
  });
  const sorted = ESTIMATE_DRAFT_BUILDER_TRADES
    .filter(trade => trade !== 'Other')
    .sort((a, b) => scores[b] - scores[a]);
  const best = sorted[0];
  if (!best || scores[best] < 2) return null;
  const second = sorted[1];
  if (second && scores[second] > 0 && scores[best] - scores[second] < 2) return null;
  return best;
}

function inferEstimateBuilderJobType(text: string): EstimateDraftBuilderJobType | null {
  const normalized = compactText(text);
  if (!normalized) return null;
  const rules: Array<{ type: EstimateDraftBuilderJobType; keywords: string[] }> = [
    { type: 'service_diagnostic', keywords: ['diagnostic', 'diagnose', 'troubleshoot', 'inspect', 'assessment', 'service call'] },
    { type: 'replacement', keywords: ['replace', 'replacement', 'swap out', 'remove and replace'] },
    { type: 'install', keywords: ['install', 'installation', 'new', 'set up'] },
    { type: 'maintenance', keywords: ['maintenance', 'tune up', 'tuneup', 'clean', 'service', 'preventive'] },
    { type: 'repair', keywords: ['repair', 'fix', 'patch', 'correct', 'resolve'] },
  ];
  return rules.find(rule => rule.keywords.some(keyword => normalized.includes(compactText(keyword))))?.type ?? null;
}

function textIncludesAny(normalizedText: string, keywords: string[]) {
  return keywords.some(keyword => normalizedText.includes(compactText(keyword)));
}

function estimateBuilderScopeNeedsPermitFee(normalizedScope: string) {
  return textIncludesAny(normalizedScope, ['permit', 'inspection', 'code']);
}

function estimateBuilderScopeNeedsDisposalFee(normalizedScope: string) {
  const disposalPhrases = [
    'haul off',
    'haul-off',
    'debris',
    'dispose',
    'discard',
    'remove old',
    'old sink',
    'old faucet',
    'old disposal',
    'take away',
  ];
  if (textIncludesAny(normalizedScope, disposalPhrases)) return true;
  return normalizedScope.includes('disposal') && !normalizedScope.includes('garbage disposal');
}

function estimateBuilderScopeLooksLikeKitchenSinkFixtureWork(roughScope: string) {
  const normalized = compactText(roughScope);
  const hasSink = textIncludesAny(normalized, ['sink', 'kitchen sink']);
  const hasFaucet = textIncludesAny(normalized, ['faucet', 'fixture']);
  const hasGarbageDisposal = textIncludesAny(normalized, ['garbage disposal', 'disposal unit', 'disposer']);
  return hasSink && (hasFaucet || hasGarbageDisposal);
}

function orderEstimateDraftBuilderSeeds(seeds: EstimateDraftBuilderLineSeed[]) {
  const lineTypeWeight: Record<EstimateLineType, number> = {
    material: 0,
    labor: 1,
    other: 2,
    fee: 3,
  };
  return [...seeds].sort((a, b) => lineTypeWeight[a.line_type] - lineTypeWeight[b.line_type]);
}

function estimateDraftBuilderJobTotalLaborSeed(trade: EstimateDraftBuilderTrade): EstimateDraftBuilderLineSeed {
  const label = trade === 'Other' ? 'Labor for requested work' : `${trade} labor`;
  return {
    line_type: 'labor',
    description: label,
    unit: 'hour',
    keywords: ['labor', 'work', 'install', 'repair', 'replacement'],
  };
}

function estimateDraftBuilderSeedIsCustomerSafe(seed: EstimateDraftBuilderLineSeed) {
  const description = compactText(seed.description);
  return !description.includes('contingency') && !description.includes('cleanup');
}

function estimateDraftBuilderFeeIsRelevant(seed: EstimateDraftBuilderLineSeed, roughScope: string) {
  if (seed.line_type !== 'fee') return true;
  const normalized = compactText(roughScope);
  const description = compactText(seed.description);
  if (description.includes('permit') || description.includes('inspection')) return estimateBuilderScopeNeedsPermitFee(normalized);
  if (description.includes('disposal') || description.includes('haul')) return estimateBuilderScopeNeedsDisposalFee(normalized);
  return textIncludesAny(normalized, seed.keywords && seed.keywords.length > 0 ? seed.keywords : [seed.description]);
}

function contextualEstimateBuilderSeeds({
  trade,
  roughScope,
  laborMode,
}: {
  trade: EstimateDraftBuilderTrade;
  roughScope: string;
  laborMode: EstimateDraftBuilderLaborMode;
}): EstimateDraftBuilderLineSeed[] | null {
  const normalized = compactText(roughScope);
  if (!normalized || (trade !== 'Plumbing' && !estimateBuilderScopeLooksLikeKitchenSinkFixtureWork(roughScope))) return null;

  const hasSink = textIncludesAny(normalized, ['sink', 'kitchen sink']);
  const hasFaucet = textIncludesAny(normalized, ['faucet', 'fixture']);
  const hasGarbageDisposal = textIncludesAny(normalized, ['garbage disposal', 'disposal unit', 'disposer']);
  if (!hasSink || (!hasFaucet && !hasGarbageDisposal)) return null;

  const materialSeeds: EstimateDraftBuilderLineSeed[] = [
    hasSink && {
      line_type: 'material',
      description: 'Sink',
      editor_source_note: 'Suggested because the rough scope mentions replacing the kitchen sink.',
      unit: 'each',
      keywords: ['sink', 'kitchen sink'],
    },
    hasFaucet && {
      line_type: 'material',
      description: 'Faucet / hardware',
      editor_source_note: 'Suggested because the rough scope mentions a new sink faucet.',
      unit: 'each',
      keywords: ['faucet', 'hardware'],
    },
    hasGarbageDisposal && {
      line_type: 'material',
      description: 'Garbage disposal',
      editor_source_note: 'Suggested because the rough scope mentions garbage disposal.',
      unit: 'each',
      keywords: ['garbage disposal', 'disposal unit', 'disposer'],
    },
    {
      line_type: 'material',
      description: 'Installation hardware',
      editor_source_note: 'Suggested as a common material allowance for this installation.',
      unit: 'lot',
      keywords: ['installation hardware', 'mounting hardware', 'hardware'],
    },
    {
      line_type: 'material',
      description: 'Fittings / connections',
      editor_source_note: 'Suggested as a common plumbing connection allowance for this scope.',
      unit: 'lot',
      keywords: ['fittings', 'connections', 'drain', 'supply'],
    },
  ].filter(Boolean) as EstimateDraftBuilderLineSeed[];

  const laborSeeds: EstimateDraftBuilderLineSeed[] = laborMode === 'job_total'
    ? [{ line_type: 'labor', description: 'Labor', editor_source_note: 'Suggested because the scope includes removal and installation work.', unit: 'hour', keywords: ['labor', 'install', 'replace', 'remove'] }]
    : [
        hasSink && { line_type: 'labor', description: 'Sink installation labor', editor_source_note: 'Suggested because the rough scope mentions replacing the kitchen sink.', unit: 'hour', keywords: ['sink labor', 'sink installation', 'labor'] },
        hasFaucet && { line_type: 'labor', description: 'Faucet installation labor', editor_source_note: 'Suggested because the rough scope mentions a new sink faucet.', unit: 'hour', keywords: ['faucet labor', 'faucet installation', 'labor'] },
        hasGarbageDisposal && { line_type: 'labor', description: 'Garbage disposal installation labor', editor_source_note: 'Suggested because the rough scope mentions garbage disposal.', unit: 'hour', keywords: ['garbage disposal labor', 'disposal installation', 'labor'] },
        { line_type: 'labor', description: 'Fittings / connections labor', editor_source_note: 'Suggested as common labor for drain, fitting, and supply connection work.', unit: 'hour', keywords: ['fittings labor', 'connections labor', 'labor'] },
      ].filter(Boolean) as EstimateDraftBuilderLineSeed[];

  const feeSeeds: EstimateDraftBuilderLineSeed[] = [];
  if (estimateBuilderScopeNeedsPermitFee(normalized)) {
    feeSeeds.push({ line_type: 'fee', description: 'Permit or inspection coordination', unit: 'each', keywords: ['permit', 'inspection', 'code'] });
  }
  if (estimateBuilderScopeNeedsDisposalFee(normalized)) {
    feeSeeds.push({ line_type: 'fee', description: 'Disposal / haul-off', unit: 'job', keywords: ['disposal', 'haul', 'haul-off'] });
  }

  return [...materialSeeds, ...laborSeeds, ...feeSeeds];
}

function estimateDraftBuilderSeeds({
  trade,
  roughScope,
  laborMode,
}: {
  trade: EstimateDraftBuilderTrade;
  roughScope: string;
  laborMode: EstimateDraftBuilderLaborMode;
}) {
  const contextualSeeds = contextualEstimateBuilderSeeds({ trade, roughScope, laborMode });
  if (contextualSeeds) return contextualSeeds;

  const rulePack = ESTIMATE_DRAFT_BUILDER_RULE_PACKS[trade];
  const safeSeeds = rulePack.lines
    .filter(estimateDraftBuilderSeedIsCustomerSafe)
    .filter(seed => estimateDraftBuilderFeeIsRelevant(seed, roughScope));
  const nonLaborSeeds = safeSeeds.filter(seed => seed.line_type !== 'labor');
  const laborSeeds = laborMode === 'job_total'
    ? [estimateDraftBuilderJobTotalLaborSeed(trade)]
    : safeSeeds.filter(seed => seed.line_type === 'labor');
  return orderEstimateDraftBuilderSeeds([...nonLaborSeeds, ...laborSeeds]);
}

function estimateBuilderDefaultLineDescription(seed: EstimateDraftBuilderLineSeed, jobType: EstimateDraftBuilderJobType) {
  if (jobType === 'service_diagnostic' && seed.description.toLowerCase().includes('diagnostic')) return seed.description;
  if (jobType === 'maintenance' && seed.description.toLowerCase().includes('maintenance')) return seed.description;
  return seed.description;
}

function estimateBuilderKeywordScore(seed: EstimateDraftBuilderLineSeed, charge: ContractorSavedEstimateCharge) {
  const seedDescription = compactText(seed.description);
  const chargeName = compactText(charge.name);
  const chargeDescription = compactText(charge.description || '');
  const combinedChargeText = `${chargeName} ${chargeDescription}`.trim();
  if (!seedDescription || !chargeName) return 0;

  let score = 0;
  if (normalizeEstimateLineType(charge.line_type) === seed.line_type) score += 25;
  if (chargeName === seedDescription) score += 100;
  if (chargeName && seedDescription.includes(chargeName)) score += 85;
  if (chargeName && chargeName.includes(seedDescription)) score += 85;

  (seed.keywords || []).forEach(keyword => {
    const compactKeyword = compactText(keyword);
    if (!compactKeyword) return;
    if (chargeName === compactKeyword) score += 60;
    if (chargeName.includes(compactKeyword)) score += 35;
    if (chargeDescription.includes(compactKeyword)) score += 20;
  });

  const seedTokens = new Set(seedDescription.split(' ').filter(token => token.length > 3));
  const overlap = combinedChargeText.split(' ').filter(token => seedTokens.has(token)).length;
  score += Math.min(overlap * 8, 32);

  return score;
}

function findSavedChargeMatchForEstimateBuilder(seed: EstimateDraftBuilderLineSeed, charges: ContractorSavedEstimateCharge[]) {
  const activeCharges = charges.filter(charge => charge.active);
  const scored = activeCharges
    .map(charge => ({
      charge,
      score: estimateBuilderKeywordScore(seed, charge),
      compatibleType: normalizeEstimateLineType(charge.line_type) === seed.line_type,
    }))
    .filter(candidate => candidate.score >= 85 && candidate.compatibleType)
    .sort((a, b) => b.score - a.score);
  if (scored.length === 0) return null;
  const [best, second] = scored;
  if (second && best.score - second.score < 20) return null;
  return best.charge;
}

function estimateBuilderEditorSourceNote(seed: EstimateDraftBuilderLineSeed) {
  if (seed.editor_source_note) return seed.editor_source_note;
  const sourceTerms = (seed.keywords || [])
    .slice(0, 3)
    .map(keyword => keyword.trim())
    .filter(Boolean)
    .join(', ');
  return sourceTerms
    ? `Suggested from rough scope: ${sourceTerms}.`
    : 'Suggested from the rough scope and selected trade.';
}

function estimateBuilderLineFromSeed(seed: EstimateDraftBuilderLineSeed, charges: ContractorSavedEstimateCharge[], jobType: EstimateDraftBuilderJobType) {
  const matchedCharge = findSavedChargeMatchForEstimateBuilder(seed, charges);
  if (matchedCharge) {
    return {
      line: {
        ...estimateLineDraftFromSavedCharge(matchedCharge),
        builderGenerated: true,
        editor_source_note: `${estimateBuilderEditorSourceNote(seed)} Matched saved charge: ${matchedCharge.name}.`,
      },
      matched: true,
    };
  }
  return {
    line: createEstimateLineDraft({
      line_type: seed.line_type,
      description: estimateBuilderDefaultLineDescription(seed, jobType),
      line_title: estimateBuilderDefaultLineDescription(seed, jobType),
      customer_description: '',
      quantity: seed.quantity || '1',
      unit: seed.unit || 'each',
      unit_price: '',
      builderGenerated: true,
      editor_source_note: estimateBuilderEditorSourceNote(seed),
    }),
    matched: false,
  };
}

function customerFacingRoughScope(value: string) {
  return value
    .replace(/\b(?:quote|estimate|bid)\s*(?:for|on)?\s*/gi, '')
    .replace(/\b(?:at|@|for|rate|price|cost)\s+\$?\s*[\d,]+(?:\.\d{1,2})?(?:\s*(?:\/|per\s*)\s*(?:h(?:ou)?r|hr|each|ea))?/gi, '')
    .replace(/\b(?:price|pricing|cost|rate)\s*(?:is|at|for)?\s*\$?\s*[\d,]+(?:\.\d{1,2})?/gi, '')
    .replace(/\$\s*[\d,]+(?:\.\d{1,2})?/g, '')
    .replace(/\b(?:internal|helper|draft|placeholder|price required)\b/gi, '')
    .replace(/\s+/g, ' ')
    .replace(/\s+([,.!?])/g, '$1')
    .trim();
}

function buildRuleBasedEstimateDraft({
  trade,
  jobType,
  laborMode,
  roughScope,
  subjectName,
  savedCharges,
}: {
  trade: EstimateDraftBuilderTrade;
  jobType: EstimateDraftBuilderJobType;
  laborMode: EstimateDraftBuilderLaborMode;
  roughScope: string;
  subjectName: string;
  savedCharges: ContractorSavedEstimateCharge[];
}) {
  const rulePack = ESTIMATE_DRAFT_BUILDER_RULE_PACKS[trade];
  const dateLabel = new Date().toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
  const cleanScope = customerFacingRoughScope(roughScope);
  const builtLines = estimateDraftBuilderSeeds({ trade, roughScope, laborMode })
    .map(seed => estimateBuilderLineFromSeed(seed, savedCharges, jobType));
  const jobTypeLabel = estimateBuilderJobTypeLabel(jobType);
  const requestedScope = cleanScope
    ? `Requested scope: ${/[.!?]$/.test(cleanScope) ? cleanScope : `${cleanScope}.`}`
    : '';
  const scope = [
    rulePack.scopeLead(jobTypeLabel.toLowerCase()),
    requestedScope,
  ].filter(Boolean).join(' ');

  return {
    title: `${trade === 'Other' ? 'Project' : trade} ${jobTypeLabel} Estimate - ${subjectName || 'Customer'} - ${dateLabel}`,
    scope,
    notes: rulePack.notes,
    lines: builtLines.map(item => item.line),
    matchedCount: builtLines.filter(item => item.matched).length,
    builtTrade: trade,
    builtJobType: jobType,
  };
}

function estimateDraftLooksBlank(draft: EstimateDraft) {
  return !draft.title.trim()
    && !draft.scope.trim()
    && !draft.notes.trim()
    && draft.line_items.every(line => !draftLineHasContent(line));
}

function estimateDraftTitleLooksDefault(title: string) {
  const normalized = title.trim().toLowerCase();
  return !normalized || normalized.startsWith('estimate - ') || normalized.startsWith('estimate — ');
}

function tradeToolNumber(values: Record<string, string>, key: string, fallback = 0) {
  const value = Number(String(values[key] ?? '').replace(/[^0-9.-]/g, ''));
  return Number.isFinite(value) ? value : fallback;
}

function tradeToolMoneyValue(value: number) {
  return Number.isFinite(value) && value > 0 ? String(Math.round(value * 100) / 100) : '';
}

function tradeToolLine(overrides: Partial<EstimateLineDraft>) {
  return createEstimateLineDraft(overrides);
}

function tradeToolTitle(label: string, subjectName: string) {
  return `Estimate — ${label} — ${subjectName || 'Customer'} — ${new Date().toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}`;
}

function defaultTradeToolInputValues(tool: TradeToolDefinition) {
  return Object.fromEntries(tool.inputs.map(input => [input.id, input.defaultValue]));
}

