function tradeToolMatchesContractor(toolTrade: string, serviceCategories: string[]) {
  const normalizedTrade = normalizeText(toolTrade);
  return serviceCategories.some(category => {
    const normalizedCategory = normalizeText(category);
    if (normalizedCategory === normalizedTrade) return true;
    if (normalizedTrade === 'decks') return ['decks', 'deck', 'carpentry', 'framing', 'handyman', 'general maintenance'].includes(normalizedCategory);
    if (normalizedTrade === 'plumbing') return normalizedCategory.includes('plumb');
    if (normalizedTrade === 'electrical') return normalizedCategory.includes('electric');
    return false;
  });
}

function tradeToolSearchMatches(tool: TradeToolDefinition, search: string) {
  const terms = normalizeText(search).split(' ').filter(Boolean);
  if (terms.length === 0) return true;
  const haystack = normalizeText([tool.name, tool.trade, tool.helper, ...tool.searchTerms].join(' '));
  return terms.every(term => haystack.includes(term));
}

function estimateDraftFromEstimate(estimate: Estimate): EstimateDraft {
  return {
    title: estimate.title,
    scope: estimate.scope,
    notes: estimate.notes,
    terms: estimate.terms,
    service_request_id: estimate.service_request_id || '',
    inspection_id: estimate.inspection_id || '',
    home_id: estimate.home_id || '',
    local_home_id: estimate.local_home_id || '',
    line_items: estimate.line_items?.length
      ? [...estimate.line_items]
          .sort((a, b) => a.sort_order - b.sort_order)
          .map(line => createEstimateLineDraft({
            id: line.id,
            line_type: normalizeEstimateLineType(line.line_type),
            description: line.description,
            line_title: line.line_title || line.description || '',
            customer_description: line.customer_description || '',
            model_spec: line.model_spec || '',
            supply_status: normalizeEstimateLineSupplyStatus(line.supply_status),
            quantity: String(line.quantity),
            unit: line.unit,
            unit_price: lineUnitPriceInputFromCents(line.unit_price_cents),
          }))
      : [createEstimateLineDraft()],
  };
}

function invoiceDraftFromInvoice(invoice: Invoice): InvoiceDraftForm {
  const taxableCents = Math.max(0, invoice.subtotal_cents - invoice.discount_cents);
  const derivedTaxRate = taxableCents > 0 && invoice.tax_cents > 0
    ? Number(((invoice.tax_cents / taxableCents) * 100).toFixed(4))
    : 0;
  return {
    invoice_number: invoice.invoice_number,
    title: invoice.title,
    scope: invoice.scope,
    notes: invoice.notes,
    terms: invoice.terms,
    service_request_id: invoice.service_request_id || '',
    job_id: invoice.job_id || '',
    estimate_id: invoice.estimate_id || '',
    home_id: invoice.home_id || '',
    local_home_id: invoice.local_home_id || '',
    due_at: invoice.due_at ? invoice.due_at.slice(0, 10) : '',
    tax: String(Number(invoice.tax_rate_percent ?? derivedTaxRate) || ''),
    discount_type: invoice.discount_type ?? 'amount',
    discount: invoice.discount_type === 'percentage'
      ? String(Number(invoice.discount_value ?? 0) || '')
      : centsToDollars(invoice.discount_cents),
    discount_reason: invoice.discount_reason ?? '',
    line_items: invoice.line_items?.length
      ? [...invoice.line_items]
          .sort((a, b) => a.sort_order - b.sort_order)
          .map(line => createEstimateLineDraft({
            id: line.id,
            line_type: normalizeEstimateLineType(line.line_type),
            description: line.description,
            line_title: line.line_title || line.description || '',
            customer_description: line.customer_description || '',
            model_spec: line.model_spec || '',
            supply_status: normalizeEstimateLineSupplyStatus(line.supply_status),
            quantity: String(line.quantity),
            unit: line.unit,
            unit_price: lineUnitPriceInputFromCents(line.unit_price_cents),
          }))
      : [createEstimateLineDraft()],
  };
}

function estimateDraftFromTemplate(template: EstimateTemplate, subjectName: string): EstimateDraft {
  return {
    title: `${template.name} — ${subjectName} — ${new Date().toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}`,
    scope: template.scope,
    notes: template.notes,
    terms: template.terms || createBlankEstimateDraft().terms,
    service_request_id: '',
    inspection_id: '',
    line_items: template.line_items?.length
      ? [...template.line_items]
          .sort((a, b) => a.sort_order - b.sort_order)
          .map(line => createEstimateLineDraft({
            line_type: normalizeEstimateLineType(line.line_type),
            description: line.description,
            line_title: line.line_title || line.description || '',
            customer_description: line.customer_description || '',
            model_spec: line.model_spec || '',
            supply_status: normalizeEstimateLineSupplyStatus(line.supply_status),
            quantity: String(line.quantity),
            unit: line.unit,
            unit_price: lineUnitPriceInputFromCents(line.unit_price_cents),
            editor_source_note: `Suggested by saved estimate template: ${template.name}.`,
          }))
      : [createEstimateLineDraft()],
  };
}

