function formatDateTime(value?: string | null) {
  if (!value) return 'Not used yet';
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return value;
  return date.toLocaleString('en-US', {
    month: 'short',
    day: 'numeric',
    year: 'numeric',
    hour: 'numeric',
    minute: '2-digit',
  });
}

function buildHalfHourTimeOptions(startHour: number, endHour: number) {
  const optionCount = ((endHour - startHour) * 2) + 1;
  return Array.from({ length: optionCount }, (_, index) => {
    const totalMinutes = (startHour * 60) + (index * 30);
    const hour24 = Math.floor(totalMinutes / 60);
    const minute = totalMinutes % 60;
    const value = `${String(hour24).padStart(2, '0')}:${String(minute).padStart(2, '0')}`;
    return { value, label: formatTimeOptionLabel(value) };
  });
}

function formatTimeOptionLabel(value: string) {
  const [hourPart, minutePart] = value.split(':');
  const hour24 = Number(hourPart);
  const minute = Number(minutePart);
  if (!Number.isFinite(hour24) || !Number.isFinite(minute)) return value;
  const hour12 = hour24 % 12 || 12;
  const period = hour24 < 12 ? 'AM' : 'PM';
  return `${hour12}:${String(minute).padStart(2, '0')} ${period}`;
}

const VISIT_TIME_OPTIONS = buildHalfHourTimeOptions(7, 21);
const CALENDAR_EVENT_TIME_OPTIONS = buildHalfHourTimeOptions(6, 20);
const CALENDAR_EVENT_RECURRENCE_OPTIONS: { value: CalendarEventRecurrenceFrequency; label: string }[] = [
  { value: 'none', label: 'Does not repeat' },
  { value: 'weekly', label: 'Weekly' },
  { value: 'monthly', label: 'Monthly' },
  { value: 'quarterly', label: 'Quarterly' },
  { value: 'annually', label: 'Annually' },
];

function calendarEventTimeOptions(currentTime: string) {
  if (!currentTime || CALENDAR_EVENT_TIME_OPTIONS.some(option => option.value === currentTime)) {
    return CALENDAR_EVENT_TIME_OPTIONS;
  }

  return [...CALENDAR_EVENT_TIME_OPTIONS, { value: currentTime, label: `${formatTimeOptionLabel(currentTime)} (current)` }]
    .sort((a, b) => a.value.localeCompare(b.value));
}

function splitDateTimeLocalValue(value: string) {
  const [dateValue = '', timeValue = ''] = value.split('T');
  return { dateValue, timeValue: timeValue.slice(0, 5) };
}

function combineDateTimeLocalValue(dateValue: string, timeValue: string) {
  if (!dateValue || !timeValue) return '';
  return `${dateValue}T${timeValue}`;
}

function combineLocalDateAndTime(dateValue: string, timeValue: string) {
  if (!dateValue || !timeValue) return null;
  return new Date(`${dateValue}T${timeValue}`);
}

function normalizeCalendarEventRecurrenceFrequency(value: string | null | undefined): CalendarEventRecurrenceFrequency {
  return value === 'weekly' || value === 'monthly' || value === 'quarterly' || value === 'annually' ? value : 'none';
}

function calendarEventRecurrenceLabel(frequency: CalendarEventRecurrenceFrequency) {
  return CALENDAR_EVENT_RECURRENCE_OPTIONS.find(option => option.value === frequency)?.label ?? 'Does not repeat';
}

function calendarEventRecurrenceRule(frequency: CalendarEventRecurrenceFrequency) {
  return frequency === 'none' ? null : `FREQ=${frequency.toUpperCase()}`;
}

function addMonthsClamped(date: Date, months: number) {
  const next = new Date(date);
  const day = next.getDate();
  next.setDate(1);
  next.setMonth(next.getMonth() + months);
  const lastDay = new Date(next.getFullYear(), next.getMonth() + 1, 0).getDate();
  next.setDate(Math.min(day, lastDay));
  return next;
}

function nextCalendarEventOccurrence(date: Date, frequency: CalendarEventRecurrenceFrequency) {
  if (frequency === 'weekly') {
    const next = new Date(date);
    next.setDate(next.getDate() + 7);
    return next;
  }
  if (frequency === 'monthly') return addMonthsClamped(date, 1);
  if (frequency === 'quarterly') return addMonthsClamped(date, 3);
  if (frequency === 'annually') return addMonthsClamped(date, 12);
  return new Date(date);
}

function calendarEventRecurrenceSummary(event: Pick<ContractorCalendarEvent, 'recurrence_frequency' | 'recurrence_ends_at'>) {
  const frequency = normalizeCalendarEventRecurrenceFrequency(event.recurrence_frequency);
  if (frequency === 'none') return 'Does not repeat';
  const label = calendarEventRecurrenceLabel(frequency).toLowerCase();
  if (!event.recurrence_ends_at) return `Repeats ${label}`;
  const endDate = new Date(event.recurrence_ends_at);
  if (Number.isNaN(endDate.getTime())) return `Repeats ${label}`;
  return `Repeats ${label} until ${endDate.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })}`;
}

function calendarEventEndDateInputValue(value: string | null | undefined) {
  if (!value) return '';
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return '';
  const pad = (n: number) => String(n).padStart(2, '0');
  return `${date.getFullYear()}-${pad(date.getMonth() + 1)}-${pad(date.getDate())}`;
}

function recurringCalendarEventOccurrences(event: ContractorCalendarEvent, rangeStart: Date, rangeEnd: Date) {
  const frequency = normalizeCalendarEventRecurrenceFrequency(event.recurrence_frequency);
  const first = new Date(event.starts_at);
  if (Number.isNaN(first.getTime())) return [];
  if (frequency === 'none') return [{ event, startsAt: event.starts_at }];

  const endLimit = event.recurrence_ends_at ? new Date(event.recurrence_ends_at) : rangeEnd;
  const finalEnd = Number.isNaN(endLimit.getTime()) || endLimit.getTime() > rangeEnd.getTime() ? rangeEnd : endLimit;
  if (finalEnd.getTime() < first.getTime()) return [];

  const occurrences: { event: ContractorCalendarEvent; startsAt: string }[] = [];
  let current = new Date(first);
  let guard = 0;
  while (current.getTime() < rangeStart.getTime() && guard < 500) {
    current = nextCalendarEventOccurrence(current, frequency);
    guard += 1;
  }
  while (current.getTime() <= finalEnd.getTime() && guard < 700) {
    occurrences.push({ event, startsAt: current.toISOString() });
    current = nextCalendarEventOccurrence(current, frequency);
    guard += 1;
  }
  return occurrences;
}

const LOCAL_CLAIM_INVITE_STATUS_LABELS: Record<LocalCustomerClaimInviteStatus, string> = {
  pending: 'Invite pending',
  claimed: 'Claimed by homeowner',
  declined: 'Invite declined',
  expired: 'Invite expired',
  revoked: 'Invite revoked',
};

function effectiveLocalClaimInviteStatus(invite?: LocalCustomerClaimInvite | null): LocalCustomerClaimInviteStatus | null {
  if (!invite) return null;
  if (invite.status === 'pending') {
    const expiresAt = new Date(invite.expires_at).getTime();
    if (!Number.isNaN(expiresAt) && expiresAt <= Date.now()) return 'expired';
  }
  return invite.status;
}

function localCustomerClaimInviteUrl(token: string) {
  return `${window.location.origin}${window.location.pathname}#/homeowner?claim=${encodeURIComponent(token)}`;
}

function toList(value: string) {
  return value
    .split(',')
    .map(item => item.trim())
    .filter(Boolean);
}

function fromList(value?: string[]) {
  return (value || []).join(', ');
}

const CONTRACTOR_SERVICE_AREA_RADIUS_OPTIONS = [10, 25, 50, 100, 200] as const;
const DEFAULT_CONTRACTOR_SERVICE_RADIUS = 25;

type GeocodeLocationResult = {
  ok: boolean;
  normalized_location: string;
  location_text: string;
  city: string;
  state: string;
  zip_code: string;
  latitude: number | null;
  longitude: number | null;
  provider: string;
  provider_place_id?: string;
  precision: string;
  error?: string;
};

function normalizeServiceAreaRadius(value: number | string | null | undefined) {
  const parsed = Number(value);
  return CONTRACTOR_SERVICE_AREA_RADIUS_OPTIONS.includes(parsed as typeof CONTRACTOR_SERVICE_AREA_RADIUS_OPTIONS[number])
    ? parsed
    : DEFAULT_CONTRACTOR_SERVICE_RADIUS;
}

function parseContractorServiceAreaLocation(value: string) {
  const locationText = value.trim();
  if (/^\d{5}$/.test(locationText)) {
    return {
      location_text: locationText,
      zip_code: locationText,
      city: '',
      state: '',
    };
  }

  const parts = locationText.split(',').map(part => part.trim()).filter(Boolean);
  const city = parts.length >= 2 ? parts[0] : '';
  const rawState = parts.length >= 2 ? parts[1] : '';
  const state = /^[a-z]{2}$/i.test(rawState) ? rawState.toUpperCase() : rawState;
  return {
    location_text: locationText,
    zip_code: '',
    city,
    state,
  };
}

function createBlankContractorServiceArea(sortOrder = 0): ContractorServiceArea {
  return {
    id: `draft-${crypto.randomUUID()}`,
    contractor_id: '',
    label: '',
    location_text: '',
    zip_code: '',
    city: '',
    state: '',
    radius_miles: DEFAULT_CONTRACTOR_SERVICE_RADIUS,
    latitude: null,
    longitude: null,
    geocode_status: 'pending',
    geocoded_at: null,
    normalized_location: '',
    geocode_provider: '',
    sort_order: sortOrder,
    created_at: '',
    updated_at: '',
  };
}

function normalizeContractorServiceArea(area: Partial<ContractorServiceArea>, index = 0): ContractorServiceArea {
  const location = parseContractorServiceAreaLocation(area.location_text || area.zip_code || [area.city, area.state].filter(Boolean).join(', '));
  return {
    id: area.id || `draft-${crypto.randomUUID()}`,
    contractor_id: area.contractor_id || '',
    label: area.label || '',
    location_text: area.location_text || location.location_text,
    zip_code: area.zip_code || location.zip_code,
    city: area.city || location.city,
    state: area.state || location.state,
    radius_miles: normalizeServiceAreaRadius(area.radius_miles),
    latitude: area.latitude ?? null,
    longitude: area.longitude ?? null,
    geocode_status: area.geocode_status || 'pending',
    geocoded_at: area.geocoded_at || null,
    normalized_location: area.normalized_location || '',
    geocode_provider: area.geocode_provider || '',
    sort_order: typeof area.sort_order === 'number' ? area.sort_order : index,
    created_at: area.created_at || '',
    updated_at: area.updated_at || '',
  };
}

function contractorServiceAreaHasLocation(area: ContractorServiceArea) {
  return Boolean(area.location_text.trim() || area.zip_code.trim() || area.city.trim() || area.state.trim());
}

function contractorServiceAreaDisplay(area: Pick<ContractorServiceArea, 'label' | 'location_text' | 'zip_code' | 'city' | 'state' | 'radius_miles'>) {
  const location = area.location_text || area.zip_code || [area.city, area.state].filter(Boolean).join(', ') || 'Service area';
  return `${area.label ? `${area.label}: ` : ''}${location} + ${normalizeServiceAreaRadius(area.radius_miles)} miles`;
}

function contractorServiceAreaNeedsGeocode(area: ContractorServiceArea) {
  return contractorServiceAreaHasLocation(area)
    && (area.latitude === null || area.longitude === null || area.geocode_status !== 'geocoded');
}

function contractorServiceAreaRowsForSave(areas: ContractorServiceArea[], contractorId: string) {
  return areas
    .map((area, index) => {
      const parsedLocation = parseContractorServiceAreaLocation(area.location_text || area.zip_code || [area.city, area.state].filter(Boolean).join(', '));
      return {
        contractor_id: contractorId,
        label: area.label.trim(),
        location_text: parsedLocation.location_text,
        zip_code: parsedLocation.zip_code,
        city: parsedLocation.city,
        state: parsedLocation.state,
        radius_miles: normalizeServiceAreaRadius(area.radius_miles),
        latitude: area.latitude,
        longitude: area.longitude,
        geocode_status: area.geocode_status,
        geocoded_at: area.geocoded_at,
        normalized_location: area.normalized_location,
        geocode_provider: area.geocode_provider,
        sort_order: index,
      };
    })
    .filter(area => Boolean(area.location_text || area.zip_code || area.city || area.state));
}

async function invokeGeocodeLocation(area: Pick<ContractorServiceArea, 'location_text' | 'zip_code' | 'city' | 'state'>): Promise<GeocodeLocationResult> {
  if (!supabase) {
    return {
      ok: false,
      normalized_location: '',
      location_text: area.location_text,
      city: '',
      state: '',
      zip_code: '',
      latitude: null,
      longitude: null,
      provider: '',
      precision: '',
      error: 'Geocoding is not available.',
    };
  }
  const { data, error } = await supabase.functions.invoke('geocode-location', {
    body: {
      location_text: area.location_text,
      zip_code: area.zip_code,
      city: area.city,
      state: area.state,
    },
  });
  if (error) {
    return {
      ok: false,
      normalized_location: '',
      location_text: area.location_text,
      city: '',
      state: '',
      zip_code: '',
      latitude: null,
      longitude: null,
      provider: '',
      precision: '',
      error: error.message,
    };
  }
  return data as GeocodeLocationResult;
}

function normalizeSharingPermissions(permissions?: Partial<SharingPermissions> | null): SharingPermissions {
  return {
    ...EMPTY_PERMISSIONS,
    ...(permissions || {}),
  };
}

function connectionSourceLabel(source?: string | null) {
  if (source === 'homeowner_request') return 'Requested by homeowner';
  if (source === 'homeowner_reconnect') return 'Originally requested by homeowner';
  if (source === 'contractor_invite') return 'Started from contractor referral link';
  return 'Connection source recorded';
}

function connectionEventLabel(eventType: string) {
  const labels: Record<string, string> = {
    connection_requested: 'Connection requested',
    connection_approved: 'Connection approved',
    connection_request_accepted: 'Contractor accepted request',
    connection_request_declined: 'Contractor declined request',
    permissions_updated: 'Sharing permissions updated',
    connection_revoked: 'Access revoked',
    reconnect_requested: 'Reconnect requested',
  };
  return labels[eventType] || eventType.replace(/_/g, ' ');
}

function serviceRequestStatusLabel(status: ServiceRequestStatus) {
  const labels: Record<ServiceRequestStatus, string> = {
    open: 'Open',
    contractor_responded: 'Responded',
    homeowner_replied: 'Replied',
    declined: 'Declined',
    closed: 'Closed',
  };
  return labels[status] || status;
}

function serviceRequestStatusClass(status: ServiceRequestStatus) {
  if (status === 'open') return 'bg-slate-100 text-slate-700';
  if (status === 'contractor_responded') return 'bg-blue-50 text-blue-700';
  if (status === 'homeowner_replied') return 'bg-amber-50 text-amber-700';
  if (status === 'closed') return 'bg-emerald-50 text-emerald-700';
  return 'bg-red-50 text-red-700';
}

function serviceRequestStatusAccent(status: ServiceRequestStatus) {
  if (status === 'open') return 'border-l-slate-300';
  if (status === 'contractor_responded') return 'border-l-blue-400';
  if (status === 'homeowner_replied') return 'border-l-amber-400';
  if (status === 'closed') return 'border-l-emerald-400';
  return 'border-l-red-300';
}

function serviceRequestSearchText(request: ServiceRequestSummary) {
  return normalizeText([
    request.title,
    request.description,
    request.category,
    request.urgency,
    request.status,
    request.contractor_name,
    request.homeowner_name,
    request.homeowner_city,
    request.home_label,
    request.home_address,
    request.closing_summary,
    request.quote?.scope,
    request.quote?.status,
    request.appointment?.status,
    request.appointment?.notes,
    ...(request.messages || []).map(message => message.body),
  ].filter(Boolean).join(' '));
}

function serviceRequestMatchesSearch(request: ServiceRequestSummary, query: string) {
  const terms = normalizeText(query).split(' ').filter(Boolean);
  if (terms.length === 0) return true;
  const searchable = serviceRequestSearchText(request);
  return terms.every(term => searchable.includes(term));
}

function contractorRequestNeedsFollowUp(request: ServiceRequestSummary) {
  return !['closed', 'declined'].includes(request.status)
    && (
      request.status === 'homeowner_replied'
      || request.quote?.status === 'accepted'
      || (request.appointment?.status === 'proposed' && request.appointment.proposed_by === 'homeowner')
    );
}

function homeownerRequestNeedsResponse(request: ServiceRequestSummary) {
  return !['closed', 'declined'].includes(request.status)
    && (
      request.quote?.status === 'pending'
      || (request.appointment?.status === 'proposed' && request.appointment.proposed_by === 'contractor')
    );
}

function homeownerRequestQueueFor(request: ServiceRequestSummary): HomeownerRequestView {
  if (['closed', 'declined', 'cancelled', 'archived'].includes(request.status)) return 'closed';
  return 'open_pending';
}

function contractorRequestQueueFor(request: ServiceRequestSummary): ContractorRequestView {
  if (request.status === 'closed') return 'closed';
  if (request.status === 'declined') return 'declined';
  if (request.status === 'open') return 'new';
  if (request.appointment && !contractorRequestNeedsFollowUp(request)) return 'scheduled';
  return 'open';
}

function appointmentNextActionText(appointment: ServiceRequestAppointment, perspective: 'homeowner' | 'contractor') {
  if (appointment.status === 'confirmed') return 'Confirmed on both calendars.';
  if (appointment.status === 'completed') return 'Completed.';
  if (appointment.status === 'cancelled') return 'Cancelled.';
  if (appointment.status === 'proposed') {
    if (appointment.proposed_by === perspective) {
      return perspective === 'homeowner'
        ? 'Waiting on the contractor to confirm this requested time.'
        : 'Waiting on the homeowner to confirm this proposed time.';
    }
    return 'Your response is needed.';
  }
  return '';
}

function appointmentResponseText(appointment: ServiceRequestAppointment, perspective: 'homeowner' | 'contractor') {
  if (appointment.status !== 'proposed') return '';
  if (appointment.proposed_by === perspective) return appointmentNextActionText(appointment, perspective);
  return perspective === 'homeowner'
    ? 'The contractor proposed this time. Confirm it, decline it, or request another time.'
    : 'The homeowner requested this time. Confirm it, decline it, or propose another time.';
}

function notificationCategoryLabel(type: string) {
  if (type.includes('support')) return 'Support';
  if (type.includes('appointment')) return 'Calendar';
  if (type.includes('invoice')) return 'Invoice';
  if (type.includes('estimate')) return 'Estimate';
  if (type.includes('quote')) return 'Quote';
  if (type.includes('connection')) return 'Connection';
  if (type.includes('inspection') || type.includes('report')) return 'Job';
  if (type.includes('log')) return 'Home History';
  return 'Service Request';
}

function notificationCategoryClass(type: string) {
  if (type.includes('support')) return 'bg-sky-100 text-sky-700';
  if (type.includes('appointment')) return 'bg-amber-100 text-amber-700';
  if (type.includes('invoice')) return 'bg-teal-100 text-teal-700';
  if (type.includes('estimate')) return 'bg-emerald-100 text-emerald-700';
  if (type.includes('quote')) return 'bg-emerald-100 text-emerald-700';
  if (type.includes('connection')) return 'bg-blue-100 text-blue-700';
  if (type.includes('inspection') || type.includes('report')) return 'bg-violet-100 text-violet-700';
  return 'bg-slate-100 text-slate-700';
}

