function HomeownerCalendarEventDetail({
  request,
  appointment,
  estimates,
  invoices,
  historyEntries,
  onClose,
  onViewRequest,
  onViewEstimate,
  onViewInvoice,
  onViewHomeHistory,
}: {
  request: ServiceRequestSummary;
  appointment: ServiceRequestAppointment;
  estimates: Estimate[];
  invoices: Invoice[];
  historyEntries: MaintenanceLogEntry[];
  onClose: () => void;
  onViewRequest: () => void;
  onViewEstimate: (estimate: Estimate) => void;
  onViewInvoice: (invoice: Invoice) => void;
  onViewHomeHistory: () => void;
}) {
  const dialogRef = useRef<HTMLDivElement | null>(null);
  const appointmentDate = new Date(appointment.proposed_at);
  const linkedEstimate = estimates.find(estimate => ['sent', 'accepted'].includes(estimate.status)) ?? estimates[0] ?? null;
  const linkedInvoice = invoices.find(invoice => ['sent', 'viewed', 'overdue', 'partially_paid'].includes(invoice.status)) ?? invoices[0] ?? null;
  const statusLabel: Record<AppointmentStatus, string> = {
    proposed: 'Proposed',
    confirmed: 'Confirmed',
    completed: 'Completed',
    cancelled: 'Cancelled',
  };
  const requestStatusLabel: Record<ServiceRequestStatus, string> = {
    open: 'Open',
    contractor_responded: 'Contractor responded',
    homeowner_replied: 'Homeowner replied',
    declined: 'Declined',
    closed: 'Closed',
  };
  const proposedByLabel = appointment.proposed_by === 'contractor' ? 'Contractor proposed' : 'You proposed';
  const detailRows = [
    { label: 'Contractor', value: request.contractor_name },
    { label: 'Property', value: [request.home_label, request.home_address].filter(Boolean).join(' · ') },
    { label: 'Service type', value: request.category },
    { label: 'Request status', value: requestStatusLabel[request.status] ?? request.status },
  ].filter(row => row.value);

  useEffect(() => {
    const previousOverflow = document.body.style.overflow;
    document.body.style.overflow = 'hidden';
    const focusFrame = window.requestAnimationFrame(() => dialogRef.current?.focus());
    return () => {
      window.cancelAnimationFrame(focusFrame);
      document.body.style.overflow = previousOverflow;
    };
  }, []);

  return (
    <div className="fixed inset-0 z-[90] flex items-start justify-center overflow-y-auto bg-black/40 p-4">
      <div
        ref={dialogRef}
        role="dialog"
        aria-modal="true"
        aria-label="Calendar event"
        tabIndex={-1}
        onKeyDown={keyboardEvent => {
          if (keyboardEvent.key === 'Escape') onClose();
        }}
        className="my-8 w-full max-w-lg rounded-2xl border border-[#E1E3E7] bg-white p-5 shadow-2xl outline-none sm:p-6"
      >
        <div className="mb-1 flex items-center justify-between gap-3">
          <h2 className="text-lg font-bold text-[#02132D]">Calendar event</h2>
          <button type="button" onClick={onClose} className="text-[#223D67]/70 hover:text-[#02132D]"><X size={18} /></button>
        </div>
        <p className="mb-4 inline-flex items-center gap-1.5 rounded-full bg-blue-100 px-2.5 py-0.5 text-xs font-semibold text-blue-700">
          Homeowner appointment
        </p>

        <div className="space-y-4">
          <div>
            <p className="text-xs font-semibold uppercase tracking-[0.14em] text-slate-500">Visit</p>
            <h3 className="mt-1 break-words text-xl font-bold text-slate-950">{request.title}</h3>
            {request.description && <p className="mt-2 text-sm leading-6 text-slate-600">{request.description}</p>}
          </div>

          <div className="grid gap-3 sm:grid-cols-2">
            <div className="rounded-xl border border-slate-200 bg-slate-50 p-3">
              <p className="text-xs font-semibold uppercase tracking-[0.12em] text-slate-500">Date and time</p>
              <p className="mt-1 text-sm font-semibold text-slate-900">
                {Number.isNaN(appointmentDate.getTime())
                  ? 'Appointment time unavailable'
                  : appointmentDate.toLocaleString('en-US', {
                      month: 'short',
                      day: 'numeric',
                      year: 'numeric',
                      hour: 'numeric',
                      minute: '2-digit',
                    })}
              </p>
            </div>
            <div className="rounded-xl border border-slate-200 bg-slate-50 p-3">
              <p className="text-xs font-semibold uppercase tracking-[0.12em] text-slate-500">Status</p>
              <p className="mt-1 text-sm font-semibold text-slate-900">{statusLabel[appointment.status]}</p>
              <p className="mt-1 text-xs text-slate-500">{proposedByLabel}</p>
            </div>
          </div>

          {detailRows.length > 0 && (
            <div className="grid gap-2 rounded-xl border border-slate-200 bg-white p-3">
              {detailRows.map(row => (
                <div key={row.label} className="grid gap-0.5 sm:grid-cols-[120px_1fr] sm:gap-3">
                  <p className="text-xs font-semibold uppercase tracking-[0.12em] text-slate-500">{row.label}</p>
                  <p className="break-words text-sm font-medium text-slate-800">{row.value}</p>
                </div>
              ))}
            </div>
          )}

          {appointment.notes && (
            <div className="rounded-xl border border-slate-200 bg-white p-3">
              <p className="text-xs font-semibold uppercase tracking-[0.12em] text-slate-500">Appointment notes</p>
              <p className="mt-1 text-sm leading-6 text-slate-700">{appointment.notes}</p>
            </div>
          )}

          <div className="rounded-xl border border-blue-100 bg-blue-50 p-3 text-xs leading-5 text-blue-900">
            Appointment changes and responses stay in Service Requests for now, so the full request thread and contractor messages remain together.
          </div>
        </div>

        <div className="mt-5 flex flex-wrap items-center justify-between gap-2">
          <button type="button" onClick={onClose} className={buttonClass('secondary')}>
            Close
          </button>
          <div className="flex flex-wrap items-center gap-2">
            {historyEntries.length > 0 && (
              <button type="button" onClick={onViewHomeHistory} className={buttonClass('secondary')}>
                <ClipboardList size={15} />
                View Home History
              </button>
            )}
            {linkedEstimate && (
              <button type="button" onClick={() => onViewEstimate(linkedEstimate)} className={buttonClass('secondary')}>
                <Receipt size={15} />
                View estimate
              </button>
            )}
            {linkedInvoice && (
              <button type="button" onClick={() => onViewInvoice(linkedInvoice)} className={buttonClass('secondary')}>
                <Receipt size={15} />
                View invoice
              </button>
            )}
            <button type="button" onClick={onViewRequest} className={buttonClass('primary')}>
              <MessageSquare size={15} />
              View service request
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

function StarDisplay({ rating }: { rating: number }) {
  return (
    <div className="flex gap-0.5">
      {[1,2,3,4,5].map(s => (
        <span key={s} className={`text-base ${s <= rating ? 'text-amber-400' : 'text-slate-600'}`}>★</span>
      ))}
    </div>
  );
}

function MediaThumbnails({ items }: { items: ServiceRequestMedia[] }) {
  const [lightbox, setLightbox] = useState<string | null>(null);
  const [signedUrls, setSignedUrls] = useState<Record<string, string>>({});

  useEffect(() => {
    let cancelled = false;
    const loadUrls = async () => {
      if (!supabase || items.length === 0) {
        if (!cancelled) setSignedUrls({});
        return;
      }

      const client = supabase;
      const entries = await Promise.all(items.map(async item => {
        const { data, error } = await client.storage
          .from('service-request-media')
          .createSignedUrl(item.storage_path, 60 * 15);
        return [item.id, error ? '' : data?.signedUrl ?? ''] as const;
      }));

      if (!cancelled) {
        setSignedUrls(Object.fromEntries(entries.filter(([, url]) => Boolean(url))));
      }
    };

    void loadUrls();
    return () => {
      cancelled = true;
    };
  }, [items]);

  if (items.length === 0) return null;
  return (
    <>
      <div className="mt-2 flex flex-wrap gap-2">
        {items.map(item => {
          const url = signedUrls[item.id];
          const isVideo = item.content_type.startsWith('video/');
          if (!url) {
            return (
              <div key={item.id} className="flex h-24 w-24 items-center justify-center rounded-lg border border-slate-200 bg-slate-50 px-2 text-center text-xs font-medium text-slate-500">
                Loading attachment
              </div>
            );
          }
          return isVideo ? (
            <video
              key={item.id}
              src={url}
              controls
              className="h-24 w-40 rounded-lg border border-slate-600 object-cover bg-slate-900"
            />
          ) : (
            <button key={item.id} type="button" onClick={() => setLightbox(url)} className="shrink-0">
              <img
                src={url}
                alt={item.file_name}
                className="h-24 w-24 rounded-lg border border-slate-600 object-cover"
              />
            </button>
          );
        })}
      </div>
      {lightbox && (
        <div
          className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 p-4"
          onClick={() => setLightbox(null)}
        >
          <img src={lightbox} alt="Full size" className="max-h-full max-w-full rounded-xl shadow-2xl" />
        </div>
      )}
    </>
  );
}

function InspectionPhotoImage({ photo, alt, className }: { photo: string; alt: string; className: string }) {
  const [src, setSrc] = useState('');

  useEffect(() => {
    let cancelled = false;
    const storagePath = inspectionMediaStoragePath(photo);
    if (!storagePath) {
      setSrc(photo);
      return () => {
        cancelled = true;
      };
    }

    const loadUrl = async () => {
      if (!supabase) return;
      const { data, error } = await supabase.storage
        .from('inspection-media')
        .createSignedUrl(storagePath, 60 * 15);
      if (!cancelled) setSrc(error ? '' : data?.signedUrl ?? '');
    };

    setSrc('');
    void loadUrl();
    return () => {
      cancelled = true;
    };
  }, [photo]);

  if (!src) {
    return (
      <div className={`${className} flex items-center justify-center bg-slate-100 text-[10px] font-medium text-slate-500`}>
        Loading
      </div>
    );
  }

  return <img src={src} alt={alt} className={className} />;
}

function ServiceRequestMessages({ messages, media }: { messages: ServiceRequestSummary['messages']; media: ServiceRequestMedia[] }) {
  if (messages.length === 0) {
    return <p className="text-sm text-slate-400">No messages recorded yet.</p>;
  }

  const mediaByMessage: Record<string, ServiceRequestMedia[]> = {};
  const rootMedia: ServiceRequestMedia[] = [];
  for (const item of media) {
    if (item.message_id) {
      (mediaByMessage[item.message_id] ??= []).push(item);
    } else {
      rootMedia.push(item);
    }
  }

  return (
    <div className="space-y-2">
      {rootMedia.length > 0 && (
        <div className="rounded-xl border border-slate-200 bg-white px-3 py-2">
          <p className="text-xs font-bold uppercase tracking-[0.12em] text-slate-400">Attachments</p>
          <MediaThumbnails items={rootMedia} />
        </div>
      )}
      {messages.map(message => (
        <div key={message.id} className="rounded-xl border border-slate-200 bg-white px-3 py-2">
          <div className="flex flex-wrap items-center justify-between gap-2">
            <p className="text-xs font-bold uppercase tracking-[0.12em] text-slate-400">
              {message.actor_role === 'contractor' ? 'Contractor' : message.actor_role === 'homeowner' ? 'Homeowner' : 'ServSync'}
            </p>
            <p className="text-xs font-medium text-slate-400">{formatDateTime(message.created_at)}</p>
          </div>
          <p className="mt-1 whitespace-pre-wrap text-sm text-slate-700">{message.body}</p>
          {mediaByMessage[message.id] && <MediaThumbnails items={mediaByMessage[message.id]} />}
        </div>
      ))}
    </div>
  );
}

function PermissionChips({ permissions }: { permissions: SharingPermissions }) {
  const labels: { key: keyof SharingPermissions; label: string }[] = [
    { key: 'share_contact', label: 'Contact' },
    { key: 'share_home_overview', label: 'Home overview' },
    { key: 'share_address', label: 'Address' },
    { key: 'share_preferred_vendors', label: 'Vendors' },
    { key: 'share_photos', label: 'Photos' },
  ];
  const shared = labels.filter(item => permissions?.[item.key]);
  return (
    <div className="mt-3 flex flex-wrap gap-2">
      {shared.length === 0 ? (
        <span className="rounded-full bg-[#F7F9FC] px-2 py-0.5 text-xs font-semibold text-[#223D67]">No data shared</span>
      ) : (
        shared.map(item => (
          <span key={item.key} className="rounded-full bg-[#0078FF]/10 px-2 py-0.5 text-xs font-semibold text-[#0078FF]">
            {item.label}
          </span>
        ))
      )}
    </div>
  );
}

type ContextualConnectionSubmitDraft = {
  message: string;
  share_contact: boolean;
  properties: ContextualConnectionPropertyPermission[];
};

function contextualContractorLabel(contractor: ContextualConnectionContractorTarget) {
  const location = [contractor.city, contractor.state].filter(Boolean).join(', ');
  return location ? `${contractor.business_name} · ${location}` : contractor.business_name;
}

function contextualHomeLabel(home: HomeProfile) {
  const location = [home.address_line1, home.city, home.state].filter(Boolean).join(', ');
  return home.nickname || location || 'Property';
}

function defaultContextualPropertyPermission(homeId: string): ContextualConnectionPropertyPermission {
  return {
    home_id: homeId,
    share_home_overview: true,
    share_address: false,
    share_preferred_vendors: false,
    share_photos: false,
  };
}

function contextualPropertyHasPermission(property: ContextualConnectionPropertyPermission) {
  return property.share_home_overview || property.share_address || property.share_preferred_vendors;
}

function activeSharingDraftFromConnection(
  connection: HomeownerConnection,
  homes: HomeProfile[],
  preferredHomeId = '',
): ActiveSharedPropertyDraft {
  const permissions = normalizeSharingPermissions(connection.permissions);
  const availableHomeIds = new Set(homes.map(home => home.id));
  const properties = (connection.shared_properties || [])
    .filter(property => availableHomeIds.has(property.home_id))
    .map(property => ({
      home_id: property.home_id,
      share_home_overview: Boolean(property.share_home_overview),
      share_address: Boolean(property.share_address),
      share_preferred_vendors: Boolean(property.share_preferred_vendors),
      share_photos: false,
    }));

  if (properties.length > 0) {
    return { share_contact: Boolean(permissions.share_contact), properties };
  }

  const fallbackHome = homes.find(home => home.id === preferredHomeId) ?? homes[0] ?? null;
  if (fallbackHome && (permissions.share_home_overview || permissions.share_address || permissions.share_preferred_vendors)) {
    return {
      share_contact: Boolean(permissions.share_contact),
      properties: [{
        home_id: fallbackHome.id,
        share_home_overview: Boolean(permissions.share_home_overview),
        share_address: Boolean(permissions.share_address),
        share_preferred_vendors: Boolean(permissions.share_preferred_vendors),
        share_photos: false,
      }],
    };
  }

  return { share_contact: Boolean(permissions.share_contact), properties: [] };
}

function ContextualConnectionRequestModal({
  contractor,
  homes,
  initialHomeId,
  submitting,
  error,
  onSubmit,
  onClose,
}: {
  contractor: ContextualConnectionContractorTarget;
  homes: HomeProfile[];
  initialHomeId?: string;
  submitting: boolean;
  error?: string;
  onSubmit: (draft: ContextualConnectionSubmitDraft) => Promise<void>;
  onClose: () => void;
}) {
  const firstHomeId = initialHomeId && homes.some(home => home.id === initialHomeId)
    ? initialHomeId
    : homes.length === 1 ? homes[0].id : '';
  const [message, setMessage] = useState('');
  const [shareContact, setShareContact] = useState(false);
  const [propertyDrafts, setPropertyDrafts] = useState<Record<string, ContextualConnectionPropertyPermission>>(() => (
    firstHomeId ? { [firstHomeId]: defaultContextualPropertyPermission(firstHomeId) } : {}
  ));
  const [copySources, setCopySources] = useState<Record<string, string>>({});
  const [localError, setLocalError] = useState('');

  const selectedProperties = homes
    .map(home => propertyDrafts[home.id])
    .filter((property): property is ContextualConnectionPropertyPermission => Boolean(property));
  const selectedHomeIds = new Set(selectedProperties.map(property => property.home_id));

  const toggleHome = (homeId: string, checked: boolean) => {
    setLocalError('');
    setPropertyDrafts(current => {
      if (checked) {
        if (current[homeId]) return current;
        return { ...current, [homeId]: defaultContextualPropertyPermission(homeId) };
      }
      const next = { ...current };
      delete next[homeId];
      return next;
    });
    setCopySources(current => {
      const next = { ...current };
      delete next[homeId];
      return next;
    });
  };

  const updateProperty = (homeId: string, patch: Partial<ContextualConnectionPropertyPermission>) => {
    setLocalError('');
    setPropertyDrafts(current => ({
      ...current,
      [homeId]: {
        ...(current[homeId] || defaultContextualPropertyPermission(homeId)),
        ...patch,
        share_photos: false,
      },
    }));
  };

  const copyPermissions = (targetHomeId: string) => {
    const sourceHomeId = copySources[targetHomeId];
    const source = sourceHomeId ? propertyDrafts[sourceHomeId] : null;
    if (!source || source.home_id === targetHomeId) return;
    updateProperty(targetHomeId, {
      share_home_overview: source.share_home_overview,
      share_address: source.share_address,
      share_preferred_vendors: source.share_preferred_vendors,
      share_photos: false,
    });
  };

  const submit = async () => {
    setLocalError('');
    if (selectedProperties.length === 0) {
      setLocalError('Select at least one property for this connection request.');
      return;
    }
    if (selectedProperties.some(property => !contextualPropertyHasPermission(property))) {
      setLocalError('Choose at least one service-relevant detail to share for each selected property.');
      return;
    }

    await onSubmit({
      message: cleanHumanWrittenText(message).trim(),
      share_contact: shareContact,
      properties: selectedProperties.map(property => ({ ...property, share_photos: false })),
    });
  };

  return (
    <div
      className="fixed inset-0 z-[70] flex items-end justify-center bg-slate-950/55 p-0 sm:items-center sm:p-4"
      role="dialog"
      aria-modal="true"
      aria-labelledby="contextual-connection-request-title"
      onMouseDown={event => {
        if (event.target === event.currentTarget && !submitting) onClose();
      }}
    >
      <div className="max-h-[94vh] w-full overflow-y-auto rounded-t-2xl bg-white shadow-2xl sm:max-w-3xl sm:rounded-2xl">
        <div className="sticky top-0 z-10 flex items-start justify-between gap-3 border-b border-slate-200 bg-white px-5 py-4">
          <div className="min-w-0">
            <p className="text-xs font-bold uppercase tracking-[0.14em] text-slate-500">Connection request</p>
            <h2 id="contextual-connection-request-title" className="mt-1 text-xl font-bold text-slate-950">
              Share property access with {contractor.business_name}
            </h2>
            <p className="mt-1 text-sm text-slate-500">{contextualContractorLabel(contractor)}</p>
          </div>
          <button
            type="button"
            onClick={onClose}
            disabled={submitting}
            className="rounded-full p-2 text-slate-500 transition hover:bg-slate-100 hover:text-slate-900 disabled:cursor-not-allowed disabled:opacity-60"
            aria-label="Close connection request"
          >
            <X size={18} />
          </button>
        </div>

        <div className="space-y-5 px-5 py-5">
          <div className="rounded-2xl border border-blue-100 bg-blue-50 p-4">
            <p className="text-sm font-bold text-blue-950">You choose what each property shares.</p>
            <p className="mt-1 text-sm leading-6 text-blue-800">
              Pick one or more properties and share only the service-relevant details this contractor should see if they accept.
              Contact info is controlled separately for the connection.
            </p>
          </div>

          <label className="flex items-start gap-3 rounded-xl border border-slate-200 bg-white p-3">
            <input
              type="checkbox"
              className="mt-1 h-4 w-4 rounded border-slate-300 accent-[#0078FF]"
              checked={shareContact}
              onChange={event => setShareContact(event.target.checked)}
              disabled={submitting}
            />
            <span>
              <span className="block text-sm font-semibold text-slate-950">Share my contact info with this contractor</span>
              <span className="mt-1 block text-sm leading-5 text-slate-500">
                This is connection-level access. Property details below stay separate per property.
              </span>
            </span>
          </label>

          <Field label="Optional message">
            <textarea
              className={inputClass()}
              rows={3}
              maxLength={500}
              value={message}
              onChange={event => setMessage(event.target.value)}
              disabled={submitting}
              placeholder="Example: We are considering you for HVAC maintenance at our main home."
            />
          </Field>

          <div>
            <p className="mb-2 text-xs font-bold uppercase tracking-[0.12em] text-slate-500">Properties</p>
            {homes.length === 0 ? (
              <div className="rounded-xl border border-amber-200 bg-amber-50 p-4">
                <p className="text-sm font-semibold text-amber-900">Add a property before requesting a contractor connection.</p>
                <p className="mt-1 text-sm leading-6 text-amber-800">
                  The new connection request flow needs at least one homeowner property so permissions can be set clearly.
                </p>
              </div>
            ) : (
              <div className="grid gap-2 sm:grid-cols-2">
                {homes.map(home => (
                  <label key={home.id} className="flex cursor-pointer items-start gap-3 rounded-xl border border-slate-200 bg-white p-3 transition hover:border-blue-300 hover:bg-blue-50">
                    <input
                      type="checkbox"
                      className="mt-1 h-4 w-4 rounded border-slate-300 accent-[#0078FF]"
                      checked={selectedHomeIds.has(home.id)}
                      onChange={event => toggleHome(home.id, event.target.checked)}
                      disabled={submitting}
                    />
                    <span className="min-w-0">
                      <span className="block truncate text-sm font-semibold text-slate-950">{contextualHomeLabel(home)}</span>
                      <span className="mt-1 block truncate text-xs text-slate-500">{[home.city, home.state].filter(Boolean).join(', ') || 'Location not listed'}</span>
                    </span>
                  </label>
                ))}
              </div>
            )}
          </div>

          {selectedProperties.length > 0 && (
            <div className="space-y-3">
              <p className="text-xs font-bold uppercase tracking-[0.12em] text-slate-500">Per-property permissions</p>
              {selectedProperties.map(property => {
                const home = homes.find(candidate => candidate.id === property.home_id);
                const otherSelectedHomes = homes.filter(candidate => selectedHomeIds.has(candidate.id) && candidate.id !== property.home_id);
                return (
                  <div key={property.home_id} className="rounded-2xl border border-slate-200 bg-slate-50 p-4">
                    <div className="flex flex-col gap-3 sm:flex-row sm:items-start sm:justify-between">
                      <div>
                        <p className="text-sm font-bold text-slate-950">{home ? contextualHomeLabel(home) : 'Selected property'}</p>
                        <p className="mt-1 text-xs leading-5 text-slate-500">Choose the service-relevant details this contractor may see for this property.</p>
                      </div>
                      {otherSelectedHomes.length > 0 && (
                        <div className="grid gap-2 sm:grid-cols-[minmax(150px,1fr)_auto]">
                          <select
                            className={inputClass()}
                            value={copySources[property.home_id] || ''}
                            onChange={event => setCopySources(current => ({ ...current, [property.home_id]: event.target.value }))}
                            disabled={submitting}
                            aria-label={`Copy permissions source for ${home ? contextualHomeLabel(home) : 'property'}`}
                          >
                            <option value="">Copy permissions from...</option>
                            {otherSelectedHomes.map(sourceHome => (
                              <option key={sourceHome.id} value={sourceHome.id}>{contextualHomeLabel(sourceHome)}</option>
                            ))}
                          </select>
                          <button
                            type="button"
                            onClick={() => copyPermissions(property.home_id)}
                            disabled={submitting || !copySources[property.home_id]}
                            className={buttonClass('secondary')}
                          >
                            Copy
                          </button>
                        </div>
                      )}
                    </div>

                    <div className="mt-4 grid gap-2 sm:grid-cols-2">
                      <label className="flex items-start gap-3 rounded-xl border border-slate-200 bg-white p-3">
                        <input
                          type="checkbox"
                          className="mt-1 h-4 w-4 rounded border-slate-300 accent-[#0078FF]"
                          checked={property.share_home_overview}
                          onChange={event => updateProperty(property.home_id, { share_home_overview: event.target.checked })}
                          disabled={submitting}
                        />
                        <span>
                          <span className="block text-sm font-semibold text-slate-950">Home overview</span>
                          <span className="mt-1 block text-xs leading-5 text-slate-500">Basic service-relevant property details.</span>
                        </span>
                      </label>
                      <label className="flex items-start gap-3 rounded-xl border border-slate-200 bg-white p-3">
                        <input
                          type="checkbox"
                          className="mt-1 h-4 w-4 rounded border-slate-300 accent-[#0078FF]"
                          checked={property.share_address}
                          onChange={event => updateProperty(property.home_id, { share_address: event.target.checked })}
                          disabled={submitting}
                        />
                        <span>
                          <span className="block text-sm font-semibold text-slate-950">Address</span>
                          <span className="mt-1 block text-xs leading-5 text-slate-500">Street address for this selected property.</span>
                        </span>
                      </label>
                      <label className="flex items-start gap-3 rounded-xl border border-slate-200 bg-white p-3">
                        <input
                          type="checkbox"
                          className="mt-1 h-4 w-4 rounded border-slate-300 accent-[#0078FF]"
                          checked={property.share_preferred_vendors}
                          onChange={event => updateProperty(property.home_id, { share_preferred_vendors: event.target.checked })}
                          disabled={submitting}
                        />
                        <span>
                          <span className="block text-sm font-semibold text-slate-950">Preferred vendors</span>
                          <span className="mt-1 block text-xs leading-5 text-slate-500">Any vendor notes already saved for this property.</span>
                        </span>
                      </label>
                      <label className="flex cursor-not-allowed items-start gap-3 rounded-xl border border-slate-200 bg-slate-100 p-3 opacity-75">
                        <input
                          type="checkbox"
                          className="mt-1 h-4 w-4 rounded border-slate-300"
                          checked={false}
                          disabled
                        />
                        <span>
                          <span className="block text-sm font-semibold text-slate-700">Photos</span>
                          <span className="mt-1 block text-xs leading-5 text-slate-500">Deferred for a later phase.</span>
                        </span>
                      </label>
                    </div>
                  </div>
                );
              })}
            </div>
          )}

          {(localError || error) && <Notice tone="error" text={localError || error || 'Unable to submit connection request.'} />}

          <div className="flex flex-col-reverse gap-2 border-t border-slate-200 pt-4 sm:flex-row sm:justify-end">
            <button type="button" onClick={onClose} disabled={submitting} className={buttonClass('secondary')}>
              Cancel
            </button>
            <button
              type="button"
              onClick={() => void submit()}
              disabled={submitting || homes.length === 0}
              className={buttonClass('primary')}
            >
              <Link2 size={16} />
              {submitting ? 'Sending request...' : 'Send connection request'}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

function SharedField({ label, value, allowed }: { label: string; value?: string | null; allowed: boolean }) {
  return (
    <div className={`rounded-lg border px-2.5 py-2 ${allowed ? 'border-[#E1E3E7] bg-white' : 'border-[#E1E3E7] bg-[#F7F9FC]'}`}>
      <div className="flex items-center justify-between gap-2">
        <p className="text-[11px] font-semibold uppercase tracking-[0.1em] text-[#223D67]/70">{label}</p>
        {!allowed && <Lock size={13} className="text-slate-400" />}
      </div>
      <p className={`mt-0.5 text-sm font-semibold ${allowed ? 'text-[#02132D]' : 'text-[#223D67]/65'}`}>
        {allowed ? value || 'Not provided' : 'Not shared'}
      </p>
    </div>
  );
}

function pendingSharedPropertyAddress(property: ContractorPendingConnectionSharedProperty) {
  if (!property.share_address) return 'Not shared';
  const street = [property.address_line1, property.address_line2].filter(Boolean).join(', ');
  const locality = [property.city, property.state, property.zip_code].filter(Boolean).join(' ');
  return [street, locality].filter(Boolean).join(' · ') || 'Not shared';
}

function pendingSharedPropertyPermissionLabels(property: ContractorPendingConnectionSharedProperty) {
  const labels: string[] = [];
  if (property.share_home_overview) labels.push('Home overview');
  if (property.share_address) labels.push('Address');
  if (property.share_preferred_vendors) labels.push('Preferred vendors');
  return labels;
}

function connectedHomeList(connection: ContractorConnectedHomeowner): ContractorConnectedHomeownerHome[] {
  if (Array.isArray(connection.homes) && connection.homes.length > 0) return connection.homes;
  return connection.home ? [connection.home] : [];
}

function ConnectedHomeProperties({ homes, permissions }: { homes: ContractorConnectedHomeownerHome[]; permissions: SharingPermissions }) {
  if (!permissions.share_home_overview) {
    return <EmptyState text="Home details are not shared for this connection." />;
  }
  if (homes.length === 0) {
    return <EmptyState text="No homeowner properties are shared yet." />;
  }

  return (
    <div className="space-y-3">
      {homes.map((home, index) => {
        const propertyLabel = home.nickname || home.address_line1 || `Property ${index + 1}`;
        const location = [home.city, home.state].filter(Boolean).join(', ');
        return (
          <div key={home.id || `${propertyLabel}-${index}`} className="rounded-xl border border-slate-200 bg-slate-50/80 p-4">
            <div className="mb-3 flex flex-wrap items-start justify-between gap-2">
              <div>
                <p className="text-sm font-bold text-slate-950">{propertyLabel}</p>
                {location && <p className="mt-0.5 text-xs font-medium text-slate-500">{location}</p>}
              </div>
              {index === 0 && <span className="rounded-full bg-blue-100 px-2 py-0.5 text-xs font-bold text-blue-700">Primary</span>}
            </div>
            <div className="grid gap-3 sm:grid-cols-2">
              <SharedField label="Home nickname" value={home.nickname} allowed={permissions.share_home_overview} />
              <SharedField label="Home type" value={home.home_type} allowed={permissions.share_home_overview} />
              <SharedField label="Year built" value={home.year_built} allowed={permissions.share_home_overview} />
              <SharedField label="Square feet" value={home.square_feet} allowed={permissions.share_home_overview} />
              <SharedField label="Address" value={[home.address_line1, home.address_line2].filter(Boolean).join(', ')} allowed={permissions.share_address} />
              <SharedField label="City / State" value={location} allowed={permissions.share_home_overview} />
              <SharedField label="ZIP" value={home.zip_code} allowed={permissions.share_home_overview} />
              <div className="sm:col-span-2">
                <SharedField label="Home notes" value={home.notes} allowed={permissions.share_home_overview} />
              </div>
            </div>
          </div>
        );
      })}
    </div>
  );
}

function InfoBox({ label, value }: { label: string; value: string }) {
  return (
    <div className="rounded-lg border border-[#E1E3E7] bg-white px-2.5 py-2 shadow-sm">
      <p className="text-[11px] font-semibold uppercase tracking-[0.1em] text-[#223D67]/70">{label}</p>
      <p className="mt-0.5 text-sm font-semibold text-[#02132D]">{value}</p>
    </div>
  );
}

function MetricButton({ label, value, onClick }: { label: string; value: string; onClick: () => void }) {
  return (
    <button
      type="button"
      onClick={onClick}
      className="rounded-lg border border-[#E1E3E7] bg-white px-2.5 py-2 text-left shadow-sm transition hover:border-[#1B85FB] hover:bg-[#F7F9FC]"
    >
      <p className="text-[11px] font-semibold uppercase tracking-[0.1em] text-[#223D67]/70">{label}</p>
      <p className="mt-0.5 text-sm font-semibold text-[#02132D]">{value}</p>
    </button>
  );
}

function NotificationBell({
  notifications,
  unreadCount,
  onMarkRead,
  onOpenNotification,
}: {
  notifications: AppNotification[];
  unreadCount?: number;
  onMarkRead: (ids: string[]) => void;
  onOpenNotification?: (notification: AppNotification) => void;
}) {
  const [open, setOpen] = useState(false);
  const buttonRef = useRef<HTMLButtonElement | null>(null);
  const [panelPosition, setPanelPosition] = useState({ top: 64, left: 16, width: 352, maxHeight: 560 });
  const unread = unreadCount ?? notifications.filter(n => !n.read_at).length;

  const updatePanelPosition = useCallback(() => {
    const rect = buttonRef.current?.getBoundingClientRect();
    if (!rect) return;
    const margin = 16;
    const gap = 8;
    const width = Math.min(352, window.innerWidth - margin * 2);
    const preferredHeight = Math.min(560, window.innerHeight - margin * 2);
    let left = rect.left;
    if (left + width > window.innerWidth - margin) {
      left = window.innerWidth - width - margin;
    }
    left = Math.max(margin, left);

    let top = rect.bottom + gap;
    if (top + preferredHeight > window.innerHeight - margin) {
      top = rect.top - preferredHeight - gap;
    }
    top = Math.max(margin, top);
    const maxHeight = Math.max(220, Math.min(preferredHeight, window.innerHeight - top - margin));

    setPanelPosition({ top, left, width, maxHeight });
  }, []);

  useEffect(() => {
    if (!open) return;
    updatePanelPosition();
    window.addEventListener('resize', updatePanelPosition);
    window.addEventListener('scroll', updatePanelPosition, true);
    return () => {
      window.removeEventListener('resize', updatePanelPosition);
      window.removeEventListener('scroll', updatePanelPosition, true);
    };
  }, [open, updatePanelPosition]);

  const handleOpen = () => {
    if (!open) updatePanelPosition();
    setOpen(o => !o);
  };

  const handleNotificationClick = (notification: AppNotification) => {
    if (!notification.read_at) onMarkRead([notification.id]);
    if ((notification.request_id || notification.estimate_id || notification.invoice_id || notification.support_inquiry_id || notification.type.includes('support') || notification.type.includes('connection') || notification.type.includes('invoice')) && onOpenNotification) {
      onOpenNotification(notification);
      setOpen(false);
    }
  };

  return (
    <div className="relative shrink-0">
      <button
        ref={buttonRef}
        type="button"
        onClick={handleOpen}
        className="relative flex h-10 w-10 items-center justify-center rounded-xl border border-[#1B85FB]/25 bg-[#02132D] text-blue-100 transition hover:border-[#1B85FB] hover:bg-[#05214A]"
      >
        <Bell size={18} />
        {unread > 0 && (
          <span className="absolute -right-1 -top-1 flex h-5 w-5 items-center justify-center rounded-full bg-[#0078FF] text-[10px] font-bold text-white">
            {unread > 9 ? '9+' : unread}
          </span>
        )}
      </button>
      {open && (
        <div
          className="fixed z-[80] flex flex-col overflow-hidden rounded-2xl border border-[#E1E3E7] bg-white shadow-2xl"
          style={{
            top: panelPosition.top,
            left: panelPosition.left,
            width: panelPosition.width,
            maxHeight: panelPosition.maxHeight,
          }}
        >
          <div className="flex items-center justify-between border-b border-[#E1E3E7] px-4 py-3">
            <div>
              <p className="text-sm font-bold text-[#02132D]">Notifications</p>
              {unread > 0 && <p className="text-xs text-[#223D67]/70">{unread} unread</p>}
            </div>
            <div className="flex items-center gap-2">
              {notifications.some(notification => !notification.read_at) && (
                <button
                  type="button"
                  onClick={() => onMarkRead(notifications.filter(notification => !notification.read_at).map(notification => notification.id))}
                  className="text-xs font-semibold text-[#0078FF] hover:text-[#005FD6]"
                >
                  Mark all read
                </button>
              )}
              <button type="button" onClick={() => setOpen(false)} className="text-[#223D67]/70 hover:text-[#02132D]"><X size={15} /></button>
            </div>
          </div>
          {notifications.length === 0 ? (
            <p className="px-4 py-6 text-center text-sm text-[#223D67]/70">No notifications yet.</p>
          ) : (
            <ul className="min-h-0 flex-1 divide-y divide-[#E1E3E7] overflow-y-auto">
              {notifications.map(n => (
                <li key={n.id}>
                  <button
                    type="button"
                    onClick={() => handleNotificationClick(n)}
                    className={`w-full px-4 py-3 text-left transition hover:bg-blue-50 ${n.read_at ? 'opacity-65' : ''}`}
                  >
                    <div className="flex items-start justify-between gap-3">
                      <div className="min-w-0">
                        <div className="flex flex-wrap items-center gap-2">
                          {!n.read_at && <span className="mt-1 h-2 w-2 rounded-full bg-[#0078FF]" />}
                          <p className="text-sm font-semibold text-[#02132D]">{n.title}</p>
                          <span className={`rounded-full px-2 py-0.5 text-[10px] font-bold uppercase tracking-[0.08em] ${notificationCategoryClass(n.type)}`}>
                            {notificationCategoryLabel(n.type)}
                          </span>
                        </div>
                        <p className="mt-0.5 text-xs text-[#223D67]">{n.body}</p>
                        <p className="mt-1 text-xs text-[#223D67]/70">{formatDateTime(n.created_at)}</p>
                      </div>
                      {(n.request_id || n.estimate_id || n.support_inquiry_id || n.type.includes('support') || n.type.includes('connection')) && <ArrowRight size={14} className="mt-1 shrink-0 text-[#223D67]/55" />}
                    </div>
                  </button>
                </li>
              ))}
            </ul>
          )}
        </div>
      )}
    </div>
  );
}

function ContractorPublicProfilePage({
  slug,
  currentProfile,
}: {
  slug: string;
  currentProfile: Profile | null;
}) {
  const [data, setData] = useState<ContractorPublicProfile | null>(null);
  const [loading, setLoading] = useState(true);
  const [notFound, setNotFound] = useState(false);
  const [connectionStatus, setConnectionStatus] = useState<string | null>(null);
  const [homeownerHomes, setHomeownerHomes] = useState<HomeProfile[]>([]);
  const [connectionModalOpen, setConnectionModalOpen] = useState(false);
  const [requesting, setRequesting] = useState(false);
  const [requestDone, setRequestDone] = useState(false);
  const [requestError, setRequestError] = useState('');

  useEffect(() => {
    const load = async () => {
      if (!supabase || !slug) { setNotFound(true); setLoading(false); return; }
      const { data: result, error } = await supabase.rpc('servsync_get_public_contractor_profile', { p_slug: slug });
      if (error || !result) { setNotFound(true); setLoading(false); return; }
      const profile = result as ContractorPublicProfile;
      setData(profile);

      if (currentProfile?.role === 'homeowner') {
        const [connectionRes, homesRes] = await Promise.all([
          supabase
            .from('homeowner_contractor_connections')
            .select('id,status')
            .eq('homeowner_user_id', currentProfile.id)
            .eq('contractor_id', profile.contractor_id)
            .maybeSingle(),
          supabase
            .from('homes')
            .select('*')
            .eq('homeowner_user_id', currentProfile.id)
            .order('created_at', { ascending: true }),
        ]);
        const conn = connectionRes.data;
        if (conn) {
          setConnectionStatus(conn.status as string);
        }
        if (!homesRes.error) setHomeownerHomes((homesRes.data || []) as HomeProfile[]);
      }
      setLoading(false);
    };
    void load();
  }, [slug, currentProfile?.id]);

  const publicContractorTarget = data ? {
    id: data.contractor_id,
    business_name: data.business_name,
    city: data.city,
    state: data.state,
    logo_url: data.logo_url,
    service_categories: data.categories,
  } satisfies ContextualConnectionContractorTarget : null;

  const submitConnectionRequest = async (draft: ContextualConnectionSubmitDraft) => {
    if (!supabase || !data || !currentProfile) return;
    setRequesting(true);
    setRequestError('');
    try {
      const { error } = await supabase.rpc('servsync_submit_contextual_connection_request', {
        p_contractor_id: data.contractor_id,
        p_request_message: draft.message,
        p_share_contact: draft.share_contact,
        p_property_permissions: draft.properties.map(property => ({
          home_id: property.home_id,
          share_home_overview: property.share_home_overview,
          share_address: property.share_address,
          share_preferred_vendors: property.share_preferred_vendors,
          share_photos: false,
        })),
      });
      if (error) throw error;
      setConnectionModalOpen(false);
      setConnectionStatus('pending');
      setRequestDone(true);
    } catch (err) {
      setRequestError(readableError(err, 'Unable to request contractor connection.'));
    } finally {
      setRequesting(false);
    }
  };

  if (loading) {
    return (
      <div className="rounded-2xl border border-slate-200 bg-white p-8 text-center text-sm font-semibold text-slate-500 shadow-sm">
        Loading profile…
      </div>
    );
  }

  if (notFound || !data) {
    return (
      <div className="rounded-2xl border border-slate-200 bg-white p-8 text-center shadow-sm">
        <p className="text-base font-bold text-slate-950">Contractor not found</p>
        <p className="mt-1 text-sm text-slate-500">This profile link may be incorrect or the contractor may no longer be active.</p>
        <button type="button" onClick={() => updateRoute('home')} className={`${buttonClass('secondary')} mt-4`}>
          Back to home
        </button>
      </div>
    );
  }

  const location = [data.city, data.state].filter(Boolean).join(', ');
  const hasCredentials = data.license_number || data.insurance_status || data.bonded_status;
  const externalReviewLinks = normalizeExternalReviewLinks(data.external_review_links);
  const returnToHomeownerDiscover = () => {
    window.localStorage.setItem(STORAGE_KEYS.homeownerTab, 'discover');
    updateRoute('homeowner');
  };

  return (
    <div className="mx-auto max-w-3xl space-y-5">
      {currentProfile?.role === 'homeowner' && (
        <div className="flex flex-wrap items-center justify-between gap-3 rounded-2xl border border-slate-200 bg-white px-4 py-3 shadow-sm">
          <p className="text-sm text-slate-500">Viewing a public contractor profile from ServSync.</p>
          <div className="flex flex-wrap gap-2">
            <button type="button" onClick={returnToHomeownerDiscover} className={buttonClass('secondary')}>
              Back to Discover
            </button>
            <button type="button" onClick={() => updateRoute('homeowner')} className={buttonClass('secondary')}>
              Go to my portal
            </button>
          </div>
        </div>
      )}

      {/* Header card */}
      <section className="rounded-3xl border border-slate-200 bg-white p-6 shadow-sm">
        <div className="flex flex-wrap items-start justify-between gap-4">
          <div className="flex min-w-0 flex-1 gap-4">
            {data.logo_url && (
              <div className="flex h-20 w-20 shrink-0 items-center justify-center overflow-hidden rounded-2xl border border-[#E1E3E7] bg-white shadow-sm">
                <img src={data.logo_url} alt={`${data.business_name} logo`} className="h-full w-full object-contain p-2" />
              </div>
            )}
            <div className="min-w-0">
              <p className="text-xs font-semibold uppercase tracking-[0.2em] text-blue-700">Contractor profile</p>
              <h1 className="mt-2 text-3xl font-bold text-slate-950">{data.business_name}</h1>
              {location && (
                <p className="mt-1 flex items-center gap-1.5 text-sm text-slate-500">
                  <MapPin size={14} />
                  {location}
                </p>
              )}
              {data.categories.length > 0 && (
                <div className="mt-3 flex flex-wrap gap-1.5">
                  {data.categories.map(c => (
                    <span key={c} className="rounded-full bg-blue-50 px-2.5 py-0.5 text-xs font-semibold text-blue-700">{c}</span>
                  ))}
                </div>
              )}
            </div>
          </div>

          {data.avg_rating !== null && (
            <div className="shrink-0 rounded-2xl border border-slate-200 bg-slate-50 px-5 py-3 text-center">
              <p className="text-3xl font-bold text-slate-950">{data.avg_rating.toFixed(1)}</p>
              <StarDisplay rating={Math.round(data.avg_rating)} />
              <p className="mt-1 text-xs text-slate-500">{data.review_count} ServSync {data.review_count === 1 ? 'review' : 'reviews'}</p>
            </div>
          )}
        </div>

        {/* CTA */}
        <div className="mt-5 border-t border-slate-200 pt-5">
          {currentProfile?.role === 'homeowner' && (!connectionStatus || ['declined', 'revoked', 'dismissed'].includes(connectionStatus)) && !requestDone && (
            <div className="rounded-2xl border border-blue-200 bg-blue-50 p-4">
              <p className="text-sm font-semibold text-blue-950">Connect before requesting service</p>
              <p className="mt-1 text-sm text-blue-800">
                Send a connection request first. Choose the properties and service-relevant details this contractor may see if they accept.
              </p>
              {requestError && <div className="mt-3"><Notice tone="error" text={requestError} /></div>}
              <button type="button" onClick={() => setConnectionModalOpen(true)} disabled={requesting} className={`${buttonClass('primary')} mt-3`}>
                <Link2 size={16} />
                {requesting ? 'Sending request…' : connectionStatus ? `Request again with ${data.business_name}` : `Request connection with ${data.business_name}`}
              </button>
            </div>
          )}
          {currentProfile?.role === 'homeowner' && ((connectionStatus && !['declined', 'revoked', 'dismissed'].includes(connectionStatus)) || requestDone) && (
            <div className="flex flex-wrap items-center gap-3">
              <span className={`rounded-full px-3 py-1 text-sm font-semibold ${
                connectionStatus === 'active' ? 'bg-emerald-50 text-emerald-700' : 'bg-amber-50 text-amber-700'
              }`}>
                {connectionStatus === 'active' ? 'Connected' : 'Connection request sent'}
              </span>
              <button type="button" onClick={returnToHomeownerDiscover} className={buttonClass('secondary')}>
                Back to Discover
              </button>
              <button type="button" onClick={() => updateRoute('homeowner')} className={buttonClass('secondary')}>
                Go to my portal
              </button>
            </div>
          )}
          {currentProfile?.role === 'contractor' && (
            <p className="text-xs text-slate-500">You're viewing this as a contractor. Homeowners can request a connection from this page.</p>
          )}
        </div>
      </section>

      {publicContractorTarget && connectionModalOpen && (
        <ContextualConnectionRequestModal
          key={publicContractorTarget.id}
          contractor={publicContractorTarget}
          homes={homeownerHomes}
          submitting={requesting}
          error={requestError}
          onSubmit={submitConnectionRequest}
          onClose={() => {
            if (requesting) return;
            setConnectionModalOpen(false);
            setRequestError('');
          }}
        />
      )}

      {/* About + credentials */}
      <div className="grid gap-5 md:grid-cols-[1fr_auto]">
        {data.business_summary && (
          <section className="rounded-2xl border border-slate-200 bg-white p-5 shadow-sm">
            <p className="mb-2 text-xs font-bold uppercase tracking-wide text-slate-500">About</p>
            <p className="text-sm leading-6 text-slate-700">{data.business_summary}</p>
            {data.website_url && (
              <a href={data.website_url} target="_blank" rel="noopener noreferrer"
                className="mt-3 inline-flex items-center gap-1.5 text-sm font-semibold text-blue-700 hover:text-blue-800">
                Visit website →
              </a>
            )}
          </section>
        )}

        {hasCredentials && (
          <section className="rounded-2xl border border-slate-200 bg-white p-5 shadow-sm">
            <p className="mb-3 text-xs font-bold uppercase tracking-wide text-slate-500">Credentials</p>
            <div className="space-y-2 text-sm">
              {data.license_number && (
                <div className="flex items-center gap-2 text-slate-700">
                  <ShieldCheck size={14} className="shrink-0 text-emerald-600" />
                  <span>License listed · {data.license_number}</span>
                </div>
              )}
              {data.insurance_status && (
                <div className="flex items-center gap-2 text-slate-700">
                  <ShieldCheck size={14} className="shrink-0 text-emerald-600" />
                  <span>Insurance listed · {data.insurance_status}</span>
                </div>
              )}
              {data.bonded_status && (
                <div className="flex items-center gap-2 text-slate-700">
                  <ShieldCheck size={14} className="shrink-0 text-emerald-600" />
                  <span>Bonded listed · {data.bonded_status}</span>
                </div>
              )}
            </div>
            <p className="mt-3 text-xs leading-5 text-slate-500">
              Listed credentials are contractor-provided unless ServSync clearly states otherwise.
            </p>
          </section>
        )}
      </div>

      {externalReviewLinks.length > 0 && (
        <section className="rounded-2xl border border-slate-200 bg-white p-5 shadow-sm">
          <p className="mb-2 text-xs font-bold uppercase tracking-wide text-slate-500">External Reviews</p>
          <p className="mb-3 text-sm leading-6 text-slate-600">
            External review links take you to third-party review sites. ServSync reviews are separate and come from completed ServSync work.
          </p>
          <div className="flex flex-wrap gap-2">
            {externalReviewLinks.map(link => (
              <a
                key={`${link.source}-${link.url}`}
                href={link.url}
                target="_blank"
                rel="noopener noreferrer"
                className={buttonClass('secondary')}
              >
                <Star size={15} />
                View {link.label || externalReviewSourceLabel(link.source)}
              </a>
            ))}
          </div>
        </section>
      )}

      {/* Reviews */}
      {data.reviews.length > 0 && (
        <section className="rounded-2xl border border-slate-200 bg-white p-5 shadow-sm">
          <p className="mb-3 text-xs font-bold uppercase tracking-wide text-slate-500">
            ServSync Reviews ({data.review_count})
          </p>
          <p className="mb-3 text-sm leading-6 text-slate-600">From completed ServSync work.</p>
          <div className="space-y-3">
            {data.reviews.map((review, i) => (
              <PublicReviewCard key={i} review={review} />
            ))}
          </div>
        </section>
      )}

      {data.reviews.length === 0 && (
        <section className="rounded-2xl border border-slate-200 bg-white p-5 text-center shadow-sm">
          <p className="text-xs font-bold uppercase tracking-wide text-slate-500">ServSync Reviews</p>
          <p className="mt-2 text-sm text-slate-500">No ServSync reviews yet.</p>
          <p className="mt-1 text-xs text-slate-500">ServSync reviews come from completed ServSync work.</p>
        </section>
      )}
    </div>
  );
}

function DiscoverFeed({
  perspective,
  userId,
  contractorId,
  contractorProfile,
  connections,
  contractorSlugs = {},
  onRequestConnection,
  onRequestService,
}: {
  perspective: 'homeowner' | 'contractor';
  userId: string;
  contractorId: string | null;
  contractorProfile?: ContractorProfile | null;
  connections: HomeownerConnection[];
  contractorSlugs?: Record<string, string>;
  onRequestConnection?: (contractor: ContextualConnectionContractorTarget) => void;
  onRequestService?: (contractorId: string, category: string) => void;
}) {
  const [feed, setFeed] = useState<DiscoverFeedItem[]>([]);
  const [savedFeed, setSavedFeed] = useState<DiscoverFeedItem[]>([]);
  const [feedLoading, setFeedLoading] = useState(false);
  const [filterCategory, setFilterCategory] = useState('');
  const [filterLocation, setFilterLocation] = useState('');
  const [filterRadiusMiles, setFilterRadiusMiles] = useState(String(DEFAULT_CONTRACTOR_SERVICE_RADIUS));
  const [filterKeyword, setFilterKeyword] = useState('');
  const [feedView, setFeedView] = useState<'all' | 'saved'>('all');
  const [selectedPostId, setSelectedPostId] = useState<string | null>(null);
  const [discoverLocationStatus, setDiscoverLocationStatus] = useState<'idle' | 'loading' | 'geocoded' | 'fallback'>('idle');
  const [discoverLocationMessage, setDiscoverLocationMessage] = useState('');

  const [postDraft, setPostDraft] = useState({ category: '', title: '', description: '', city: '', state: '' });
  const [postFiles, setPostFiles] = useState<File[]>([]);
  const [postFileInput, setPostFileInput] = useState<HTMLInputElement | null>(null);
  const [posting, setPosting] = useState(false);
  const [deletingPostId, setDeletingPostId] = useState<string | null>(null);
  const [postNotice, setPostNotice] = useState('');
  const [postError, setPostError] = useState('');

  const [savingPostId, setSavingPostId] = useState<string | null>(null);
  const [actionNotice, setActionNotice] = useState('');
  const [actionError, setActionError] = useState('');

  const loadSavedFeed = async () => {
    if (!supabase || perspective !== 'homeowner') return;
    try {
      const { data, error } = await supabase.rpc('servsync_discover_saved_posts');
      if (error) throw error;
      setSavedFeed((data || []) as DiscoverFeedItem[]);
    } catch {
      setSavedFeed([]);
    }
  };

  const loadFeed = async () => {
    if (!supabase) return;
    setFeedLoading(true);
    try {
      let searchLat: number | null = null;
      let searchLng: number | null = null;
      const locationQuery = filterLocation.trim();
      if (perspective === 'homeowner' && locationQuery) {
        setDiscoverLocationStatus('loading');
        setDiscoverLocationMessage('');
        const geocodeResult = await invokeGeocodeLocation({
          location_text: locationQuery,
          zip_code: '',
          city: '',
          state: '',
        });
        if (geocodeResult.ok && geocodeResult.latitude !== null && geocodeResult.longitude !== null) {
          searchLat = geocodeResult.latitude;
          searchLng = geocodeResult.longitude;
          setDiscoverLocationStatus('geocoded');
          setDiscoverLocationMessage('Showing contractors whose listed service areas overlap this search area.');
        } else {
          setDiscoverLocationStatus('fallback');
          setDiscoverLocationMessage('We could not confirm that location. Showing text matches instead.');
        }
      } else if (perspective === 'homeowner') {
        setDiscoverLocationStatus('idle');
        setDiscoverLocationMessage('');
      }
      const { data, error } = perspective === 'contractor'
        ? await supabase.rpc('servsync_my_discover_posts')
        : await supabase.rpc('servsync_discover_feed', {
          p_category: filterCategory || null,
          p_location: filterLocation || null,
          p_radius_miles: filterLocation.trim() ? Number(filterRadiusMiles) : null,
          p_search_lat: searchLat,
          p_search_lng: searchLng,
        });
      if (error) throw error;
      setFeed((data || []) as DiscoverFeedItem[]);
    } catch {
      // silently show empty
    } finally {
      setFeedLoading(false);
    }
  };

  useEffect(() => {
    void loadFeed();
    if (perspective === 'homeowner') void loadSavedFeed();
  }, []);

  const recordPostView = async (item: DiscoverFeedItem, source: 'homeowner_discover_expand' | 'homeowner_discover_profile') => {
    if (!supabase || perspective !== 'homeowner') return;
    try {
      const today = new Date().toISOString().slice(0, 10);
      const storageKey = `servsync.discover.postView.${userId}.${item.post_id}.${today}`;
      if (window.localStorage.getItem(storageKey)) return;
      const { error } = await supabase.rpc('servsync_record_discover_post_view', {
        p_post_id: item.post_id,
        p_source: source,
      });
      if (error) throw error;
      window.localStorage.setItem(storageKey, new Date().toISOString());
    } catch {
      // View tracking should never interrupt homeowner browsing.
    }
  };

  const kudosCounts = (reviews: PublicReview[]) => {
    const counts: Record<string, number> = {};
    reviews.forEach(r => r.kudos.forEach(k => { counts[k] = (counts[k] ?? 0) + 1; }));
    return Object.entries(counts).sort((a, b) => b[1] - a[1]);
  };

  const uploadPostPhotos = async (files: File[]): Promise<string[]> => {
    if (!supabase || files.length === 0) return [];
    const urls: string[] = [];
    for (const file of files) {
      const contentType = file.type === 'image/jpg' ? 'image/jpeg' : file.type;
      const ext = contentType === 'image/png' ? 'png' : contentType === 'image/webp' ? 'webp' : 'jpg';
      if (!['image/jpeg', 'image/png', 'image/webp'].includes(contentType)) {
        throw new Error('Discover photos must be JPG, PNG, or WebP. HEIC/HEIF photos may upload but will not display reliably in web browsers.');
      }
      const storagePath = `${userId}/posts/${crypto.randomUUID()}.${ext}`;
      const { error: uploadError } = await supabase.storage
        .from('discover-media')
        .upload(storagePath, file, { contentType });
      if (uploadError) throw uploadError;
      const { data: urlData } = supabase.storage.from('discover-media').getPublicUrl(storagePath);
      urls.push(urlData.publicUrl);
    }
    return urls;
  };

  const submitPost = async () => {
    if (!supabase) return;
    if (!postDraft.title.trim()) { setPostError('Add a title before posting.'); return; }
    setPosting(true);
    setPostError('');
    setPostNotice('');
    try {
      const photoUrls = await uploadPostPhotos(postFiles);
      const { error } = await supabase.rpc('servsync_create_contractor_post', {
        p_category: postDraft.category,
        p_title: postDraft.title.trim(),
        p_description: cleanHumanWrittenText(postDraft.description),
        p_photos: photoUrls,
        p_city: postDraft.city.trim(),
        p_state: postDraft.state.trim(),
      });
      if (error) throw error;
      setPostDraft({ category: '', title: '', description: '', city: '', state: '' });
      setPostFiles([]);
      setPostNotice('Post published.');
      await loadFeed();
    } catch (err) {
      setPostError(err instanceof Error ? err.message : 'Unable to create post.');
    } finally {
      setPosting(false);
    }
  };

  const deletePost = async (postId: string) => {
    if (!supabase) return;
    setDeletingPostId(postId);
    try {
      await supabase.rpc('servsync_delete_contractor_post', { p_post_id: postId });
      setFeed(prev => prev.filter(p => p.post_id !== postId));
    } finally {
      setDeletingPostId(null);
    }
  };

  const requestConnection = async (item: DiscoverFeedItem) => {
    if (onRequestConnection) {
      onRequestConnection({
        id: item.contractor_id,
        business_name: item.business_name,
        city: item.contractor_city,
        state: item.contractor_state,
        service_categories: item.categories,
      });
      setSelectedPostId(null);
      return;
    }
    setActionError('Open this from the homeowner portal so you can choose property access for the request.');
  };

  const togglePostSave = async (item: DiscoverFeedItem) => {
    if (!supabase || perspective !== 'homeowner') return;
    const wasSaved = Boolean(item.is_saved);
    setSavingPostId(item.post_id);
    setActionNotice('');
    setActionError('');
    try {
      const { data, error } = await supabase.rpc('servsync_toggle_discover_post_save', {
        p_post_id: item.post_id,
      });
      if (error) throw error;
      const isSaved = Boolean(data);
      setFeed(prev => prev.map(post => {
        if (post.post_id !== item.post_id) return post;
        const currentSaveCount = Number(post.save_count ?? 0);
        const nextSaveCount = isSaved === wasSaved
          ? currentSaveCount
          : Math.max(0, currentSaveCount + (isSaved ? 1 : -1));
        return { ...post, is_saved: isSaved, save_count: nextSaveCount };
      }));
      await loadSavedFeed();
      setActionNotice(isSaved ? 'Post saved.' : 'Post removed from saved posts.');
    } catch (err) {
      setActionError(readableError(err, 'Unable to update saved posts.'));
    } finally {
      setSavingPostId(null);
    }
  };

  const existingConnectionMap = connections.reduce<Record<string, ConnectionStatus>>((map, c) => {
    map[c.contractor_id] = c.status;
    return map;
  }, {});

  const savedFeedCount = savedFeed.length;
  const feedForView = perspective === 'homeowner' && feedView === 'saved'
    ? savedFeed.filter(item => !filterCategory || item.post_category === filterCategory)
    : feed;
  const keywordTerms = normalizeText(filterKeyword).split(' ').filter(Boolean);
  const visibleFeed = keywordTerms.length === 0
    ? feedForView
    : feedForView.filter(item => {
      const searchableText = normalizeText([
        item.title,
        item.description,
        item.business_name,
        item.post_category,
        item.business_summary,
        item.contractor_city,
        item.contractor_state,
        (item.service_areas || []).map(area => contractorServiceAreaDisplay(area)).join(' '),
        item.categories.join(' '),
        item.reviews.map(review => [review.body, review.kudos.join(' ')].join(' ')).join(' '),
      ].join(' '));
      return keywordTerms.every(term => searchableText.includes(term));
    });
  const selectedPost = selectedPostId
    ? [...visibleFeed, ...feed, ...savedFeed].find(item => item.post_id === selectedPostId) ?? null
    : null;
  const selectedPostConnectionStatus = selectedPost ? existingConnectionMap[selectedPost.contractor_id] : undefined;
  const selectedPostSlug = selectedPost ? contractorSlugs[selectedPost.contractor_id] : undefined;
  const selectedPostExternalReviewLinks = selectedPost ? normalizeExternalReviewLinks(selectedPost.external_review_links) : [];
  const selectedPostServiceAreas = selectedPost?.service_areas || [];
  const selectedPostTopKudos = selectedPost ? kudosCounts(selectedPost.reviews).slice(0, 4) : [];

  const openPostDetail = (item: DiscoverFeedItem) => {
    setSelectedPostId(item.post_id);
    void recordPostView(item, 'homeowner_discover_expand');
  };

  return (
    <div className="space-y-5">
      {perspective === 'contractor' && (
        <div className="rounded-2xl border border-blue-100 bg-blue-50 p-5 shadow-sm">
          <div className="flex flex-wrap items-start justify-between gap-4">
            <div className="max-w-3xl">
              <p className="text-sm font-bold text-blue-950">Your Discover presence</p>
              <p className="mt-1 text-sm leading-6 text-blue-900">
                Homeowners can discover your public profile and helpful posts. Discover is homeowner-controlled: contractors can post useful local content, but cannot directly contact homeowners through Discover.
              </p>
              <div className="mt-3 flex flex-wrap items-center gap-2 text-xs font-semibold">
                <span className={`rounded-full px-3 py-1 ${contractorProfile?.public_profile_enabled ? 'bg-emerald-100 text-emerald-700' : 'bg-slate-100 text-slate-600'}`}>
                  {contractorProfile?.public_profile_enabled ? 'Public profile enabled' : 'Public profile hidden'}
                </span>
                {contractorProfile?.business_name && (
                  <span className="rounded-full bg-white/80 px-3 py-1 text-blue-900">{contractorProfile.business_name}</span>
                )}
              </div>
            </div>
            {contractorProfile?.slug && (
              <button
                type="button"
                onClick={() => updateRoute('profile', `slug=${encodeURIComponent(contractorProfile.slug)}`)}
                className={buttonClass('secondary')}
              >
                View public profile
              </button>
            )}
          </div>
        </div>
      )}

      {/* Filter bar */}
      {perspective === 'homeowner' && (
        <div className="rounded-2xl border border-slate-200 bg-white p-4 shadow-sm">
          <div className="mb-3">
            <p className="text-sm font-bold text-slate-950">Filter contractor posts</p>
            <p className="mt-1 text-sm text-slate-500">
              Browse recent work, service updates, availability, and maintenance tips shared publicly by local contractors.
            </p>
            <p className="mt-1 text-xs leading-5 text-slate-500">
              Search by ZIP or city to find contractors whose listed service areas match your area.
            </p>
          </div>
          <div className="grid gap-3 lg:grid-cols-[1fr_0.9fr_1fr_0.8fr_auto]">
            <div className="relative">
              <Search size={15} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
              <input
                className="w-full rounded-xl border border-slate-200 bg-white py-2 pl-9 pr-3 text-sm text-slate-900 placeholder:text-slate-400 outline-none focus:border-blue-500 focus:ring-2 focus:ring-blue-500/20"
                placeholder="Search work, contractor, keyword"
                value={filterKeyword}
                onChange={e => setFilterKeyword(e.target.value)}
              />
            </div>
            <select
              className="w-full rounded-xl border border-slate-200 bg-white px-3 py-2 text-sm text-slate-900 outline-none focus:border-blue-500 focus:ring-2 focus:ring-blue-500/20"
              value={filterCategory}
              onChange={e => setFilterCategory(e.target.value)}
            >
              <option value="">All categories</option>
              {SERVICE_REQUEST_CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
            </select>
            <div className="relative">
              <MapPin size={15} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
              <input
                className="w-full rounded-xl border border-slate-200 bg-white py-2 pl-9 pr-3 text-sm text-slate-900 placeholder:text-slate-400 outline-none focus:border-blue-500 focus:ring-2 focus:ring-blue-500/20"
                placeholder="ZIP or city"
                value={filterLocation}
                onChange={e => setFilterLocation(e.target.value)}
                onKeyDown={e => e.key === 'Enter' && void loadFeed()}
              />
            </div>
            <select
              className="w-full rounded-xl border border-slate-200 bg-white px-3 py-2 text-sm text-slate-900 outline-none focus:border-blue-500 focus:ring-2 focus:ring-blue-500/20"
              value={filterRadiusMiles}
              onChange={e => setFilterRadiusMiles(e.target.value)}
              aria-label="Service area radius"
            >
              {CONTRACTOR_SERVICE_AREA_RADIUS_OPTIONS.map(radius => (
                <option key={radius} value={radius}>{radius} miles</option>
              ))}
            </select>
            <button
              type="button"
              onClick={() => void loadFeed()}
              disabled={feedLoading}
              className={buttonClass('primary')}
            >
              {feedLoading ? 'Loading...' : 'Search'}
            </button>
          </div>
          {filterLocation.trim() && (
            <p className={`mt-3 rounded-xl border px-3 py-2 text-xs leading-5 ${
              discoverLocationStatus === 'fallback'
                ? 'border-amber-200 bg-amber-50 text-amber-900'
                : 'border-blue-100 bg-blue-50 text-blue-900'
            }`}>
              {discoverLocationStatus === 'geocoded'
                ? discoverLocationMessage
                : discoverLocationStatus === 'fallback'
                  ? discoverLocationMessage
                  : discoverLocationStatus === 'loading'
                    ? 'Confirming that location...'
                    : 'Mileage is a guide for now. Results are based on contractor-listed service areas and matching locations.'}
            </p>
          )}
        </div>
      )}
      {perspective === 'homeowner' && (
        <div className="flex flex-wrap gap-2">
          <button
            type="button"
            onClick={() => setFeedView('all')}
            className={`rounded-full px-4 py-2 text-sm font-semibold transition ${feedView === 'all' ? 'bg-blue-600 text-white shadow-sm' : 'border border-slate-200 bg-white text-slate-600 hover:border-blue-300 hover:text-blue-700'}`}
          >
            All Posts
          </button>
          <button
            type="button"
            onClick={() => setFeedView('saved')}
            className={`rounded-full px-4 py-2 text-sm font-semibold transition ${feedView === 'saved' ? 'bg-blue-600 text-white shadow-sm' : 'border border-slate-200 bg-white text-slate-600 hover:border-blue-300 hover:text-blue-700'}`}
          >
            Saved Posts
            {savedFeedCount > 0 && <span className="ml-2 rounded-full bg-white/20 px-2 py-0.5 text-xs">{savedFeedCount}</span>}
          </button>
        </div>
      )}
      {actionNotice && <Notice tone="success" text={actionNotice} />}
      {actionError && <Notice tone="error" text={actionError} />}

      {/* Contractor: share a job */}
      {perspective === 'contractor' && contractorId && (
        <div className="rounded-2xl border border-slate-200 bg-white p-5 shadow-sm">
          <p className="text-sm font-bold text-slate-950">Create Post</p>
          <p className="mt-1 mb-3 text-sm leading-5 text-slate-500">
            Share recent work, maintenance tips, or helpful local advice. Homeowners choose whether to view your profile or request a connection.
          </p>
          <p className="mb-3 rounded-xl border border-blue-100 bg-blue-50 px-3 py-2 text-xs leading-5 text-blue-900">
            Posts are public and should share recent work, maintenance tips, or helpful local advice. Discover does not allow contractors to directly contact homeowners.
            Homeowners choose when to view your profile, connect, or request service.
          </p>
          {postNotice && <div className="mb-3 rounded-xl border border-emerald-200 bg-emerald-50 px-3 py-2 text-sm text-emerald-700">{postNotice}</div>}
          {postError && <div className="mb-3 rounded-xl border border-red-200 bg-red-50 px-3 py-2 text-sm text-red-700">{postError}</div>}
          <div className="grid gap-3 sm:grid-cols-2">
            <Field label="Category">
              <select className={inputClass()} value={postDraft.category} onChange={e => setPostDraft(d => ({ ...d, category: e.target.value }))}>
                <option value="">Select category</option>
                {SERVICE_REQUEST_CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
              </select>
            </Field>
            <Field label="Title">
              <input className={inputClass()} {...writingAssistProps} placeholder="e.g. Spring HVAC maintenance reminder" value={postDraft.title} onChange={e => setPostDraft(d => ({ ...d, title: e.target.value }))} />
            </Field>
            <Field label="City">
              <input className={inputClass()} placeholder="City of job" value={postDraft.city} onChange={e => setPostDraft(d => ({ ...d, city: e.target.value }))} />
            </Field>
            <Field label="State">
              <AutocompleteInput
                id="discover-post-state"
                value={postDraft.state}
                onChange={state => setPostDraft(d => ({ ...d, state }))}
                options={US_STATE_OPTIONS}
                placeholder="Start typing a state..."
              />
            </Field>
            <div className="sm:col-span-2">
              <Field label="Description">
                <textarea className={inputClass()} rows={3} {...writingAssistProps} placeholder="Share recent work, maintenance advice, or helpful local context." value={postDraft.description} onChange={e => setPostDraft(d => ({ ...d, description: e.target.value }))} />
              </Field>
            </div>
          </div>

          <div className="mt-3 flex flex-wrap items-center gap-3">
            <input
              ref={el => setPostFileInput(el)}
              type="file"
              accept="image/jpeg,image/png,image/webp"
              multiple
              className="hidden"
              onChange={e => {
                const files = Array.from(e.target.files ?? []);
                setPostFiles(prev => [...prev, ...files]);
                e.target.value = '';
              }}
            />
            <button type="button" onClick={() => postFileInput?.click()} className={buttonClass('secondary')}>
              <Paperclip size={15} /> Add photos
            </button>
            <span className="max-w-xl text-xs leading-5 text-slate-500">
              Discover photos are public. Use JPG, PNG, or WebP so they display correctly.
            </span>
            {postFiles.length > 0 && (
              <div className="flex flex-wrap gap-2">
                {postFiles.map((f, i) => (
                  <div key={i} className="flex items-center gap-1 rounded-lg bg-slate-100 px-2 py-1 text-xs text-slate-600">
                    {f.name}
                    <button type="button" onClick={() => setPostFiles(prev => prev.filter((_, j) => j !== i))} className="text-slate-400 hover:text-red-500">
                      <X size={12} />
                    </button>
                  </div>
                ))}
              </div>
            )}
          </div>

          <div className="mt-4">
            <button type="button" onClick={() => void submitPost()} disabled={posting} className={buttonClass('primary')}>
              {posting ? 'Publishing...' : 'Create Post'}
            </button>
          </div>
        </div>
      )}

      {perspective === 'contractor' && (
        <div className="rounded-2xl border border-slate-200 bg-white p-4 shadow-sm">
          <div className="flex flex-wrap items-center justify-between gap-3">
            <div>
              <p className="text-sm font-bold text-slate-950">My Posts</p>
              <p className="mt-1 text-sm text-slate-500">
                Only posts from your contractor account appear here. View counts are real homeowner views, shown as aggregate totals only.
              </p>
            </div>
            <span className="rounded-full bg-slate-100 px-3 py-1 text-xs font-semibold text-slate-600">
              {feed.length} {feed.length === 1 ? 'post' : 'posts'}
            </span>
          </div>
        </div>
      )}

      {/* Feed */}
      {!feedLoading && visibleFeed.length === 0 && (
        <EmptyState text={perspective === 'homeowner' && feedView === 'saved' && savedFeedCount === 0
          ? 'No saved posts yet. Save helpful contractor posts to revisit later.'
          : feed.length === 0
            ? perspective === 'homeowner'
              ? 'Contractor posts will appear here as local pros start sharing updates, services, and availability.'
              : 'No posts yet. Post recent work, seasonal advice, or maintenance tips to help homeowners understand what you do.'
            : 'No posts match those filters yet.'} />
      )}

      {visibleFeed.map(item => {
        const isOwnPost = item.contractor_id === contractorId;
        const topKudos = kudosCounts(item.reviews).slice(0, 4);
        const existingStatus = existingConnectionMap[item.contractor_id];
        const contractorSlug = contractorSlugs[item.contractor_id];
        const externalReviewLinks = normalizeExternalReviewLinks(item.external_review_links);
        const serviceAreas = item.service_areas || [];

        return (
          <div
            key={item.post_id}
            role="button"
            tabIndex={0}
            onClick={() => openPostDetail(item)}
            onKeyDown={event => {
              if (event.key === 'Enter' || event.key === ' ') {
                event.preventDefault();
                openPostDetail(item);
              }
            }}
            className="overflow-hidden rounded-2xl border border-slate-200 bg-white shadow-sm transition hover:border-blue-200 hover:shadow-md focus:outline-none focus:ring-2 focus:ring-blue-500/30"
          >
            {/* Card header */}
            <div className="px-5 py-4">
              <div className="flex flex-wrap items-start justify-between gap-3">
                <div className="min-w-0 flex-1">
                  {/* Contractor info */}
                  <div className="flex flex-wrap items-center gap-2">
                    <span className="font-bold text-slate-950">{item.business_name}</span>
                    {item.post_category && (
                      <span className="rounded-full bg-blue-50 px-2 py-0.5 text-xs font-semibold text-blue-700">{item.post_category}</span>
                    )}
                  </div>
                  <p className="mt-0.5 flex items-center gap-1 text-xs text-slate-500">
                    <MapPin size={12} className="shrink-0" />
                    {[item.contractor_city, item.contractor_state].filter(Boolean).join(', ') || 'Location not listed'}
                    {item.categories.length > 0 && <span className="ml-2 text-slate-500">· {item.categories.slice(0,3).join(', ')}</span>}
                  </p>
                  {serviceAreas.length > 0 && perspective === 'homeowner' && (
                    <div className="mt-2 flex flex-wrap gap-1.5">
                      {serviceAreas.slice(0, 4).map((area, index) => (
                        <span key={`${item.post_id}-service-area-${index}`} className="rounded-full bg-slate-100 px-2 py-0.5 text-xs font-semibold text-slate-600">
                          {contractorServiceAreaDisplay(area)}
                        </span>
                      ))}
                      {serviceAreas.length > 4 && (
                        <span className="rounded-full bg-slate-50 px-2 py-0.5 text-xs font-semibold text-slate-500">
                          +{serviceAreas.length - 4} more
                        </span>
                      )}
                    </div>
                  )}

                  {/* Post title */}
                  <p className="mt-2 text-base font-semibold text-slate-950">{item.title}</p>
                  {item.description && (
                    <p className="mt-1 text-sm text-slate-600 line-clamp-2">{item.description}</p>
                  )}

                  {/* Photo strip */}
                  {item.photos.length > 0 && (
                    <div className="mt-3 flex gap-2 overflow-x-auto pb-1">
                      {item.photos.slice(0, 4).map((url, i) => (
                        <img key={i} src={url} alt="" className="h-24 w-24 shrink-0 rounded-xl border border-slate-200 object-cover" />
                      ))}
                    </div>
                  )}

                  {/* Kudos chips */}
                  {topKudos.length > 0 && (
                    <div className="mt-2 flex flex-wrap gap-1.5">
                      {topKudos.map(([k, count]) => (
                        <span key={k} className="rounded-full bg-blue-50 px-2 py-0.5 text-xs font-semibold text-blue-700">
                          {k} <span className="opacity-60">×{count}</span>
                        </span>
                      ))}
                    </div>
                  )}
                  {externalReviewLinks.length > 0 && perspective === 'homeowner' && (
                    <div className="mt-2 flex flex-wrap gap-1.5">
                      <span className="inline-flex items-center gap-1 rounded-full border border-slate-200 bg-slate-50 px-2.5 py-1 text-xs font-semibold text-slate-600">
                        <Star size={12} />
                        External reviews available
                      </span>
                    </div>
                  )}
                </div>

                {/* Rating + actions */}
                <div className="flex shrink-0 flex-col items-end gap-2" onClick={event => event.stopPropagation()}>
                  {item.avg_rating !== null && (
                    <div className="flex items-center gap-1">
                      <StarDisplay rating={Math.round(item.avg_rating)} />
                      <span className="text-sm font-bold text-slate-950">{item.avg_rating.toFixed(1)}</span>
                    </div>
                  )}
                  {item.review_count > 0 && (
                    <p className="text-xs text-slate-500">{item.review_count} {item.review_count === 1 ? 'review' : 'reviews'}</p>
                  )}
                  {isOwnPost && (
                    <span className="rounded-full bg-slate-100 px-3 py-1 text-xs font-semibold text-slate-600">
                      {Number(item.view_count ?? 0).toLocaleString()} {Number(item.view_count ?? 0) === 1 ? 'view' : 'views'} · {Number(item.save_count ?? 0).toLocaleString()} {Number(item.save_count ?? 0) === 1 ? 'save' : 'saves'}
                    </span>
                  )}

                  {perspective === 'homeowner' && (
                    <button
                      type="button"
                      disabled={savingPostId === item.post_id}
                      onClick={() => void togglePostSave(item)}
                      className={`rounded-xl border px-3 py-2 text-sm font-semibold transition ${item.is_saved ? 'border-blue-200 bg-blue-50 text-blue-700 hover:bg-blue-100' : 'border-slate-200 bg-white text-slate-600 hover:border-blue-300 hover:text-blue-700'}`}
                    >
                      {savingPostId === item.post_id ? 'Saving...' : item.is_saved ? 'Saved' : 'Save Post'}
                    </button>
                  )}

                  {perspective === 'homeowner' && contractorSlug && (
                    <button
                      type="button"
                      onClick={() => {
                        void recordPostView(item, 'homeowner_discover_profile');
                        updateRoute('profile', `slug=${encodeURIComponent(contractorSlug)}`);
                      }}
                      className={buttonClass('secondary')}
                    >
                      View Profile
                    </button>
                  )}
                  {perspective === 'homeowner' && (!existingStatus || ['declined', 'revoked', 'dismissed'].includes(existingStatus)) && (
                    <button
                      type="button"
                      onClick={() => void requestConnection(item)}
                      className={buttonClass('primary')}
                    >
                      {existingStatus ? 'Request again' : 'Request connection'}
                    </button>
                  )}
                  {perspective === 'homeowner' && existingStatus === 'active' && (
                    <div className="flex flex-col items-end gap-2">
                      <span className="rounded-full bg-emerald-50 px-3 py-1 text-xs font-semibold text-emerald-700">
                        Connected
                      </span>
                      <button
                        type="button"
                        onClick={() => onRequestService?.(item.contractor_id, item.post_category || item.categories[0] || 'General Maintenance')}
                        className={buttonClass('primary')}
                      >
                        Request service
                      </button>
                    </div>
                  )}
                  {perspective === 'homeowner' && existingStatus === 'pending' && (
                    <span className="rounded-full bg-amber-50 px-3 py-1 text-xs font-semibold text-amber-700">
                      Pending
                    </span>
                  )}
                  {isOwnPost && (
                    <button
                      type="button"
                      disabled={deletingPostId === item.post_id}
                      onClick={() => void deletePost(item.post_id)}
                      className="text-xs text-slate-500 transition-colors hover:text-red-500"
                    >
                      {deletingPostId === item.post_id ? 'Deleting…' : 'Delete post'}
                    </button>
                  )}
                  <button
                    type="button"
                    onClick={() => openPostDetail(item)}
                    className="flex items-center gap-1 text-xs font-semibold text-slate-500 hover:text-slate-900"
                  >
                    View Post
                    <ChevronRight size={13} />
                  </button>
                </div>
              </div>
            </div>
          </div>
        );
      })}
      {selectedPost && (
        <div
          className="fixed inset-0 z-50 flex items-end justify-center bg-slate-950/50 p-0 sm:items-center sm:p-4"
          role="dialog"
          aria-modal="true"
          aria-labelledby="discover-post-detail-title"
          onMouseDown={event => {
            if (event.target === event.currentTarget) setSelectedPostId(null);
          }}
        >
          <div className="max-h-[92vh] w-full overflow-y-auto rounded-t-2xl bg-white shadow-2xl sm:max-w-3xl sm:rounded-2xl">
            <div className="sticky top-0 z-10 flex items-start justify-between gap-3 border-b border-slate-200 bg-white px-5 py-4">
              <div className="min-w-0">
                <p className="text-xs font-bold uppercase tracking-[0.14em] text-slate-500">Contractor post</p>
                <h2 id="discover-post-detail-title" className="mt-1 text-xl font-bold text-slate-950">{selectedPost.title}</h2>
                <p className="mt-1 text-sm text-slate-500">
                  {selectedPost.business_name}
                  {selectedPost.post_category ? ` · ${selectedPost.post_category}` : ''}
                </p>
              </div>
              <button
                type="button"
                onClick={() => setSelectedPostId(null)}
                className="rounded-full p-2 text-slate-500 transition hover:bg-slate-100 hover:text-slate-900"
                aria-label="Close post detail"
              >
                <X size={18} />
              </button>
            </div>

            <div className="space-y-5 px-5 py-5">
              <div className="flex flex-wrap items-center gap-2 text-xs font-semibold">
                <span className="inline-flex items-center gap-1 rounded-full bg-slate-100 px-2.5 py-1 text-slate-600">
                  <MapPin size={12} />
                  {[selectedPost.contractor_city, selectedPost.contractor_state].filter(Boolean).join(', ') || 'Location not listed'}
                </span>
                <span className="rounded-full bg-slate-100 px-2.5 py-1 text-slate-600">
                  Posted {new Date(selectedPost.created_at).toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' })}
                </span>
                {selectedPost.avg_rating !== null && selectedPost.review_count > 0 && (
                  <span className="inline-flex items-center gap-1 rounded-full bg-blue-50 px-2.5 py-1 text-blue-700">
                    <Star size={12} />
                    {selectedPost.avg_rating.toFixed(1)} from {selectedPost.review_count} ServSync {selectedPost.review_count === 1 ? 'review' : 'reviews'}
                  </span>
                )}
              </div>

              {selectedPost.description && (
                <p className="whitespace-pre-wrap text-sm leading-6 text-slate-700">{selectedPost.description}</p>
              )}

              {selectedPost.photos.length > 0 && (
                <div>
                  <p className="mb-2 text-xs font-bold uppercase tracking-wide text-slate-500">Photos</p>
                  <div className="grid grid-cols-2 gap-2 sm:grid-cols-3">
                    {selectedPost.photos.map((url, i) => (
                      <a key={i} href={url} target="_blank" rel="noopener noreferrer">
                        <img src={url} alt="" className="h-36 w-full rounded-xl border border-slate-200 object-cover transition-opacity hover:opacity-90" />
                      </a>
                    ))}
                  </div>
                </div>
              )}

              {(selectedPost.business_summary || selectedPost.categories.length > 0 || selectedPostServiceAreas.length > 0) && (
                <div className="rounded-2xl border border-slate-200 bg-slate-50 p-4">
                  <p className="text-sm font-bold text-slate-950">{selectedPost.business_name}</p>
                  {selectedPost.business_summary && (
                    <p className="mt-2 text-sm leading-6 text-slate-600">{selectedPost.business_summary}</p>
                  )}
                  {selectedPost.categories.length > 0 && (
                    <div className="mt-3 flex flex-wrap gap-1.5">
                      {selectedPost.categories.slice(0, 8).map(category => (
                        <span key={`${selectedPost.post_id}-${category}`} className="rounded-full bg-white px-2.5 py-1 text-xs font-semibold text-slate-600">
                          {category}
                        </span>
                      ))}
                    </div>
                  )}
                  {selectedPostServiceAreas.length > 0 && (
                    <div className="mt-3">
                      <p className="mb-1 text-xs font-bold uppercase tracking-wide text-slate-500">Service area</p>
                      <div className="flex flex-wrap gap-1.5">
                        {selectedPostServiceAreas.slice(0, 8).map((area, index) => (
                          <span key={`${selectedPost.post_id}-modal-service-area-${index}`} className="rounded-full bg-white px-2.5 py-1 text-xs font-semibold text-slate-600">
                            {contractorServiceAreaDisplay(area)}
                          </span>
                        ))}
                        {selectedPostServiceAreas.length > 8 && (
                          <span className="rounded-full bg-white px-2.5 py-1 text-xs font-semibold text-slate-500">
                            +{selectedPostServiceAreas.length - 8} more
                          </span>
                        )}
                      </div>
                    </div>
                  )}
                </div>
              )}

              {selectedPostTopKudos.length > 0 && (
                <div>
                  <p className="mb-2 text-xs font-bold uppercase tracking-wide text-slate-500">Common review notes</p>
                  <div className="flex flex-wrap gap-1.5">
                    {selectedPostTopKudos.map(([k, count]) => (
                      <span key={k} className="rounded-full bg-blue-50 px-2.5 py-1 text-xs font-semibold text-blue-700">
                        {k} <span className="opacity-60">x{count}</span>
                      </span>
                    ))}
                  </div>
                </div>
              )}

              {selectedPostExternalReviewLinks.length > 0 && perspective === 'homeowner' && (
                <div>
                  <p className="mb-1 text-xs font-bold uppercase tracking-wide text-slate-500">External Reviews</p>
                  <p className="mb-2 text-xs leading-5 text-slate-500">
                    These links open third-party review sites. They are separate from ServSync reviews.
                  </p>
                  <div className="flex flex-wrap gap-2">
                    {selectedPostExternalReviewLinks.map(link => (
                      <a
                        key={`${selectedPost.post_id}-${link.source}-${link.url}`}
                        href={link.url}
                        target="_blank"
                        rel="noopener noreferrer"
                        className={buttonClass('secondary')}
                      >
                        View {link.label || externalReviewSourceLabel(link.source)}
                      </a>
                    ))}
                  </div>
                </div>
              )}

              {selectedPost.reviews.length > 0 && (
                <div>
                  <p className="mb-2 text-xs font-bold uppercase tracking-wide text-slate-500">ServSync Reviews</p>
                  <div className="space-y-2">
                    {selectedPost.reviews.map((review, i) => (
                      <PublicReviewCard key={i} review={review} />
                    ))}
                  </div>
                </div>
              )}

              <div className="flex flex-wrap gap-2 border-t border-slate-200 pt-4">
                {perspective === 'homeowner' && (
                  <button
                    type="button"
                    disabled={savingPostId === selectedPost.post_id}
                    onClick={() => void togglePostSave(selectedPost)}
                    className={buttonClass(selectedPost.is_saved ? 'secondary' : 'primary')}
                  >
                    {savingPostId === selectedPost.post_id ? 'Saving...' : selectedPost.is_saved ? 'Saved' : 'Save Post'}
                  </button>
                )}
                {perspective === 'homeowner' && selectedPostSlug && (
                  <button
                    type="button"
                    onClick={() => {
                      void recordPostView(selectedPost, 'homeowner_discover_profile');
                      setSelectedPostId(null);
                      updateRoute('profile', `slug=${encodeURIComponent(selectedPostSlug)}`);
                    }}
                    className={buttonClass('secondary')}
                  >
                    View Contractor Profile
                  </button>
                )}
                {perspective === 'homeowner' && (!selectedPostConnectionStatus || ['declined', 'revoked', 'dismissed'].includes(selectedPostConnectionStatus)) && (
                  <button
                    type="button"
                    onClick={() => void requestConnection(selectedPost)}
                    className={buttonClass('primary')}
                  >
                    {selectedPostConnectionStatus ? 'Request again' : 'Connect'}
                  </button>
                )}
                {perspective === 'homeowner' && selectedPostConnectionStatus === 'active' && (
                  <button
                    type="button"
                    onClick={() => {
                      onRequestService?.(selectedPost.contractor_id, selectedPost.post_category || selectedPost.categories[0] || 'General Maintenance');
                      setSelectedPostId(null);
                    }}
                    className={buttonClass('primary')}
                  >
                    Request Service
                  </button>
                )}
                {perspective === 'homeowner' && selectedPostConnectionStatus === 'pending' && (
                  <span className="inline-flex items-center rounded-xl bg-amber-50 px-3 py-2 text-sm font-semibold text-amber-700">
                    Connection pending
                  </span>
                )}
                <button type="button" onClick={() => setSelectedPostId(null)} className={buttonClass('secondary')}>
                  Close
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

function SidebarLayout({
  tabs,
  activeTab,
  onChange,
  actions,
  children,
  brand,
  profile,
  profileLogoUrl,
  profileLogoFit = 'contain',
  onSignOut,
}: {
  tabs: { id: string; label: string; icon: React.ReactNode; badge?: number; group?: string }[];
  activeTab: string;
  onChange: (id: string) => void;
  actions?: React.ReactNode;
  children: React.ReactNode;
  brand: { name: string; subtitle: string };
  profile: Profile;
  profileLogoUrl?: string | null;
  profileLogoFit?: 'contain' | 'cover';
  onSignOut: () => Promise<void>;
}) {
  const [mobileOpen, setMobileOpen] = useState(false);
  const activeTabMeta = tabs.find(tab => tab.id === activeTab);
  const groupedTabs = tabs.reduce<Array<{ group: string; tabs: typeof tabs }>>((groups, tab) => {
    const groupName = tab.group || 'Navigation';
    const existing = groups.find(group => group.group === groupName);
    if (existing) {
      existing.tabs.push(tab);
    } else {
      groups.push({ group: groupName, tabs: [tab] });
    }
    return groups;
  }, []);

  const renderTabButton = (tab: (typeof tabs)[number]) => (
    <button
      key={tab.id}
      type="button"
      onClick={() => { onChange(tab.id); setMobileOpen(false); }}
      className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl text-sm font-medium transition-colors text-left ${
        activeTab === tab.id
          ? 'bg-[#0078FF] text-white'
          : 'text-blue-100/75 hover:bg-white/10 hover:text-white'
      }`}
    >
      <span className="shrink-0 opacity-80">{tab.icon}</span>
      <span className="flex-1 truncate">{tab.label}</span>
      {tab.badge !== undefined && tab.badge > 0 && (
        <span className="ml-auto flex h-5 min-w-[20px] items-center justify-center rounded-full bg-[#1B85FB] px-1 text-xs font-bold text-white">
          {tab.badge > 99 ? '99+' : tab.badge}
        </span>
      )}
    </button>
  );

  const sidebarContent = (
    <div className="flex h-full min-h-0 flex-col bg-[#02132D] border-r border-[#1B85FB]/15">
      <div className="flex items-center gap-3 px-4 py-4 border-b border-[#1B85FB]/15 shrink-0">
        <div className="flex h-9 w-9 items-center justify-center overflow-hidden rounded-lg bg-[#02132D] shadow-sm shrink-0">
          <img src="/servsync-mark-white.png" alt="ServSync" className="h-full w-full object-cover" />
        </div>
        <div className="min-w-0 flex-1">
          <p className="font-bold text-white leading-tight text-sm truncate">{brand.name}</p>
          <p className="text-xs text-blue-100/70 truncate">{brand.subtitle}</p>
        </div>
        {actions && <div className="shrink-0">{actions}</div>}
      </div>

      <nav className="min-h-0 flex-1 overflow-y-auto py-3 px-2 space-y-4">
        {groupedTabs.map(group => (
          <div key={group.group}>
            <p className="px-3 pb-1.5 text-[10px] font-bold uppercase tracking-[0.16em] text-[#1B85FB]/70">
              {group.group}
            </p>
            <div className="space-y-0.5">
              {group.tabs.map(renderTabButton)}
            </div>
          </div>
        ))}
      </nav>

      <div className="border-t border-[#1B85FB]/15 px-2 py-3 shrink-0 space-y-1">
        <div className="flex items-center gap-3 px-2 py-2 rounded-xl hover:bg-white/10 transition-colors group">
          <div className="flex h-8 w-8 items-center justify-center overflow-hidden rounded-full bg-[#1B85FB]/15 text-blue-50 text-xs font-bold shrink-0">
            {profileLogoUrl ? (
              <img
                src={profileLogoUrl}
                alt={`${brand.name} profile`}
                className={profileLogoFit === 'cover' ? 'h-full w-full object-cover' : 'h-full w-full bg-white object-contain p-1'}
              />
            ) : (
              (profile.full_name || profile.email || '?').charAt(0).toUpperCase()
            )}
          </div>
          <div className="min-w-0 flex-1">
            <p className="text-sm font-medium text-white truncate leading-tight">{profile.full_name || profile.email}</p>
            <p className="text-xs text-blue-100/70 capitalize truncate">{profile.role.replace('_', ' ')}</p>
          </div>
          <button
            type="button"
            onClick={() => void onSignOut()}
            className="shrink-0 text-blue-100/70 hover:text-white transition-colors"
            title="Sign out"
          >
            <LogOut size={16} />
          </button>
        </div>
        <LegalLinks contractor={profile.role === 'contractor'} className="px-2 pt-1 text-blue-100/55" />
      </div>
    </div>
  );

  return (
    <div className="flex min-h-screen bg-[#F7F9FC] md:h-screen md:overflow-hidden">
      <aside className="hidden md:flex md:w-64 md:shrink-0 md:flex-col">
        {sidebarContent}
      </aside>

      {mobileOpen && (
        <div className="fixed inset-0 z-50 flex md:hidden">
          <div className="absolute inset-0 bg-black/60" onClick={() => setMobileOpen(false)} />
          <aside className="relative z-10 flex w-64 flex-col shadow-xl">
            {sidebarContent}
          </aside>
        </div>
      )}

      <div className="flex min-h-screen flex-1 min-w-0 flex-col md:min-h-0 md:overflow-hidden">
        <div className="flex items-center gap-3 border-b border-[#E1E3E7] bg-white px-4 py-3 md:hidden shrink-0">
          <button type="button" onClick={() => setMobileOpen(true)} className="text-[#223D67] hover:text-[#0078FF] transition-colors">
            <Menu size={22} />
          </button>
          <div className="min-w-0 flex-1">
            <p className="font-bold text-[#02132D] text-sm leading-tight">{brand.name}</p>
            <p className="text-xs text-[#223D67] truncate">{activeTabMeta?.label || brand.subtitle}</p>
          </div>
          {actions && <div className="shrink-0">{actions}</div>}
        </div>
        <main className="min-h-0 flex-1 overflow-y-visible md:overflow-y-auto">
          <div className="mx-auto max-w-6xl space-y-5 px-4 py-5 sm:px-6">
            <div className="hidden items-center justify-between gap-3 md:flex">
              <div>
                <p className="text-[11px] font-semibold uppercase tracking-[0.14em] text-[#0078FF]">{activeTabMeta?.group || brand.subtitle}</p>
                <h1 className="mt-0.5 text-lg font-bold text-[#02132D]">{activeTabMeta?.label || brand.subtitle}</h1>
              </div>
            </div>
            {children}
          </div>
        </main>
      </div>
    </div>
  );
}


