const CALENDAR_EVENT_TYPE_OPTIONS: { value: CalendarEventType; label: string }[] = [
  { value: 'service_visit', label: 'Service Visit' },
  { value: 'inspection_visit', label: 'Inspection Visit' },
  { value: 'estimate_visit', label: 'Estimate Visit' },
  { value: 'follow_up_visit', label: 'Follow-Up Visit' },
  { value: 'custom', label: 'Custom' },
];

function calendarEventTypeLabel(type: string) {
  const legacyLabels: Record<string, string> = {
    routine_inspection: 'Inspection Visit',
    follow_up: 'Follow-Up Visit',
    reminder: 'Custom',
    check_in: 'Service Visit',
    other: 'Custom',
  };
  return CALENDAR_EVENT_TYPE_OPTIONS.find(option => option.value === type)?.label ?? legacyLabels[type] ?? 'Event';
}

const CALENDAR_EVENT_JOB_TYPE_OPTIONS: { value: string; label: string; helper: string }[] = [
  { value: 'service_visit', label: 'Service job', helper: 'General service work, diagnosis, or a standard visit.' },
  { value: 'repair', label: 'Repair job', helper: 'Work focused on fixing a known issue.' },
  { value: 'install', label: 'Install job', helper: 'Installation or replacement work.' },
  { value: 'estimate_visit', label: 'Estimate visit', helper: 'A visit to review scope and prepare pricing.' },
  { value: 'inspection', label: 'Inspection / checklist job', helper: 'Structured inspection or report workflow.' },
  { value: 'maintenance_visit', label: 'Maintenance / checklist job', helper: 'Routine maintenance using checklist-style tracking.' },
];

function toDateTimeLocalValue(iso: string) {
  const d = new Date(iso);
  if (Number.isNaN(d.getTime())) return '';
  const pad = (n: number) => String(n).padStart(2, '0');
  return `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())}T${pad(d.getHours())}:${pad(d.getMinutes())}`;
}

function defaultCalendarEventStart(dateValue?: string | null) {
  const d = new Date();
  d.setHours(d.getHours() + 1, 0, 0, 0);
  if (dateValue && /^\d{4}-\d{2}-\d{2}$/.test(dateValue)) {
    const pad = (n: number) => String(n).padStart(2, '0');
    return `${dateValue}T${pad(d.getHours())}:${pad(d.getMinutes())}`;
  }
  return toDateTimeLocalValue(d.toISOString());
}

function CalendarEventComposer({
  event,
  defaultDate,
  occurrenceStartsAt,
  linkedJob,
  localContacts,
  busy,
  onSave,
  creatingJob,
  onCreateJob,
  onOpenLinkedJob,
  onDelete,
  onDeleteLinkedEvent,
  onClose,
}: {
  event: ContractorCalendarEvent | null;
  defaultDate?: string | null;
  occurrenceStartsAt: string | null;
  linkedJob: ContractorCalendarEventJobLink | null;
  localContacts: ContractorLocalContact[];
  busy: boolean;
  onSave: (draft: CalendarEventDraft) => void;
  creatingJob: boolean;
  onCreateJob?: (jobType: string) => void;
  onOpenLinkedJob: (link: ContractorCalendarEventJobLink | null) => void;
  onDelete?: () => void;
  onDeleteLinkedEvent?: (mode: 'event_only' | 'event_and_job') => void;
  onClose: () => void;
}) {
  const isEditing = Boolean(event);
  const dialogRef = useRef<HTMLDivElement | null>(null);
  const [draft, setDraft] = useState<CalendarEventDraft>(() => ({
    title: event?.title ?? '',
    event_type: event?.event_type ?? 'service_visit',
    starts_at: event ? toDateTimeLocalValue(event.starts_at) : defaultCalendarEventStart(defaultDate),
    duration_minutes: event?.duration_minutes ? String(event.duration_minutes) : '',
    notes: event?.notes ?? '',
    local_contact_id: event?.local_contact_id ?? '',
    recurrence_frequency: normalizeCalendarEventRecurrenceFrequency(event?.recurrence_frequency),
    recurrence_ends_at: calendarEventEndDateInputValue(event?.recurrence_ends_at),
  }));
  const [recurrenceEndCondition, setRecurrenceEndCondition] = useState<'none' | 'date'>(event?.recurrence_ends_at ? 'date' : 'none');
  const [createJobPanelOpen, setCreateJobPanelOpen] = useState(false);
  const [selectedJobType, setSelectedJobType] = useState('');
  const [deleteLinkedPanelOpen, setDeleteLinkedPanelOpen] = useState(false);
  const { dateValue: eventDateValue, timeValue: eventTimeValue } = splitDateTimeLocalValue(draft.starts_at);
  const eventTimeOptions = calendarEventTimeOptions(eventTimeValue);
  const recurrenceSummary = draft.recurrence_frequency === 'none'
    ? 'Does not repeat'
    : `${calendarEventRecurrenceLabel(draft.recurrence_frequency)}${recurrenceEndCondition === 'date' && draft.recurrence_ends_at ? ` until ${new Date(`${draft.recurrence_ends_at}T12:00:00`).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' })}` : ' with no end date'}`;
  const occurrenceDate = occurrenceStartsAt ? new Date(occurrenceStartsAt) : null;
  const selectedOccurrenceLabel = occurrenceDate && !Number.isNaN(occurrenceDate.getTime())
    ? occurrenceDate.toLocaleString('en-US', {
        month: 'short',
        day: 'numeric',
        year: 'numeric',
        hour: 'numeric',
        minute: '2-digit',
      })
    : '';
  const canCreateJobFromEvent = Boolean(isEditing && event && onCreateJob);
  const eventHasCustomer = Boolean(event?.local_contact_id || event?.homeowner_user_id);
  const eventIsRecurring = normalizeCalendarEventRecurrenceFrequency(event?.recurrence_frequency) !== 'none';
  const selectedJobTypeLabel = CALENDAR_EVENT_JOB_TYPE_OPTIONS.find(option => option.value === selectedJobType)?.label ?? '';

  useEffect(() => {
    const previousOverflow = document.body.style.overflow;
    document.body.style.overflow = 'hidden';
    const focusFrame = window.requestAnimationFrame(() => dialogRef.current?.focus());
    return () => {
      window.cancelAnimationFrame(focusFrame);
      document.body.style.overflow = previousOverflow;
    };
  }, []);

  return (
    <div className="fixed inset-0 z-[90] flex items-start justify-center overflow-y-auto bg-black/40 p-4">
      <div
        ref={dialogRef}
        role="dialog"
        aria-modal="true"
        aria-label={isEditing ? 'Calendar event' : 'New calendar event'}
        tabIndex={-1}
        onKeyDown={event => {
          if (event.key === 'Escape' && !busy) onClose();
        }}
        className="my-8 w-full max-w-lg rounded-2xl border border-[#E1E3E7] bg-white p-6 shadow-2xl outline-none"
      >
        <div className="mb-1 flex items-center justify-between gap-3">
          <h2 className="text-lg font-bold text-[#02132D]">{isEditing ? 'Calendar event' : 'New calendar event'}</h2>
          <button type="button" onClick={onClose} className="text-[#223D67]/70 hover:text-[#02132D]"><X size={18} /></button>
        </div>
        <p className="mb-4 inline-flex items-center gap-1.5 rounded-full bg-violet-100 px-2.5 py-0.5 text-xs font-semibold text-violet-700">
          {linkedJob ? 'Tied to a job' : 'Not tied to a job'}
        </p>
        {isEditing && (
          <div className="mb-4 rounded-xl border border-violet-100 bg-violet-50 px-3 py-2 text-xs leading-5 text-violet-900">
            {linkedJob ? (
              <span>This event occurrence is tied to a job. You can open the job or delete just the calendar event from this occurrence.</span>
            ) : eventIsRecurring ? (
              <span>Create Job from Event will create a job for the selected occurrence only{selectedOccurrenceLabel ? ` (${selectedOccurrenceLabel})` : ''}. Future repeats stay as calendar events.</span>
            ) : (
              <span>Create Job from Event will turn this calendar event into a scheduled job visit.</span>
            )}
          </div>
        )}

        <div className="space-y-4">
          <Field label="Title">
            <input className={inputClass()} value={draft.title} onChange={e => setDraft(d => ({ ...d, title: e.target.value }))} placeholder="e.g. Routine roof inspection" />
          </Field>
          <Field label="Event type">
            <select className={inputClass()} value={draft.event_type} onChange={e => setDraft(d => ({ ...d, event_type: e.target.value as CalendarEventType }))}>
              {CALENDAR_EVENT_TYPE_OPTIONS.map(option => <option key={option.value} value={option.value}>{option.label}</option>)}
            </select>
          </Field>
          <div className="grid gap-4 sm:grid-cols-2">
            <Field label="Event date">
              <input
                type="date"
                className={inputClass()}
                value={eventDateValue}
                onChange={e => setDraft(d => {
                  const { timeValue } = splitDateTimeLocalValue(d.starts_at);
                  return { ...d, starts_at: combineDateTimeLocalValue(e.target.value, timeValue) };
                })}
              />
            </Field>
            <Field label="Event time">
              <select
                className={inputClass()}
                value={eventTimeValue}
                onChange={e => setDraft(d => {
                  const { dateValue } = splitDateTimeLocalValue(d.starts_at);
                  return { ...d, starts_at: combineDateTimeLocalValue(dateValue, e.target.value) };
                })}
              >
                <option value="">Choose time</option>
                {eventTimeOptions.map(option => (
                  <option key={option.value} value={option.value}>{option.label}</option>
                ))}
              </select>
            </Field>
          </div>
          <div className="grid gap-4 sm:grid-cols-2">
            <Field label="Duration (minutes, optional)">
              <input type="number" min="1" max="1440" className={inputClass()} value={draft.duration_minutes} onChange={e => setDraft(d => ({ ...d, duration_minutes: e.target.value }))} placeholder="60" />
            </Field>
            <Field label="Customer (optional)">
              <select className={inputClass()} value={draft.local_contact_id} onChange={e => setDraft(d => ({ ...d, local_contact_id: e.target.value }))}>
                <option value="">No customer</option>
                {localContacts.map(contact => <option key={contact.id} value={contact.id}>{contact.display_name}</option>)}
              </select>
            </Field>
          </div>
          <div className="grid gap-4 sm:grid-cols-2">
            <Field label="Repeat">
              <select
                className={inputClass()}
                value={draft.recurrence_frequency}
                onChange={e => setDraft(d => {
                  const frequency = e.target.value as CalendarEventRecurrenceFrequency;
                  if (frequency === 'none') setRecurrenceEndCondition('none');
                  return {
                    ...d,
                    recurrence_frequency: frequency,
                    recurrence_ends_at: frequency === 'none' ? '' : d.recurrence_ends_at,
                  };
                })}
              >
                {CALENDAR_EVENT_RECURRENCE_OPTIONS.map(option => (
                  <option key={option.value} value={option.value}>{option.label}</option>
                ))}
              </select>
            </Field>
            {draft.recurrence_frequency !== 'none' ? (
              <Field label="End condition">
                <select
                  className={inputClass()}
                  value={recurrenceEndCondition}
                  onChange={e => {
                    const condition = e.target.value === 'date' ? 'date' : 'none';
                    setRecurrenceEndCondition(condition);
                    if (condition === 'none') setDraft(d => ({ ...d, recurrence_ends_at: '' }));
                  }}
                >
                  <option value="none">No end date</option>
                  <option value="date">End after date</option>
                </select>
              </Field>
            ) : (
              <div className="rounded-xl border border-slate-200 bg-slate-50 px-3 py-2 text-sm text-slate-500">
                One-time event
              </div>
            )}
          </div>
          {draft.recurrence_frequency !== 'none' && recurrenceEndCondition === 'date' && (
            <Field label="End after date">
              <input
                type="date"
                className={inputClass()}
                value={draft.recurrence_ends_at}
                min={eventDateValue || undefined}
                onChange={e => setDraft(d => ({ ...d, recurrence_ends_at: e.target.value }))}
              />
            </Field>
          )}
          <p className="rounded-lg bg-violet-50 px-3 py-2 text-xs font-semibold text-violet-800">
            {recurrenceSummary}
          </p>
          {isEditing && !linkedJob && createJobPanelOpen && (
            <div className="rounded-xl border border-blue-200 bg-blue-50 p-3">
              <p className="text-sm font-bold text-blue-950">Choose the job type</p>
              <p className="mt-1 text-xs leading-5 text-blue-800">
                Event type describes the calendar item only. Choose the job workflow you want ServSync to create.
              </p>
              <div className="mt-3 space-y-2">
                {CALENDAR_EVENT_JOB_TYPE_OPTIONS.map(option => (
                  <label key={option.value} className={`flex cursor-pointer gap-3 rounded-lg border p-3 text-sm transition ${selectedJobType === option.value ? 'border-blue-300 bg-white shadow-sm' : 'border-blue-100 bg-white/70 hover:border-blue-200'}`}>
                    <input
                      type="radio"
                      name="calendar-event-job-type"
                      className="mt-1"
                      value={option.value}
                      checked={selectedJobType === option.value}
                      onChange={() => setSelectedJobType(option.value)}
                    />
                    <span>
                      <span className="block font-semibold text-slate-950">{option.label}</span>
                      <span className="mt-0.5 block text-xs leading-5 text-slate-600">{option.helper}</span>
                    </span>
                  </label>
                ))}
              </div>
              <div className="mt-3 flex flex-wrap justify-end gap-2">
                <button type="button" className={buttonClass('secondary')} onClick={() => setCreateJobPanelOpen(false)} disabled={busy || creatingJob}>
                  Cancel
                </button>
                <button
                  type="button"
                  className={buttonClass('primary')}
                  disabled={!selectedJobType || busy || creatingJob}
                  onClick={() => selectedJobType && onCreateJob?.(selectedJobType)}
                >
                  {creatingJob ? 'Creating job...' : selectedJobTypeLabel ? `Create ${selectedJobTypeLabel}` : 'Create job'}
                </button>
              </div>
            </div>
          )}
          {isEditing && linkedJob && deleteLinkedPanelOpen && (
            <div className="rounded-xl border border-red-200 bg-red-50 p-3">
              <p className="text-sm font-bold text-red-950">Delete this tied calendar event?</p>
              <p className="mt-1 text-xs leading-5 text-red-800">
                Choose whether to remove only the calendar event or remove both the calendar event and the job created from it.
              </p>
              <div className="mt-3 grid gap-2">
                <button type="button" className={buttonClass('secondary')} disabled={busy} onClick={() => onDeleteLinkedEvent?.('event_only')}>
                  Delete calendar event only
                </button>
                <button type="button" className="rounded-xl border border-red-200 bg-white px-3 py-2 text-sm font-semibold text-red-600 transition hover:bg-red-50 disabled:opacity-60" disabled={busy} onClick={() => onDeleteLinkedEvent?.('event_and_job')}>
                  Delete calendar event and tied job
                </button>
                <button type="button" className={buttonClass('secondary')} disabled={busy} onClick={() => setDeleteLinkedPanelOpen(false)}>
                  Cancel
                </button>
              </div>
            </div>
          )}
          <Field label="Notes (optional)">
            <textarea rows={3} className={inputClass()} {...writingAssistProps} value={draft.notes} onChange={e => setDraft(d => ({ ...d, notes: e.target.value }))} />
          </Field>
        </div>

        <div className="mt-5 flex flex-wrap items-center justify-between gap-2">
          <div className="max-w-full">
            {linkedJob ? (
              <button type="button" onClick={() => onOpenLinkedJob(linkedJob)} disabled={busy} className={buttonClass('secondary')}>
                Open Job
              </button>
            ) : (
              <button
                type="button"
                onClick={() => setCreateJobPanelOpen(true)}
                disabled={!canCreateJobFromEvent || busy || creatingJob || !eventHasCustomer}
                className={buttonClass('secondary')}
                title={!eventHasCustomer ? 'Select a customer and save this event before creating a job.' : undefined}
              >
                {creatingJob ? 'Creating job...' : 'Create Job from Event'}
              </button>
            )}
            {isEditing && !linkedJob && !eventHasCustomer && (
              <p className="mt-1 max-w-xs text-xs leading-5 text-amber-700">
                Select a customer and save the event before creating a job.
              </p>
            )}
          </div>
          <div className="flex items-center gap-2">
            {isEditing && onDelete && (
              <button type="button" onClick={linkedJob ? () => setDeleteLinkedPanelOpen(true) : onDelete} disabled={busy} className="rounded-xl border border-red-200 bg-white px-3 py-2 text-sm font-semibold text-red-600 transition hover:bg-red-50 disabled:opacity-60">
                Delete
              </button>
            )}
            <button type="button" onClick={() => onSave(draft)} disabled={busy} className={buttonClass('primary')}>
              {busy ? 'Saving...' : isEditing ? 'Save changes' : 'Create event'}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

function VisitCalendarEventDetail({
  event,
  inspection,
  request,
  calendarEventLink,
  sourceCalendarEvent,
  busy,
  onSave,
  onOpenJob,
  onDeleteCalendarEventLink,
  onClose,
}: {
  event: ContractorVisitEvent;
  inspection: Inspection | null;
  request: ServiceRequestSummary | null;
  calendarEventLink?: ContractorCalendarEventJobLink | null;
  sourceCalendarEvent?: ContractorCalendarEvent | null;
  busy: boolean;
  onSave: (draft: { starts_at: string; notes: string; share_with_homeowner: boolean }) => void;
  onOpenJob: () => void;
  onDeleteCalendarEventLink?: (mode: 'event_only' | 'event_and_job') => void;
  onClose: () => void;
}) {
  const dialogRef = useRef<HTMLDivElement | null>(null);
  const [draft, setDraft] = useState(() => ({
    starts_at: toDateTimeLocalValue(event.scheduled_at),
    notes: event.notes ?? '',
    share_with_homeowner: Boolean(event.share_with_homeowner),
  }));
  const [deleteCalendarEventPanelOpen, setDeleteCalendarEventPanelOpen] = useState(false);
  useEffect(() => {
    setDraft({
      starts_at: toDateTimeLocalValue(event.scheduled_at),
      notes: event.notes ?? '',
      share_with_homeowner: Boolean(event.share_with_homeowner),
    });
  }, [event.id, event.scheduled_at, event.notes, event.share_with_homeowner]);
  const { dateValue: eventDateValue, timeValue: eventTimeValue } = splitDateTimeLocalValue(draft.starts_at);
  const eventTimeOptions = calendarEventTimeOptions(eventTimeValue);
  const canShareWithHomeowner = Boolean(event.service_request_id && event.homeowner_user_id);
  const scheduledAt = new Date(event.scheduled_at);
  const title = inspection?.name || request?.title || 'Scheduled service visit';
  const subject = request?.homeowner_name || (event.local_contact_id ? 'Local customer' : 'Customer');
  const statusLabel = event.status === 'scheduled'
    ? 'Scheduled'
    : event.status === 'completed'
      ? 'Completed'
      : 'Cancelled';
  const responseLabel = event.homeowner_response_status === 'not_shared'
    ? 'Contractor calendar only'
    : event.homeowner_response_status === 'shared_waiting'
      ? 'Shared — waiting for homeowner'
      : event.homeowner_response_status === 'accepted'
        ? 'Homeowner accepted'
        : event.homeowner_response_status === 'declined'
          ? 'Homeowner declined'
          : 'New time suggested';

  useEffect(() => {
    const previousOverflow = document.body.style.overflow;
    document.body.style.overflow = 'hidden';
    const focusFrame = window.requestAnimationFrame(() => dialogRef.current?.focus());
    return () => {
      window.cancelAnimationFrame(focusFrame);
      document.body.style.overflow = previousOverflow;
    };
  }, []);

  return (
    <div className="fixed inset-0 z-[90] flex items-start justify-center overflow-y-auto bg-black/40 p-4">
      <div
        ref={dialogRef}
        role="dialog"
        aria-modal="true"
        aria-label="Calendar event"
        tabIndex={-1}
        onKeyDown={keyboardEvent => {
          if (keyboardEvent.key === 'Escape' && !busy) onClose();
        }}
        className="my-8 w-full max-w-lg rounded-2xl border border-[#E1E3E7] bg-white p-6 shadow-2xl outline-none"
      >
        <div className="mb-1 flex items-center justify-between gap-3">
          <h2 className="text-lg font-bold text-[#02132D]">Calendar event</h2>
          <button type="button" onClick={onClose} className="text-[#223D67]/70 hover:text-[#02132D]"><X size={18} /></button>
        </div>
        <p className="mb-4 inline-flex items-center gap-1.5 rounded-full bg-sky-100 px-2.5 py-0.5 text-xs font-semibold text-sky-700">
          Tied to a job
        </p>

        <div className="space-y-4">
          <div>
            <p className="text-xs font-semibold uppercase tracking-[0.14em] text-slate-500">Visit</p>
            <h3 className="mt-1 text-xl font-bold text-slate-950">{title}</h3>
            <p className="mt-1 text-sm text-slate-600">{subject}</p>
          </div>

          <div className="grid gap-3 sm:grid-cols-2">
            <div className="rounded-xl border border-slate-200 bg-slate-50 p-3">
              <p className="text-xs font-semibold uppercase tracking-[0.12em] text-slate-500">Current date and time</p>
              <p className="mt-1 text-sm font-semibold text-slate-900">
                {Number.isNaN(scheduledAt.getTime())
                  ? 'Scheduled time unavailable'
                  : scheduledAt.toLocaleString('en-US', {
                      month: 'short',
                      day: 'numeric',
                      year: 'numeric',
                      hour: 'numeric',
                      minute: '2-digit',
                    })}
              </p>
            </div>
            <div className="rounded-xl border border-slate-200 bg-slate-50 p-3">
              <p className="text-xs font-semibold uppercase tracking-[0.12em] text-slate-500">Status</p>
              <p className="mt-1 text-sm font-semibold text-slate-900">{statusLabel}</p>
              <p className="mt-1 text-xs text-slate-500">{responseLabel}</p>
            </div>
          </div>

          <div className="grid gap-4 sm:grid-cols-2">
            <Field label="Event date">
              <input
                type="date"
                className={inputClass()}
                value={eventDateValue}
                onChange={inputEvent => setDraft(current => {
                  const { timeValue } = splitDateTimeLocalValue(current.starts_at);
                  return { ...current, starts_at: combineDateTimeLocalValue(inputEvent.target.value, timeValue) };
                })}
              />
            </Field>
            <Field label="Event time">
              <select
                className={inputClass()}
                value={eventTimeValue}
                onChange={inputEvent => setDraft(current => {
                  const { dateValue } = splitDateTimeLocalValue(current.starts_at);
                  return { ...current, starts_at: combineDateTimeLocalValue(dateValue, inputEvent.target.value) };
                })}
              >
                <option value="">Choose time</option>
                {eventTimeOptions.map(option => (
                  <option key={option.value} value={option.value}>{option.label}</option>
                ))}
              </select>
            </Field>
          </div>

          <Field label="Visit notes">
            <textarea
              rows={3}
              className={inputClass()}
              {...writingAssistProps}
              value={draft.notes}
              onChange={inputEvent => setDraft(current => ({ ...current, notes: inputEvent.target.value }))}
              placeholder="Add notes for this calendar event."
            />
          </Field>

          <div className="rounded-xl border border-slate-200 bg-slate-50 p-3">
            <p className="text-xs font-semibold uppercase tracking-[0.12em] text-slate-500">Sharing</p>
            {canShareWithHomeowner ? (
              <label className="mt-2 flex items-start gap-2 text-sm font-medium text-slate-700">
                <input
                  type="checkbox"
                  className="mt-1"
                  checked={draft.share_with_homeowner}
                  onChange={inputEvent => setDraft(current => ({ ...current, share_with_homeowner: inputEvent.target.checked }))}
                />
                <span>Share calendar invite with homeowner</span>
              </label>
            ) : (
              <p className="mt-1 text-sm text-slate-500">Calendar sharing is available for connected homeowner jobs.</p>
            )}
          </div>

          <div className="rounded-xl border border-slate-200 bg-white p-3">
            <p className="text-xs font-semibold uppercase tracking-[0.12em] text-slate-500">Repeat</p>
            <p className="mt-1 text-sm text-slate-700">Does not repeat. Recurrence is only supported for standalone calendar events right now.</p>
          </div>

          {calendarEventLink && (
            <div className="rounded-xl border border-blue-200 bg-blue-50 p-3">
              <p className="text-xs font-semibold uppercase tracking-[0.12em] text-blue-700">Created from calendar event</p>
              <p className="mt-1 text-sm font-semibold text-blue-950">
                {sourceCalendarEvent?.title ?? 'Original calendar event'}
              </p>
              <p className="mt-1 text-xs leading-5 text-blue-800">
                You can remove the calendar event while keeping the job, or remove both if the job has not started.
              </p>
              {deleteCalendarEventPanelOpen && (
                <div className="mt-3 grid gap-2">
                  <button type="button" className={buttonClass('secondary')} disabled={busy} onClick={() => onDeleteCalendarEventLink?.('event_only')}>
                    Delete calendar event only
                  </button>
                  <button type="button" className="rounded-xl border border-red-200 bg-white px-3 py-2 text-sm font-semibold text-red-600 transition hover:bg-red-50 disabled:opacity-60" disabled={busy} onClick={() => onDeleteCalendarEventLink?.('event_and_job')}>
                    Delete calendar event and tied job
                  </button>
                  <button type="button" className={buttonClass('secondary')} disabled={busy} onClick={() => setDeleteCalendarEventPanelOpen(false)}>
                    Cancel
                  </button>
                </div>
              )}
            </div>
          )}

          {inspection?.summary && (
            <div className="rounded-xl border border-slate-200 bg-white p-3">
              <p className="text-xs font-semibold uppercase tracking-[0.12em] text-slate-500">Job summary</p>
              <p className="mt-1 text-sm text-slate-700">{inspection.summary}</p>
            </div>
          )}

          {event.notes && (
            <div className="rounded-xl border border-slate-200 bg-white p-3">
              <p className="text-xs font-semibold uppercase tracking-[0.12em] text-slate-500">Visit notes</p>
              <p className="mt-1 text-sm text-slate-700">{event.notes}</p>
            </div>
          )}

          <p className="rounded-lg bg-sky-50 px-3 py-2 text-xs font-semibold text-sky-800">
            Open the linked job when you are ready to review the work order, checklist, report, or job workflow.
          </p>
        </div>

        <div className="mt-5 flex flex-wrap items-center justify-between gap-2">
          <button type="button" onClick={onClose} className={buttonClass('secondary')}>
            Close
          </button>
          <div className="flex flex-wrap items-center gap-2">
            {calendarEventLink && (
              <button type="button" onClick={() => setDeleteCalendarEventPanelOpen(true)} disabled={busy || !onDeleteCalendarEventLink} className="rounded-xl border border-red-200 bg-white px-3 py-2 text-sm font-semibold text-red-600 transition hover:bg-red-50 disabled:opacity-60">
                Delete calendar event
              </button>
            )}
            <button type="button" onClick={onOpenJob} disabled={!inspection || busy} className={buttonClass('secondary')}>
              Open Job
            </button>
            <button type="button" onClick={() => onSave(draft)} disabled={busy} className={buttonClass('primary')}>
              {busy ? 'Saving...' : 'Save event'}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

function CalendarView({
  requests,
  visitEvents = [],
  calendarEvents = [],
  calendarEventJobLinks = [],
  calendarEventOccurrenceExclusions = [],
  selectedDateValue,
  onSelectedDateChange,
  perspective,
  onOpenRequest,
  onOpenVisitEvent,
  onOpenCalendarEvent,
}: {
  requests: ServiceRequestSummary[];
  visitEvents?: ContractorVisitEvent[];
  calendarEvents?: ContractorCalendarEvent[];
  calendarEventJobLinks?: ContractorCalendarEventJobLink[];
  calendarEventOccurrenceExclusions?: ContractorCalendarEventOccurrenceExclusion[];
  selectedDateValue?: string | null;
  onSelectedDateChange?: (date: string) => void;
  perspective: 'homeowner' | 'contractor';
  onOpenRequest?: (request: ServiceRequestSummary) => void;
  onOpenVisitEvent?: (event: ContractorVisitEvent) => void;
  onOpenCalendarEvent?: (event: ContractorCalendarEvent, occurrenceStartsAt: string) => void;
}) {
  const now = new Date();
  const [year, setYear] = useState(now.getFullYear());
  const [month, setMonth] = useState(now.getMonth());
  const todayKey = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, '0')}-${String(now.getDate()).padStart(2, '0')}`;
  const [internalSelectedDate, setInternalSelectedDate] = useState<string | null>(todayKey);
  const selectedDate = selectedDateValue ?? internalSelectedDate;
  const selectCalendarDate = (date: string) => {
    setInternalSelectedDate(date);
    onSelectedDateChange?.(date);
  };

  type ApptEntry = { kind: 'appointment'; request: ServiceRequestSummary; appointment: ServiceRequestAppointment };
  type VisitEntry = { kind: 'visit'; visitEvent: ContractorVisitEvent; request: ServiceRequestSummary | null };
  type StandaloneEntry = { kind: 'standalone'; calendarEvent: ContractorCalendarEvent; occurrenceStartsAt: string };
  type CalendarEntry = ApptEntry | VisitEntry | StandaloneEntry;
  const visitRequestIds = new Set(visitEvents.filter(event => event.service_request_id && event.status !== 'cancelled').map(event => event.service_request_id as string));
  const linkedStandaloneOccurrenceKeys = new Set(calendarEventJobLinks.map(link => {
    const date = new Date(link.occurrence_starts_at);
    return `${link.calendar_event_id}:${Number.isNaN(date.getTime()) ? link.occurrence_starts_at : date.toISOString()}`;
  }));
  const excludedStandaloneOccurrenceKeys = new Set(calendarEventOccurrenceExclusions.map(exclusion => {
    const date = new Date(exclusion.occurrence_starts_at);
    return `${exclusion.calendar_event_id}:${Number.isNaN(date.getTime()) ? exclusion.occurrence_starts_at : date.toISOString()}`;
  }));
  const apptMap: Record<string, CalendarEntry[]> = {};
  const appointments: CalendarEntry[] = [];
  const monthGridStart = new Date(year, month, 1 - new Date(year, month, 1).getDay(), 0, 0, 0, 0);
  const monthGridEnd = new Date(year, month + 1, 0, 23, 59, 59, 999);
  const upcomingEnd = new Date(now);
  upcomingEnd.setDate(upcomingEnd.getDate() + 120);
  const recurrenceRangeStart = new Date(Math.min(monthGridStart.getTime(), now.getTime()));
  const recurrenceRangeEnd = new Date(Math.max(monthGridEnd.getTime(), upcomingEnd.getTime()));
  const addEntry = (dateValue: string, entry: CalendarEntry) => {
    const d = new Date(dateValue);
    if (Number.isNaN(d.getTime())) return;
    const key = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`;
    if (!apptMap[key]) apptMap[key] = [];
    apptMap[key].push(entry);
    appointments.push(entry);
  };
  for (const r of requests) {
    if (r.appointment && !visitRequestIds.has(r.id)) {
      addEntry(r.appointment.proposed_at, { kind: 'appointment', request: r, appointment: r.appointment });
    }
  }
  for (const event of visitEvents) {
    const request = event.service_request_id
      ? requests.find(item => item.id === event.service_request_id) ?? null
      : null;
    addEntry(event.scheduled_at, { kind: 'visit', visitEvent: event, request });
  }
  for (const calendarEvent of calendarEvents) {
    recurringCalendarEventOccurrences(calendarEvent, recurrenceRangeStart, recurrenceRangeEnd).forEach(occurrence => {
      const occurrenceDate = new Date(occurrence.startsAt);
      const occurrenceKey = `${calendarEvent.id}:${Number.isNaN(occurrenceDate.getTime()) ? occurrence.startsAt : occurrenceDate.toISOString()}`;
      if (linkedStandaloneOccurrenceKeys.has(occurrenceKey)) return;
      if (excludedStandaloneOccurrenceKeys.has(occurrenceKey)) return;
      addEntry(occurrence.startsAt, { kind: 'standalone', calendarEvent, occurrenceStartsAt: occurrence.startsAt });
    });
  }
  const entryTime = (entry: CalendarEntry) => entry.kind === 'appointment'
    ? entry.appointment.proposed_at
    : entry.kind === 'visit'
      ? entry.visitEvent.scheduled_at
      : entry.occurrenceStartsAt;
  appointments.sort((a, b) => new Date(entryTime(a)).getTime() - new Date(entryTime(b)).getTime());
  Object.values(apptMap).forEach(dayEntries => {
    dayEntries.sort((a, b) => new Date(entryTime(a)).getTime() - new Date(entryTime(b)).getTime());
  });

  const upcoming = appointments.filter(entry =>
    new Date(entryTime(entry)).getTime() >= now.getTime()
    && (entry.kind === 'appointment'
      ? !['cancelled', 'completed'].includes(entry.appointment.status)
      : entry.kind === 'visit'
        ? !['cancelled', 'completed'].includes(entry.visitEvent.status)
        : true)
  );
  const proposedForMe = appointments.filter((entry): entry is ApptEntry =>
    entry.kind === 'appointment'
    && entry.appointment.status === 'proposed'
    && entry.appointment.proposed_by !== perspective
  );

  const MONTHS = ['January','February','March','April','May','June','July','August','September','October','November','December'];
  const DAYS = ['Sun','Mon','Tue','Wed','Thu','Fri','Sat'];

  const firstDayOfWeek = new Date(year, month, 1).getDay();
  const daysInMonth = new Date(year, month + 1, 0).getDate();
  const totalCells = Math.ceil((firstDayOfWeek + daysInMonth) / 7) * 7;

  const prevMonth = () => {
    if (month === 0) { setYear(y => y - 1); setMonth(11); } else setMonth(m => m - 1);
  };
  const nextMonth = () => {
    if (month === 11) { setYear(y => y + 1); setMonth(0); } else setMonth(m => m + 1);
  };

  const appointmentStatusClass = (status: AppointmentStatus) => {
    if (status === 'confirmed') return 'border-emerald-200 bg-emerald-50 text-emerald-800';
    if (status === 'completed') return 'border-blue-200 bg-blue-50 text-blue-800';
    if (status === 'cancelled') return 'border-red-200 bg-red-50 text-red-800';
    return 'border-amber-200 bg-amber-50 text-amber-800';
  };

  const appointmentDotClass = (status: AppointmentStatus) => {
    if (status === 'confirmed') return 'bg-emerald-500';
    if (status === 'completed') return 'bg-blue-500';
    if (status === 'cancelled') return 'bg-red-400';
    return 'bg-amber-500';
  };

  const statusLabel: Record<AppointmentStatus, string> = {
    proposed: 'Proposed',
    confirmed: 'Confirmed',
    completed: 'Completed',
    cancelled: 'Cancelled',
  };

  const visitEventStatusClass = (event: ContractorVisitEvent) => {
    if (event.status === 'completed') return 'border-blue-200 bg-blue-50 text-blue-800';
    if (event.status === 'cancelled') return 'border-red-200 bg-red-50 text-red-800';
    if (event.homeowner_response_status === 'accepted') return 'border-emerald-200 bg-emerald-50 text-emerald-800';
    if (event.homeowner_response_status === 'declined' || event.homeowner_response_status === 'countered') return 'border-amber-200 bg-amber-50 text-amber-800';
    return 'border-sky-200 bg-sky-50 text-sky-800';
  };

  const visitEventDotClass = (event: ContractorVisitEvent) => {
    if (event.status === 'completed') return 'bg-blue-500';
    if (event.status === 'cancelled') return 'bg-red-400';
    if (event.homeowner_response_status === 'accepted') return 'bg-emerald-500';
    if (event.homeowner_response_status === 'declined' || event.homeowner_response_status === 'countered') return 'bg-amber-500';
    return 'bg-sky-500';
  };

  const visitResponseLabel = (event: ContractorVisitEvent) => {
    if (event.status === 'completed') return 'Completed';
    if (event.status === 'cancelled') return 'Cancelled';
    if (event.homeowner_response_status === 'not_shared') return 'Contractor calendar';
    if (event.homeowner_response_status === 'shared_waiting') return 'Shared — waiting for homeowner';
    if (event.homeowner_response_status === 'accepted') return 'Homeowner accepted';
    if (event.homeowner_response_status === 'declined') return 'Homeowner declined';
    return 'New time suggested';
  };

  const openCalendarEntry = (entry: CalendarEntry) => {
    if (entry.kind === 'standalone') {
      onOpenCalendarEvent?.(entry.calendarEvent, entry.occurrenceStartsAt);
      return;
    }
    if (entry.kind === 'visit') {
      onOpenVisitEvent?.(entry.visitEvent);
      return;
    }
    onOpenRequest?.(entry.request);
  };

  const renderAppointmentRow = (entry: CalendarEntry, compact = false) => {
    if (entry.kind === 'standalone') {
      const { calendarEvent, occurrenceStartsAt } = entry;
      const date = new Date(occurrenceStartsAt);
      const recurrenceSummary = calendarEventRecurrenceSummary(calendarEvent);
      return (
        <button
          key={`calendar-event-${calendarEvent.id}-${occurrenceStartsAt}`}
          type="button"
          onClick={() => onOpenCalendarEvent?.(calendarEvent, occurrenceStartsAt)}
          className="w-full rounded-xl border border-violet-200 bg-violet-50 p-3 text-left text-violet-900 transition hover:border-violet-300 hover:bg-violet-100"
        >
          <div className="flex items-start justify-between gap-3">
            <div className="min-w-0">
              <div className="flex flex-wrap items-center gap-2">
                <span className="h-2.5 w-2.5 rounded-full bg-violet-500" />
                <p className="font-semibold text-slate-950">{calendarEvent.title}</p>
              </div>
              <p className="mt-1 text-xs text-slate-600">
                {calendarEventTypeLabel(calendarEvent.event_type)} · {date.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })} at {date.toLocaleTimeString([], { hour: 'numeric', minute: '2-digit' })}
                {calendarEvent.duration_minutes ? ` · ${calendarEvent.duration_minutes} min` : ''}
              </p>
              {!compact && calendarEvent.notes && <p className="mt-1 text-xs text-slate-600">{calendarEvent.notes}</p>}
              <p className="mt-1 text-xs font-semibold text-violet-700">
                Not tied to a job{recurrenceSummary !== 'Does not repeat' ? ` · ${recurrenceSummary}` : ''}
              </p>
            </div>
            <span className="shrink-0 rounded-full bg-white/80 px-2 py-0.5 text-xs font-semibold text-violet-700">
              Event
            </span>
          </div>
        </button>
      );
    }
    if (entry.kind === 'visit') {
      const { visitEvent, request } = entry;
      const date = new Date(visitEvent.scheduled_at);
      const inspection = visitEvent.inspection;
      const title = inspection?.name || request?.title || 'Service visit';
      const subject = request?.homeowner_name || (visitEvent.local_contact_id ? 'Local customer' : 'Customer');
      return (
        <button
          key={`visit-${visitEvent.id}`}
          type="button"
          onClick={() => onOpenVisitEvent?.(visitEvent)}
          className={`w-full rounded-xl border p-3 text-left transition hover:border-blue-300 hover:bg-blue-50 ${visitEventStatusClass(visitEvent)}`}
        >
          <div className="flex items-start justify-between gap-3">
            <div className="min-w-0">
              <div className="flex flex-wrap items-center gap-2">
                <span className={`h-2.5 w-2.5 rounded-full ${visitEventDotClass(visitEvent)}`} />
                <p className="font-semibold text-slate-950">{title}</p>
              </div>
              <p className="mt-1 text-xs text-slate-600">
                {subject} · {date.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })} at {date.toLocaleTimeString([], { hour: 'numeric', minute: '2-digit' })}
              </p>
              {!compact && visitEvent.notes && <p className="mt-1 text-xs text-slate-600">{visitEvent.notes}</p>}
              <p className="mt-1 text-xs font-semibold text-slate-700">{visitResponseLabel(visitEvent)}</p>
            </div>
            <span className="shrink-0 rounded-full bg-white/80 px-2 py-0.5 text-xs font-semibold text-slate-700">
              Visit
            </span>
          </div>
        </button>
      );
    }
    const { request, appointment } = entry;
    const date = new Date(appointment.proposed_at);
    const otherParty = perspective === 'homeowner' ? request.contractor_name : (request.homeowner_name || 'Homeowner');
    const needsResponse = appointment.status === 'proposed' && appointment.proposed_by !== perspective;
    return (
      <button
        key={`appointment-${request.id}-${appointment.id}`}
        type="button"
        onClick={() => onOpenRequest?.(request)}
        className={`w-full rounded-xl border p-3 text-left transition hover:border-blue-300 hover:bg-blue-50 ${appointmentStatusClass(appointment.status)}`}
      >
        <div className="flex items-start justify-between gap-3">
          <div className="min-w-0">
            <div className="flex flex-wrap items-center gap-2">
              <span className={`h-2.5 w-2.5 rounded-full ${appointmentDotClass(appointment.status)}`} />
              <p className="font-semibold text-slate-950">{request.title}</p>
              {needsResponse && (
                <span className="rounded-full bg-amber-100 px-2 py-0.5 text-xs font-bold text-amber-800">
                  Needs response
                </span>
              )}
            </div>
            <p className="mt-1 text-xs text-slate-600">
              {otherParty} · {request.category} · {date.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })} at {date.toLocaleTimeString([], { hour: 'numeric', minute: '2-digit' })}
            </p>
            {!compact && appointment.notes && <p className="mt-1 text-xs text-slate-600">{appointment.notes}</p>}
            <p className="mt-1 text-xs font-semibold text-slate-700">{appointmentNextActionText(appointment, perspective)}</p>
          </div>
          <span className="shrink-0 rounded-full bg-white/80 px-2 py-0.5 text-xs font-semibold text-slate-700">
            {statusLabel[appointment.status]}
          </span>
        </div>
      </button>
    );
  };

  return (
    <div className="space-y-5">
      <div className="grid gap-5 xl:grid-cols-[1.25fr_0.75fr]">
        <div className="space-y-4">
          <div className="flex flex-wrap items-center justify-between gap-3">
            <button type="button" onClick={prevMonth} className={buttonClass('secondary')}>Prev</button>
            <h3 className="text-lg font-bold text-slate-950">{MONTHS[month]} {year}</h3>
            <div className="flex flex-wrap gap-2">
              <button
                type="button"
                onClick={() => {
                  const today = new Date();
                  setYear(today.getFullYear());
                  setMonth(today.getMonth());
                  selectCalendarDate(todayKey);
                }}
                className={buttonClass('secondary')}
              >
                Today
              </button>
              <button type="button" onClick={nextMonth} className={buttonClass('secondary')}>Next</button>
            </div>
          </div>

          <div className="grid grid-cols-7">
            {DAYS.map(d => (
              <div key={d} className="py-2 text-center text-xs font-semibold uppercase tracking-wide text-slate-500">{d}</div>
            ))}
          </div>

          <div className="grid grid-cols-7 gap-px overflow-hidden rounded-xl border border-slate-200 bg-slate-200">
            {Array.from({ length: totalCells }).map((_, i) => {
              const dayNum = i - firstDayOfWeek + 1;
              const inMonth = dayNum >= 1 && dayNum <= daysInMonth;
              const dateKey = inMonth
                ? `${year}-${String(month + 1).padStart(2, '0')}-${String(dayNum).padStart(2, '0')}`
                : '';
              const dayAppts = dateKey ? (apptMap[dateKey] ?? []) : [];
              const isToday = dateKey === todayKey;
              const isSelected = dateKey === selectedDate;

              return (
                <div
                  key={i}
                  onClick={() => { if (inMonth) selectCalendarDate(dateKey); }}
                  onKeyDown={event => {
                    if (inMonth && (event.key === 'Enter' || event.key === ' ')) {
                      event.preventDefault();
                      selectCalendarDate(dateKey);
                    }
                  }}
                  role={inMonth ? 'button' : undefined}
                  tabIndex={inMonth ? 0 : undefined}
                  className={`min-h-[98px] p-1.5 text-left transition-colors ${inMonth ? 'cursor-pointer bg-white hover:bg-blue-50' : 'bg-slate-50 opacity-50'} ${isSelected ? 'ring-2 ring-inset ring-blue-500' : ''}`}
                >
                  <div className={`mb-1 flex h-6 w-6 items-center justify-center rounded-full text-xs font-bold ${isToday ? 'bg-blue-600 text-white' : 'text-slate-600'}`}>
                    {inMonth ? dayNum : ''}
                  </div>
                  <div className="space-y-1">
                    {dayAppts.slice(0, 3).map(entry => {
                      const time = new Date(entryTime(entry)).toLocaleTimeString([], { hour: 'numeric', minute: '2-digit' });
                      const title = entry.kind === 'visit'
                        ? entry.visitEvent.inspection?.name || entry.request?.title || 'Service visit'
                        : entry.kind === 'standalone'
                          ? entry.calendarEvent.title
                          : entry.request.title;
                      const className = entry.kind === 'visit'
                        ? visitEventStatusClass(entry.visitEvent)
                        : entry.kind === 'standalone'
                          ? 'border-violet-200 bg-violet-50 text-violet-800'
                          : appointmentStatusClass(entry.appointment.status);
                      const entryId = entry.kind === 'visit'
                        ? entry.visitEvent.id
                        : entry.kind === 'standalone'
                          ? entry.calendarEvent.id
                          : entry.appointment.id;
                      return (
                        <button
                          key={`${entry.kind}-${entryId}-${entryTime(entry)}`}
                          type="button"
                          onClick={event => {
                            event.stopPropagation();
                            openCalendarEntry(entry);
                          }}
                          className={`block w-full rounded border px-1 py-0.5 text-left text-xs leading-tight transition hover:brightness-95 focus:outline-none focus:ring-2 focus:ring-blue-500 ${className}`}
                        >
                          <span className="font-semibold">{time}</span>
                          <span className="block truncate">{title}</span>
                        </button>
                      );
                    })}
                    {dayAppts.length > 3 && (
                      <p className="text-xs font-semibold text-slate-500">+{dayAppts.length - 3} more</p>
                    )}
                  </div>
                </div>
              );
            })}
          </div>

          <div className="flex flex-wrap items-center gap-4 text-xs text-slate-500">
            <span className="flex items-center gap-1.5"><span className="h-3 w-3 rounded bg-amber-500" /> Proposed</span>
            <span className="flex items-center gap-1.5"><span className="h-3 w-3 rounded bg-emerald-500" /> Confirmed</span>
            <span className="flex items-center gap-1.5"><span className="h-3 w-3 rounded bg-blue-500" /> Completed</span>
            <span className="flex items-center gap-1.5"><span className="h-3 w-3 rounded bg-red-400" /> Cancelled</span>
            <span className="flex items-center gap-1.5"><span className="h-3 w-3 rounded bg-violet-500" /> Event (no job)</span>
          </div>
        </div>

        <div className="space-y-4">
          <section className="rounded-2xl border border-slate-200 bg-slate-50 p-3">
            <p className="text-sm font-bold text-slate-950">Selected day</p>
            <p className="mt-0.5 text-xs text-slate-500">
              {selectedDate
                ? new Date(`${selectedDate}T12:00:00`).toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric' })
                : 'Choose a day on the calendar.'}
            </p>
            <div className="mt-3 space-y-2">
              {selectedDate && (apptMap[selectedDate] ?? []).length > 0 ? (
                (apptMap[selectedDate] ?? []).map(entry => renderAppointmentRow(entry, true))
              ) : (
                <EmptyState text="No appointments on this day." />
              )}
            </div>
          </section>

          <section className="rounded-2xl border border-slate-200 bg-slate-50 p-3">
            <p className="text-sm font-bold text-slate-950">Needs response</p>
            <p className="mt-0.5 text-xs text-slate-500">Proposed appointment times waiting on you.</p>
            <div className="mt-3 space-y-2">
              {proposedForMe.length === 0 ? (
                <EmptyState text="No proposed times need your response." />
              ) : (
                proposedForMe.slice(0, 4).map(entry => renderAppointmentRow(entry, true))
              )}
            </div>
          </section>

          <section className="rounded-2xl border border-slate-200 bg-slate-50 p-3">
            <p className="text-sm font-bold text-slate-950">Upcoming</p>
            <p className="mt-0.5 text-xs text-slate-500">Next scheduled or proposed appointments.</p>
            <div className="mt-3 space-y-2">
              {upcoming.length === 0 ? (
                <EmptyState text="No upcoming appointments yet." />
              ) : (
                upcoming.slice(0, 5).map(entry => renderAppointmentRow(entry, true))
              )}
            </div>
          </section>
        </div>
      </div>
    </div>
  );
}

function SetupNotice() {
  return (
    <div className="mx-auto max-w-2xl rounded-3xl border border-amber-700 bg-amber-900/30 p-6 text-amber-300">
      <h1 className="text-2xl font-bold">Supabase is not connected</h1>
      <p className="mt-2 text-sm leading-6">
        Add `VITE_SUPABASE_URL` and `VITE_SUPABASE_ANON_KEY` to the project `.env` file, then restart the dev server.
      </p>
    </div>
  );
}
